}

# Route53 Health Check for US West
resource "aws_route53_health_check" "us_west" {
  provider          = aws.route53
  fqdn              = aws_elastic_beanstalk_environment.us_west.cname
  port              = 80
  type              = "HTTP"
  resource_path     = "/"
  failure_threshold = 3
  request_interval  = 30

  tags = {
    Name = "us-west-health-check"
  }

  depends_on = [aws_elastic_beanstalk_environment.us_west]
}

# Route53 Health Check for EU Central
