  health_check_id = aws_route53_health_check.eu_central.id
  set_identifier  = "eu-central-asia"
  records         = [aws_elastic_beanstalk_environment.eu_central.cname]

  depends_on = [aws_elastic_beanstalk_environment.eu_central]
}

# Route53 Geolocation Record for US West (Oceania - default to US West)
resource "aws_route53_record" "us_west_oceania" {
  provider = aws.route53
  zone_id  = aws_route53_zone.main.zone_id
  name     = "app.example.com"
  type     = "CNAME"
  ttl      = 60

  geolocation_routing_policy {
    continent = "OC"
  }

  health_check_id = aws_route53_health_check.us_west.id
  set_identifier  = "us-west-oceania"
  records         = [aws_elastic_beanstalk_environment.us_west.cname]

  depends_on = [aws_elastic_beanstalk_environment.us_west]
}

# Default geolocation record (US West as fallback)
resource "aws_route53_record" "default" {
  provider = aws.route53
  zone_id  = aws_route53_zone.main.zone_id
  name     = "app.example.com"
  type     = "CNAME"
  ttl      = 60

  geolocation_routing_policy {
    country = "*"
  }

  health_check_id = aws_route53_health_check.us_west.id
  set_identifier  = "default"
  records         = [aws_elastic_beanstalk_environment.us_west.cname]

  depends_on = [aws_elastic_beanstalk_environment.us_west]
}

# Outputs
output "us_west_environment_cname" {
  description = "CNAME of the US West Elastic Beanstalk environment"
  value       = aws_elastic_beanstalk_environment.us_west.cname
}

output "eu_central_environment_cname" {
  description = "CNAME of the EU Central Elastic Beanstalk environment"
  value       = aws_elastic_beanstalk_environment.eu_central.cname
}

output "route53_zone_id" {
  description = "Route53 Hosted Zone ID"
  value       = aws_route53_zone.main.zone_id
}

output "route53_name_servers" {
  description = "Route53 Name Servers"
  value       = aws_route53_zone.main.name_servers
}
