  name    = "weighted.example.com"
  type    = "A"

  weighted_routing_policy {
    weight = 50
  }

  alias {
    name                   = data.aws_lb.green.dns_name
    zone_id                = data.aws_lb.green.zone_id
    evaluate_target_health = true
  }

  health_check_id = aws_route53_health_check.green.id
  set_identifier  = "green-weighted"
}

