data "aws_caller_identity" "current" {}
data "aws_region" "current" {}

# CodeBuild Service Role
resource "aws_iam_role" "codebuild_role" {
  name = "codebuild-project-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "codebuild.amazonaws.com"
        }
      }
    ]
  })
}

resource "aws_iam_role_policy" "codebuild_policy" {
  name = "codebuild-project-policy"
  role = aws_iam_role.codebuild_role.id

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect = "Allow"
        Action = [
          "logs:CreateLogGroup",
          "logs:CreateLogStream",
          "logs:PutLogEvents"
        ]
        Resource = "*"
      },
      {
        Effect = "Allow"
        Action = [
          "s3:GetObject",
          "s3:GetObjectVersion",
          "s3:PutObject"
        ]
        Resource = "*"
      },
      {
        Effect = "Allow"
        Action = [
          "codebuild:CreateReportGroup",
          "codebuild:CreateReport",
          "codebuild:UpdateReport",
          "codebuild:BatchPutTestCases",
          "codebuild:BatchPutCodeCoverages"
        ]
        Resource = "*"
      }
    ]
  })
}

# S3 Bucket for artifacts
resource "aws_s3_bucket" "codebuild_artifacts" {
  bucket = "codebuild-artifacts-${data.aws_caller_identity.current.account_id}-${data.aws_region.current.name}"
}

resource "aws_s3_bucket_versioning" "codebuild_artifacts" {
  bucket = aws_s3_bucket.codebuild_artifacts.id
  versioning_configuration {
    status = "Enabled"
  }
}

# CodeBuild Project with secondary sources
resource "aws_codebuild_project" "example" {
  name          = "example-project"
  description   = "Example CodeBuild project with secondary sources"
  service_role  = aws_iam_role.codebuild_role.arn
  build_timeout = "60"

  artifacts {
    type = "S3"
    location = aws_s3_bucket.codebuild_artifacts.bucket
    packaging = "ZIP"
    name = "build-output.zip"
  }

  environment {
    compute_type                = "BUILD_GENERAL1_SMALL"
    image                       = "aws/codebuild/standard:5.0"
    type                        = "LINUX_CONTAINER"
    image_pull_credentials_type = "CODEBUILD"
    privileged_mode             = true

    environment_variable {
      name  = "PRIMARY_SOURCE_DIR"
      value = "primary"
    }

    environment_variable {
      name  = "SECONDARY_SOURCE_1_DIR"
      value = "secondary1"
    }

    environment_variable {
      name  = "SECONDARY_SOURCE_2_DIR"
      value = "secondary2"
    }
  }

  # Primary source
  source {
    type            = "GITHUB"
    location        = "https://github.com/example/primary-repo.git"
    git_clone_depth = 1
    buildspec       = "buildspec.yml"

    git_submodules_config {
      fetch_submodules = false
    }
  }

  # Secondary source 1
  secondary_sources {
    type              = "GITHUB"
    location          = "https://github.com/example/secondary-repo-1.git"
    source_identifier = "secondary1"
    git_clone_depth   = 1

    git_submodules_config {
      fetch_submodules = false
    }
  }

  # Secondary source 2 (S3 source example)
  secondary_sources {
    type              = "S3"
    location          = "${aws_s3_bucket.codebuild_artifacts.bucket}/source-code/secondary2.zip"
    source_identifier = "secondary2"
  }

  # Secondary source 3 (CodeCommit example)
  secondary_sources {
    type              = "CODECOMMIT"
    location          = "https://git-codecommit.${data.aws_region.current.name}.amazonaws.com/v1/repos/secondary-repo-3"
    source_identifier = "secondary3"
    git_clone_depth   = 1
  }

  cache {
    type  = "S3"
    location = "${aws_s3_bucket.codebuild_artifacts.bucket}/cache"
    modes = ["LOCAL_DOCKER_LAYER_CACHE", "LOCAL_SOURCE_CACHE"]
  }

  logs_config {
    cloudwatch_logs {
      group_name  = "/aws/codebuild/example-project"
      stream_name = "build-log"
    }

    s3_logs {
      status   = "ENABLED"
      location = "${aws_s3_bucket.codebuild_artifacts.id}/build-logs"
    }
  }

  tags = {
    Environment = "example"
    Project     = "demo"
  }
}

# Example buildspec for reference (not a terraform resource)
# This would typically be in your primary source repository
locals {
  example_buildspec = <<-EOT
    version: 0.2

    phases:
      pre_build:
        commands:
          - echo "Primary source is at: $CODEBUILD_SRC_DIR"
          - echo "Secondary source 1 is at: $CODEBUILD_SRC_DIR_secondary1"
          - echo "Secondary source 2 is at: $CODEBUILD_SRC_DIR_secondary2"
          - echo "Secondary source 3 is at: $CODEBUILD_SRC_DIR_secondary3"
          - ls -la $CODEBUILD_SRC_DIR
          - ls -la $CODEBUILD_SRC_DIR_secondary1 || true
          - ls -la $CODEBUILD_SRC_DIR_secondary2 || true
          - ls -la $CODEBUILD_SRC_DIR_secondary3 || true

      build:
        commands:
          - echo "Building with multiple sources..."
          - # Your build commands here

      post_build:
        commands:
          - echo "Build completed"

    artifacts:
      files:
        - '**/*'
      base-directory: $CODEBUILD_SRC_DIR
  EOT
}

