    source_identifier = "secondary1"
    git_clone_depth   = 1

    git_submodules_config {
      fetch_submodules = false
    }
  }

  # Secondary source 2 (S3 source example)
  secondary_sources {
    type              = "S3"
    location          = "${aws_s3_bucket.codebuild_artifacts.bucket}/source-code/secondary2.zip"
    source_identifier = "secondary2"
  }

  # Secondary source 3 (CodeCommit example)
  secondary_sources {
    type              = "CODECOMMIT"
    location          = "https://git-codecommit.${data.aws_region.current.name}.amazonaws.com/v1/repos/secondary-repo-3"
    source_identifier = "secondary3"
    git_clone_depth   = 1
  }

  cache {
    type  = "S3"
    location = "${aws_s3_bucket.codebuild_artifacts.bucket}/cache"
    modes = ["LOCAL_DOCKER_LAYER_CACHE", "LOCAL_SOURCE_CACHE"]
  }

  logs_config {
    cloudwatch_logs {
      group_name  = "/aws/codebuild/example-project"
      stream_name = "build-log"
    }

    s3_logs {
      status   = "ENABLED"
      location = "${aws_s3_bucket.codebuild_artifacts.id}/build-logs"
    }
  }

  tags = {
    Environment = "example"
    Project     = "demo"
  }
}

# Example buildspec for reference (not a terraform resource)
# This would typically be in your primary source repository
locals {
  example_buildspec = <<-EOT
    version: 0.2

    phases:
      pre_build:
        commands:
          - echo "Primary source is at: $CODEBUILD_SRC_DIR"
          - echo "Secondary source 1 is at: $CODEBUILD_SRC_DIR_secondary1"
          - echo "Secondary source 2 is at: $CODEBUILD_SRC_DIR_secondary2"
          - echo "Secondary source 3 is at: $CODEBUILD_SRC_DIR_secondary3"
          - ls -la $CODEBUILD_SRC_DIR
          - ls -la $CODEBUILD_SRC_DIR_secondary1 || true
          - ls -la $CODEBUILD_SRC_DIR_secondary2 || true
          - ls -la $CODEBUILD_SRC_DIR_secondary3 || true

      build:
        commands:
          - echo "Building with multiple sources..."
          - # Your build commands here

      post_build:
        commands:
          - echo "Build completed"

    artifacts:
      files:
        - '**/*'
      base-directory: $CODEBUILD_SRC_DIR
  EOT
}
```

