data "aws_caller_identity" "current" {}
data "aws_region" "current" {}

# IAM Role for CodeBuild
resource "aws_iam_role" "codebuild_role" {
  name = "codebuild-example-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "codebuild.amazonaws.com"
        }
      }
    ]
  })
}

resource "aws_iam_role_policy" "codebuild_policy" {
  name = "codebuild-example-policy"
  role = aws_iam_role.codebuild_role.id

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect = "Allow"
        Action = [
          "logs:CreateLogGroup",
          "logs:CreateLogStream",
          "logs:PutLogEvents"
        ]
        Resource = [
          "arn:aws:logs:${data.aws_region.current.name}:${data.aws_caller_identity.current.account_id}:log-group:/aws/codebuild/*"
        ]
      },
      {
        Effect = "Allow"
        Action = [
          "s3:GetObject",
          "s3:GetObjectVersion",
          "s3:PutObject"
        ]
        Resource = "arn:aws:s3:::codebuild-*/*"
      }
    ]
  })
}

# S3 Bucket for artifacts
resource "aws_s3_bucket" "codebuild_bucket" {
  bucket = "codebuild-example-bucket-${data.aws_caller_identity.current.account_id}"
}

resource "aws_s3_bucket_versioning" "codebuild_bucket_versioning" {
  bucket = aws_s3_bucket.codebuild_bucket.id
  versioning_configuration {
    status = "Enabled"
  }
}

# CodeBuild Project
resource "aws_codebuild_project" "example" {
  name          = "example-project"
  description   = "Example CodeBuild project"
  build_timeout = "60"
  service_role  = aws_iam_role.codebuild_role.arn

  artifacts {
    type = "S3"
    location = aws_s3_bucket.codebuild_bucket.bucket
    packaging = "ZIP"
    name = "example-artifacts"
  }

  environment {
    compute_type                = "BUILD_GENERAL1_SMALL"
    image                       = "aws/codebuild/amazonlinux2-x86_64-standard:4.0"
    type                        = "LINUX_CONTAINER"
    image_pull_credentials_type = "CODEBUILD"
    privileged_mode             = true

    environment_variable {
      name  = "EXAMPLE_VAR"
      value = "example-value"
    }
  }

  source {
    type            = "GITHUB"
    location        = "https://github.com/example/example-repo.git"
    git_clone_depth = 1
    buildspec       = "buildspec.yml"
  }

  source_version = "main"

  cache {
    type     = "S3"
    location = aws_s3_bucket.codebuild_bucket.bucket
  }

  tags = {
    Environment = "example"
    Project     = "demo"
  }
}

# CodeBuild Build Batch Configuration
resource "aws_codebuild_project" "example_batch" {
  name          = "example-batch-project"
  description   = "Example CodeBuild project with batch configuration"
  build_timeout = "60"
  service_role  = aws_iam_role.codebuild_role.arn

  artifacts {
    type = "NO_ARTIFACTS"
  }

  environment {
    compute_type                = "BUILD_GENERAL1_SMALL"
    image                       = "aws/codebuild/amazonlinux2-x86_64-standard:4.0"
    type                        = "LINUX_CONTAINER"
    image_pull_credentials_type = "CODEBUILD"
  }

  source {
    type            = "GITHUB"
    location        = "https://github.com/example/example-repo.git"
    git_clone_depth = 1
    buildspec       = "buildspec-batch.yml"
  }

  build_batch_config {
    service_role = aws_iam_role.codebuild_role.arn
    timeout_in_mins = 120

    restrictions {
      maximum_builds_allowed = 10
      compute_types_allowed  = ["BUILD_GENERAL1_SMALL", "BUILD_GENERAL1_MEDIUM"]
    }

    batch_report_mode = "REPORT_AGGREGATED_BATCH"
  }

  tags = {
    Environment = "example"
    Project     = "batch-demo"
  }
}

# CodeBuild Webhook (optional - for GitHub integration)
resource "aws_codebuild_webhook" "example" {
  project_name = aws_codebuild_project.example.name
  build_type   = "BUILD_BATCH"

  filter_group {
    filter {
      type    = "EVENT"
      pattern = "PUSH, PULL_REQUEST_CREATED, PULL_REQUEST_UPDATED"
    }

    filter {
      type    = "HEAD_REF"
      pattern = "refs/heads/main"
    }
  }

  filter_group {
    filter {
      type    = "EVENT"
      pattern = "PULL_REQUEST_CREATED, PULL_REQUEST_UPDATED"
    }

    filter {
      type    = "BASE_REF"
      pattern = "refs/heads/develop"
    }
  }
}

# CodeBuild Report Group
resource "aws_codebuild_report_group" "example" {
  name = "example-report-group"
  type = "TEST"

  export_config {
    type = "S3"
    s3_destination {
      bucket = aws_s3_bucket.codebuild_bucket.bucket
      path   = "reports"
    }
  }

  tags = {
    Environment = "example"
  }
}

