# S3 Bucket for artifacts
resource "aws_s3_bucket" "artifacts" {
  bucket = "${local.project_name}-artifacts-${data.aws_caller_identity.current.account_id}"
}

data "aws_caller_identity" "current" {}

# CodeBuild Project
resource "aws_codebuild_project" "example" {
  name          = local.project_name
  description   = "Example CodeBuild project with secondary sources and artifacts"
  build_timeout = "60"
  service_role  = aws_iam_role.codebuild_role.arn

  artifacts {
    type = "S3"
    location = aws_s3_bucket.artifacts.bucket
    name     = "primary-artifacts.zip"
    packaging = "ZIP"
  }

  environment {
    compute_type                = "BUILD_GENERAL1_SMALL"
    image                       = "aws/codebuild/standard:5.0"
    type                        = "LINUX_CONTAINER"
    image_pull_credentials_type = "CODEBUILD"
    privileged_mode             = true

    environment_variable {
      name  = "ENV"
      value = "production"
    }

    environment_variable {
      name  = "AWS_DEFAULT_REGION"
      value = "us-east-1"
    }

    environment_variable {
      name  = "SECRET_VALUE"
      value = "arn:aws:secretsmanager:us-east-1:123456789012:secret:my-secret"
      type  = "SECRETS_MANAGER"
    }
  }

  source {
    type            = "GITHUB"
    location        = "https://github.com/example/primary-repo.git"
    git_clone_depth = 1
    buildspec       = "buildspec.yml"
  }

  secondary_sources {
    type            = "GITHUB"
    location        = "https://github.com/example/shared-libs.git"
    source_identifier = "SHARED_LIBS"
    git_clone_depth = 1
  }

  secondary_sources {
    type            = "GITHUB"
    location        = "https://github.com/example/configs.git"
    source_identifier = "CONFIGS"
    git_clone_depth = 1
  }

  secondary_artifacts {
    type           = "S3"
    location       = aws_s3_bucket.artifacts.bucket
    name           = "secondary-artifacts-1.zip"
    packaging      = "ZIP"
    artifact_identifier = "Artifact1"
  }

  secondary_artifacts {
    type           = "S3"
    location       = aws_s3_bucket.artifacts.bucket
    name           = "secondary-artifacts-2.zip"
    packaging      = "ZIP"
    artifact_identifier = "Artifact2"
  }

  cache {
    type     = "S3"
    location = "${aws_s3_bucket.artifacts.bucket}/cache"
  }

  tags = {
    Environment = "production"
    Project     = "example"
  }
}

