# Intent with multiple slots
resource "aws_lex_intent" "order_pizza" {
  name        = "OrderPizza"
  description = "Intent to order a pizza"

  sample_utterances = [
    "I want to order a pizza",
    "I'd like a pizza",
    "Can I get a {PizzaSize} {PizzaCrust} pizza",
    "I want a {PizzaSize} pizza with {Toppings}",
    "Order a pizza",
    "I need a pizza for delivery"
  ]

  # Slot for pizza size
  slot {
    name           = "PizzaSize"
    description    = "The size of the pizza"
    slot_constraint = "Required"
    slot_type      = aws_lex_slot_type.pizza_size.name
    priority       = 1

    value_elicitation_prompt {
      max_attempts = 2

      message {
        content_type = "PlainText"
        content      = "What size pizza would you like? We have small, medium, large, and extra large."
      }
    }
  }

  # Slot for pizza crust
  slot {
    name           = "PizzaCrust"
    description    = "The type of crust"
    slot_constraint = "Required"
    slot_type      = aws_lex_slot_type.pizza_crust.name
    priority       = 2

    value_elicitation_prompt {
      max_attempts = 2

      message {
        content_type = "PlainText"
        content      = "What type of crust would you like? We have thin, thick, stuffed, or gluten free."
      }
    }
  }

  # Slot for toppings (multiple values allowed)
  slot {
    name           = "Toppings"
    description    = "The toppings for the pizza"
    slot_constraint = "Required"
    slot_type      = aws_lex_slot_type.toppings.name
    priority       = 3

    value_elicitation_prompt {
      max_attempts = 2

      message {
        content_type = "PlainText"
        content      = "What toppings would you like? You can choose from pepperoni, mushrooms, onions, sausage, bacon, extra cheese, peppers, or olives."
      }
    }
  }

  # Slot for quantity (built-in AMAZON.NUMBER)
  slot {
    name           = "Quantity"
    description    = "Number of pizzas"
    slot_constraint = "Required"
    slot_type      = "AMAZON.NUMBER"
    priority       = 4

    value_elicitation_prompt {
      max_attempts = 2

      message {
        content_type = "PlainText"
        content      = "How many pizzas would you like to order?"
      }
    }
  }

  # Slot for delivery address (built-in AMAZON.StreetAddress)
  slot {
    name           = "DeliveryAddress"
    description    = "The delivery address"
    slot_constraint = "Required"
    slot_type      = "AMAZON.StreetAddress"
    priority       = 5

    value_elicitation_prompt {
      max_attempts = 2

      message {
        content_type = "PlainText"
        content      = "What address should we deliver the pizza to?"
      }
    }
  }

  # Slot for phone number (built-in AMAZON.PhoneNumber)
  slot {
    name           = "PhoneNumber"
    description    = "Contact phone number"
    slot_constraint = "Required"
    slot_type      = "AMAZON.PhoneNumber"
    priority       = 6

    value_elicitation_prompt {
      max_attempts = 2

      message {
        content_type = "PlainText"
        content      = "What's the best phone number to reach you at?"
      }
    }
  }

  # Slot for delivery time (built-in AMAZON.TIME)
  slot {
    name           = "DeliveryTime"
    description    = "Preferred delivery time"
    slot_constraint = "Optional"
    slot_type      = "AMAZON.TIME"
    priority       = 7

    value_elicitation_prompt {
      max_attempts = 2

      message {
        content_type = "PlainText"
        content      = "What time would you like the pizza delivered? (optional)"
      }
    }
  }

  confirmation_prompt {
    max_attempts = 2

    message {
      content_type = "PlainText"
      content      = "Got it. I'll order {Quantity} {PizzaSize} {PizzaCrust} pizza(s) with {Toppings} to be delivered to {DeliveryAddress}. Is that correct?"
    }
  }

  rejection_statement {
    message {
      content_type = "PlainText"
      content      = "Okay, I've cancelled your order. Let me know if you'd like to start over."
    }
  }

  fulfillment_activity {
    type = "ReturnIntent"
  }
}

# Fallback intent
resource "aws_lex_intent" "fallback_intent" {
  name        = "FallbackIntent"
  description = "Default fallback when user input is not understood"

  sample_utterances = []

