        content      = "What toppings would you like on your pizza? You can choose from pepperoni, mushrooms, onions, sausage, bacon, extra cheese, black olives, green peppers, pineapple, and spinach."
      }
    }
  }

  # Follow-up Slot: Delivery or Pickup
  slot {
    name           = "DeliveryMethod"
    description    = "Whether the customer wants delivery or pickup"
    slot_type      = "AMAZON.YesNo"  # Using built-in slot type
    slot_constraint = "Required"

    value_elicitation_prompt {
      max_attempts = 2

      message {
        content_type = "PlainText"
        content      = "Would you like your pizza delivered? (yes or no)"
      }
    }
  }

  # Follow-up Slot: Address (conditional, but we'll make it required for simplicity)
  slot {
    name           = "Address"
    description    = "The delivery address"
    slot_type      = "AMAZON.PostalAddress"
    slot_constraint = "Required"

    value_elicitation_prompt {
      max_attempts = 2

      message {
        content_type = "PlainText"
        content      = "What's the address for delivery?"
      }
    }
  }

  # Confirmation Prompt
  confirmation_prompt {
    max_attempts = 2

    message {
      content_type = "PlainText"
      content      = "Okay, I have your order for a {Size} pizza with {Crust} crust and {Toppings} for delivery to {Address}. Is this correct?"
    }
  }

  # Rejection Statement
  rejection_statement {
    message {
      content_type = "PlainText"
      content      = "Okay, I've cancelled your order. Let me know if you'd like to start over."
    }
  }

  # Fulfillment Activity
  fulfillment_activity {
    type = "ReturnIntent"
  }

  conclusion_statement {
    message {
      content_type = "PlainText"
      content      = "Great! Your pizza order has been placed. It will be delivered to {Address} in about 30-45 minutes. Enjoy your meal!"
    }
  }

  create_version = false
}

# Fallback Intent
resource "aws_lex_intent" "fallback" {
  name           = "FallbackIntent"
  description    = "Default fallback intent"
  fallback_intent = true

  conclusion_statement {
    message {
      content_type = "PlainText"
      content      = "I'm sorry, I didn't understand that. Can you please rephrase? You can say things like 'I want to order a pizza' or 'Order a large pizza'."
    }
  }

  create_version = false
}

# Lex Bot
resource "aws_lex_bot" "pizza_bot" {
  name        = "PizzaOrderBot"
  description = "Bot for ordering pizza with follow-up questions"
  locale      = "en-US"
  voice_id    = "Salli"

  abort_statement {
    message {
      content_type = "PlainText"
      content      = "Sorry, I'm having trouble understanding. Please try again later."
    }
  }

  clarification_prompt {
    max_attempts = 2

    message {
      content_type = "PlainText"
      content      = "I didn't understand you, what would you like me to do?"
    }
  }

  child_directed = false

  intent {
    intent_name    = aws_lex_intent.order_pizza.name
    intent_version = "$LATEST"
  }

  intent {
    intent_name    = aws_lex_intent.fallback.name
    intent_version = "$LATEST"
  }

  idle_session_ttl_in_seconds = 300
  process_behavior            = "SAVE"

  depends_on = [
    aws_lex_intent.order_pizza,
    aws_lex_intent.fallback,
    aws_lex_slot_type.crust_type,
    aws_lex_slot_type.pizza_size,
    aws_lex_slot_type.toppings
  ]
}

# Bot Alias
resource "aws_lex_bot_alias" "pizza_bot_alias" {
  name        = "PizzaBotProd"
  description = "Production alias for Pizza Order Bot"
  bot_name    = aws_lex_bot.pizza_bot.name
  bot_version = "$LATEST"

  depends_on = [aws_lex_bot.pizza_bot]
}

# Outputs
output "bot_name" {
  description = "Name of the Lex Bot"
  value       = aws_lex_bot.pizza_bot.name
}

output "bot_alias" {
  description = "Alias of the Lex Bot"
  value       = aws_lex_bot_alias.pizza_bot_alias.name
}

