provider "aws" {
  region = "us-east-1"
}

# IAM Role for Lex Bot
resource "aws_iam_role" "lex_bot_role" {
  name = "lex-pizza-bot-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "lex.amazonaws.com"
        }
      }
    ]
  })
}

resource "aws_iam_role_policy" "lex_bot_policy" {
  name = "lex-pizza-bot-policy"
  role = aws_iam_role.lex_bot_role.id

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect = "Allow"
        Action = [
          "polly:SynthesizeSpeech",
          "comprehend:DetectSentiment"
        ]
        Resource = "*"
      }
    ]
  })
}

# Custom Slot Type for Pizza Crust
resource "aws_lex_slot_type" "crust_type" {
  name                     = "PizzaCrustType"
  description              = "Types of pizza crust available"
  create_version           = false
  value_selection_strategy = "ORIGINAL_VALUE"

  enumeration_value {
    value = "thin"
  }

  enumeration_value {
    value = "thick"
  }

  enumeration_value {
    value = "stuffed"
  }

  enumeration_value {
    value = "gluten free"
  }
}

