    description    = "The type of crust for the pizza"
    slot_type      = aws_lex_slot_type.crust_type.name
    slot_type_version = "$LATEST"
    slot_constraint = "Required"

    value_elicitation_prompt {
      max_attempts = 2

      message {
        content_type = "PlainText"
        content      = "What type of crust would you like? We have thin, thick, stuffed, and gluten free."
      }
    }
  }

  # Toppings Slot
  slot {
    name           = "Toppings"
    description    = "The toppings for the pizza"
    slot_type      = aws_lex_slot_type.toppings.name
    slot_type_version = "$LATEST"
    slot_constraint = "Required"

    value_elicitation_prompt {
      max_attempts = 2

      message {
        content_type = "PlainText"
        content      = "What toppings would you like on your pizza? You can choose from pepperoni, mushrooms, onions, sausage, bacon, extra cheese, black olives, green peppers, pineapple, and spinach."
      }
    }
  }

  # Follow-up Slot: Delivery or Pickup
  slot {
    name           = "DeliveryMethod"
    description    = "Whether the customer wants delivery or pickup"
    slot_type      = "AMAZON.YesNo"  # Using built-in slot type
    slot_constraint = "Required"

    value_elicitation_prompt {
      max_attempts = 2

      message {
        content_type = "PlainText"
        content      = "Would you like your pizza delivered? (yes or no)"
      }
    }
  }

  # Follow-up Slot: Address (conditional, but we'll make it required for simplicity)
  slot {
    name           = "Address"
    description    = "The delivery address"
    slot_type      = "AMAZON.PostalAddress"
    slot_constraint = "Required"

    value_elicitation_prompt {
      max_attempts = 2

      message {
        content_type = "PlainText"
        content      = "What's the address for delivery?"
      }
    }
  }

  # Confirmation Prompt
  confirmation_prompt {
    max_attempts = 2

    message {
      content_type = "PlainText"
      content      = "Okay, I have your order for a {Size} pizza with {Crust} crust and {Toppings} for delivery to {Address}. Is this correct?"
    }
  }

  # Rejection Statement
  rejection_statement {
    message {
      content_type = "PlainText"
      content      = "Okay, I've cancelled your order. Let me know if you'd like to start over."
    }
  }

  # Fulfillment Activity
  fulfillment_activity {
    type = "ReturnIntent"
  }

  conclusion_statement {
    message {
      content_type = "PlainText"
      content      = "Great! Your pizza order has been placed. It will be delivered to {Address} in about 30-45 minutes. Enjoy your meal!"
    }
  }

  create_version = false
}

# Fallback Intent
