# Intent: BookCar
resource "aws_lex_intent" "book_car" {
  name        = "BookCar"
  description = "Intent to book a rental car"

  sample_utterances = [
    "I need a car",
    "Book a car",
    "Rent a car",
    "I want to rent a {CarType} car",
    "Book a car from {PickUpCity} to {ReturnCity}",
    "I need a car from {PickUpDate} to {ReturnDate}",
    "Rent a {CarType} in {PickUpCity}",
    "Book a car for {DriverAge} year old driver"
  ]

  confirmation_prompt {
    max_attempts = 2

    message {
      content_type = "PlainText"
      content      = "Okay, I have you down for a {CarType} rental in {PickUpCity} from {PickUpDate} to {ReturnDate}. Should I book the reservation?"
    }
  }

  rejection_statement {
    message {
      content_type = "PlainText"
      content      = "Okay, I have cancelled your reservation in progress. Let me know if you would like to book a car rental."
    }
  }

  follow_up_prompt {
    prompt {
      max_attempts = 2

      message {
        content_type = "PlainText"
        content      = "Would you like to book a hotel room with your car rental?"
      }
    }

    rejection_statement {
      message {
        content_type = "PlainText"
        content      = "Okay, I will just book the car rental for you."
      }
    }
  }

  conclusion_statement {
    message {
      content_type = "PlainText"
      content      = "Your car rental has been booked. Confirmation number: {ConfirmationNumber}"
    }
  }

  # Slot: PickUpCity
  slot {
    name           = "PickUpCity"
    slot_type      = "AMAZON.US_CITY"
    slot_constraint = "Required"

    value_elicitation_prompt {
      max_attempts = 3

      message {
        content_type = "PlainText"
        content      = "In what city do you need to rent a car?"
      }
    }
  }

  # Slot: PickUpDate
  slot {
    name           = "PickUpDate"
    slot_type      = "AMAZON.DATE"
    slot_constraint = "Required"

    value_elicitation_prompt {
      max_attempts = 3

      message {
        content_type = "PlainText"
        content      = "What day do you want to start your rental?"
      }
    }
  }

  # Slot: ReturnDate
  slot {
    name           = "ReturnDate"
    slot_type      = "AMAZON.DATE"
    slot_constraint = "Required"

    value_elicitation_prompt {
      max_attempts = 3

      message {
        content_type = "PlainText"
        content      = "What day do you want to return the car?"
      }
    }
  }

  # Slot: DriverAge
  slot {
    name           = "DriverAge"
    slot_type      = "AMAZON.NUMBER"
    slot_constraint = "Required"

    value_elicitation_prompt {
      max_attempts = 3

      message {
        content_type = "PlainText"
        content      = "How old is the driver for this rental?"
      }
    }
  }

  # Slot: CarType
  slot {
    name           = "CarType"
    slot_type      = aws_lex_slot_type.car_types.name
    slot_constraint = "Required"

    value_elicitation_prompt {
      max_attempts = 3

      message {
        content_type = "PlainText"
        content      = "What type of car would you like to rent? Our most popular options are economy, standard, luxury, and SUV."
      }
    }
  }

  # Slot: ReturnCity
  slot {
    name           = "ReturnCity"
    slot_type      = "AMAZON.US_CITY"
    slot_constraint = "Optional"

    value_elicitation_prompt {
      max_attempts = 3

      message {
        content_type = "PlainText"
        content      = "Where will you return the car?"
      }
    }
  }

  fulfillment_activity {
    type = "ReturnIntent"
  }
}

