# Intent: BookTrip (Combined with CodeHook)
resource "aws_lex_intent" "book_trip" {
  name        = "BookTrip"
  description = "Intent to book a complete trip with car and hotel"

  sample_utterances = [
    "Book a trip",
    "I want to book a vacation",
    "Plan a trip",
    "Book a trip to {Destination}",
    "I want to go to {Destination}",
    "Plan a vacation from {TravelDate}",
    "Book travel for {Travelers} people"
  ]

  confirmation_prompt {
    max_attempts = 2

    message {
      content_type = "PlainText"
      content      = "Please confirm: Trip to {Destination} for {Travelers} people starting {TravelDate} for {Duration} days. Is this correct?"
    }
  }

  rejection_statement {
    message {
      content_type = "PlainText"
      content      = "Okay, I have cancelled your trip booking. Let me know if you would like to plan a different trip."
    }
  }

  conclusion_statement {
    message {
      content_type = "PlainText"
      content      = "Your trip has been booked! Confirmation: {TripConfirmationNumber}"
    }
  }

  # Slot: Destination
  slot {
    name           = "Destination"
    slot_type      = "AMAZON.US_CITY"
    slot_constraint = "Required"

    value_elicitation_prompt {
      max_attempts = 3

      message {
        content_type = "PlainText"
        content      = "Where would you like to go?"
      }
    }
  }

  # Slot: TravelDate
  slot {
    name           = "TravelDate"
    slot_type      = "AMAZON.DATE"
    slot_constraint = "Required"

    value_elicitation_prompt {
      max_attempts = 3

      message {
        content_type = "PlainText"
        content      = "When do you want to start your trip?"
      }
    }
  }

  # Slot: Duration
  slot {
    name           = "Duration"
    slot_type      = "AMAZON.NUMBER"
    slot_constraint = "Required"

    value_elicitation_prompt {
      max_attempts = 3

      message {
        content_type = "PlainText"
        content      = "How many days will your trip be?"
      }
    }
  }

  # Slot: Travelers
  slot {
    name           = "Travelers"
    slot_type      = "AMAZON.NUMBER"
    slot_constraint = "Required"

    value_elicitation_prompt {
      max_attempts = 3

      message {
        content_type = "PlainText"
        content      = "How many people will be traveling?"
      }
    }
  }

  # Slot: Budget
  slot {
    name           = "Budget"
    slot_type      = "AMAZON.NUMBER"
    slot_constraint = "Optional"

    value_elicitation_prompt {
      max_attempts = 2

      message {
        content_type = "PlainText"
        content      = "What is your approximate budget for this trip?"
      }
    }
  }

  fulfillment_activity {
    type = "CodeHook"

    code_hook {
      message_version = "1.0"
      uri             = aws_lambda_function.book_trip_fulfillment.arn
    }
  }
}

# Main Lex Bot
resource "aws_lex_bot" "book_trip_bot" {
  name                        = "BookTripBot"
  description                 = "Bot to book car rentals, hotel rooms, and complete trips"
  voice_id                    = "Joanna"
  idle_session_ttl_in_seconds = 600
  process_behavior            = "BUILD"
  locale                      = "en-US"
  child_directed              = false
  detect_sentiment            = true
  create_version              = true

  abort_statement {
    message {
      content_type = "PlainText"
      content      = "Sorry, I could not understand. Goodbye."
    }

    message {
      content_type = "PlainText"
      content      = "I'm having trouble understanding. Please call our customer service at 1-800-TRIP-BOOK."
    }
  }

  clarification_prompt {
    max_attempts = 3

    message {
      content_type = "PlainText"
      content      = "Sorry, did you want to book a car, book a hotel, or plan a complete trip?"
    }

    message {
      content_type = "PlainText"
      content      = "I didn't understand that. You can say things like 'book a car', 'reserve a hotel', or 'plan a trip'."
    }
  }

  greeting_intent {
    intent_name    = "WelcomeIntent"
    intent_version = "$LATEST"
  }

  intent {
    intent_name    = aws_lex_intent.book_car.name
    intent_version = "$LATEST"
  }

  intent {
    intent_name    = aws_lex_intent.book_hotel.name
    intent_version = "$LATEST"
  }

  intent {
    intent_name    = aws_lex_intent.book_trip.name
    intent_version = "$LATEST"
  }

  enable_model_improvements = true
  nlu_intent_confidence_threshold = 0.4

  tags = {
    Environment = "Production"
    Project     = "TravelBooking"
    Owner       = "TravelTeam"
    CostCenter  = "12345"
  }
}

# Lex Bot Alias
resource "aws_lex_bot_alias" "book_trip_prod" {
  name        = "PROD"
  description = "Production alias for BookTripBot"
  bot_name    = aws_lex_bot.book_trip_bot.name
  bot_version = "$LATEST"

  conversation_logs {
    log_settings {
      destination = "CLOUDWATCH_LOGS"
      log_type    = "AUDIO"
      resource_arn = aws_cloudwatch_log_group.lex_audio_logs.arn
    }

    log_settings {
      destination = "S3"
      log_type    = "TEXT"
      resource_arn = aws_s3_bucket.lex_logs.arn
      kms_key_arn  = aws_kms_key.lex_logs_key.arn
    }

    iam_role_arn = aws_iam_role.lex_logs_role.arn
  }
}

# Supporting Resources for Logging
resource "aws_cloudwatch_log_group" "lex_audio_logs" {
  name              = "/aws/lex/BookTripBot/audio"
  retention_in_days = 30

  kms_key_id = aws_kms_key.lex_logs_key.arn
}

resource "aws_s3_bucket" "lex_logs" {
  bucket = "lex-book-trip-logs-${data.aws_caller_identity.current.account_id}"
}

resource "aws_s3_bucket_versioning" "lex_logs_versioning" {
  bucket = aws_s3_bucket.lex_logs.id

  versioning_configuration {
    status = "Enabled"
  }
}

resource "aws_s3_bucket_server_side_encryption_configuration" "lex_logs_encryption" {
  bucket = aws_s3_bucket.lex_logs.id

  rule {
    apply_server_side_encryption_by_default {
      kms_master_key_id = aws_kms_key.lex_logs_key.arn
      sse_algorithm     = "aws:kms"
    }
  }
}

resource "aws_kms_key" "lex_logs_key" {
  description             = "KMS key for Lex logs encryption"
  deletion_window_in_days = 30
  enable_key_rotation     = true
}

resource "aws_kms_alias" "lex_logs_key_alias" {
  name          = "alias/lex-book-trip-logs"
  target_key_id = aws_kms_key.lex_logs_key.key_id
}

resource "aws_iam_role" "lex_logs_role" {
  name = "lex-book-trip-logs-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "lex.amazonaws.com"
        }
      }
    ]
  })
}

resource "aws_iam_role_policy" "lex_logs_policy" {
  name = "lex-book-trip-logs-policy"
  role = aws_iam_role.lex_logs_role.id

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect = "Allow"
        Action = [
          "logs:CreateLogStream",
          "logs:PutLogEvents"
        ]
        Resource = "${aws_cloudwatch_log_group.lex_audio_logs.arn}:*"
      },
      {
        Effect = "Allow"
        Action = [
          "s3:PutObject"
        ]
        Resource = "${aws_s3_bucket.lex_logs.arn}/*"
      },
      {
        Effect = "Allow"
        Action = [
          "kms:Encrypt",
          "kms:Decrypt",
          "kms:GenerateDataKey*"
        ]
        Resource = aws_kms_key.lex_logs_key.arn
      }
    ]
  })
}

# Data source for account ID
data "aws_caller_identity" "current" {}

# Output values
output "bot_name" {
  value = aws_lex_bot.book_trip_bot.name
}

output "bot_alias" {
  value = aws_lex_bot_alias.book_trip_prod.name
}

output "lambda_function_arn" {
  value = aws_lambda_function.book_trip_fulfillment.arn
}

