}

provider "aws" {
  region = "us-east-1"
}

# IAM Role for Lex Bot
resource "aws_iam_role" "lex_bot_role" {
  name = "pizza_bot_role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "lex.amazonaws.com"
        }
      }
    ]
  })
}

# Lambda function for fulfillment (placeholder)
resource "aws_lambda_function" "pizza_fulfillment" {
  filename         = "pizza_fulfillment.zip"
  function_name    = "pizza_fulfillment"
  role             = aws_iam_role.lambda_role.arn
  handler          = "index.handler"
  runtime          = "python3.9"
  source_code_hash = filebase64sha256("pizza_fulfillment.zip")

  lifecycle {
    ignore_changes = [source_code_hash]
  }
}

resource "aws_iam_role" "lambda_role" {
  name = "pizza_lambda_role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "lambda.amazonaws.com"
        }
      }
    ]
  })
}

resource "aws_iam_role_policy_attachment" "lambda_basic" {
  role       = aws_iam_role.lambda_role.name
  policy_arn = "arn:aws:iam::aws:policy/service-role/AWSLambdaBasicExecutionRole"
}

# Custom Slot Types
resource "aws_lex_slot_type" "pizza_size" {
  name        = "PizzaSize"
  description = "Sizes available for pizza"

  enumeration_value {
    value = "small"
  }
  enumeration_value {
    value = "medium"
  }
  enumeration_value {
    value = "large"
  }
  enumeration_value {
    value = "extra large"
  }

  value_selection_strategy = "ORIGINAL_VALUE"
}

resource "aws_lex_slot_type" "pizza_crust" {
  name        = "PizzaCrust"
  description = "Types of pizza crust"

  enumeration_value {
    value = "thin"
  }
  enumeration_value {
    value = "thick"
  }
  enumeration_value {
    value = "stuffed"
  }
  enumeration_value {
    value = "gluten free"
  }

  value_selection_strategy = "ORIGINAL_VALUE"
}

resource "aws_lex_slot_type" "pizza_topping" {
  name        = "PizzaTopping"
  description = "Available pizza toppings"

  enumeration_value {
    value = "pepperoni"
  }
  enumeration_value {
    value = "mushrooms"
  }
  enumeration_value {
    value = "onions"
  }
  enumeration_value {
    value = "sausage"
  }
  enumeration_value {
    value = "bacon"
  }
  enumeration_value {
    value = "extra cheese"
  }
  enumeration_value {
    value = "black olives"
  }
  enumeration_value {
    value = "green peppers"
  }

  value_selection_strategy = "ORIGINAL_VALUE"
}

# Intent 1: OrderPizza
resource "aws_lex_intent" "order_pizza" {
  name        = "OrderPizza"
  description = "Intent to order a pizza"

  sample_utterances = [
    "I want to order a pizza",
    "I'd like a pizza",
    "Can I get a pizza",
    "Order a pizza",
    "I need a pizza",
    "Get me a pizza"
  ]

  slot {
    name           = "PizzaSize"
    slot_type      = aws_lex_slot_type.pizza_size.name
    slot_type_version = "$LATEST"
    description    = "The size of the pizza"
    priority       = 1

    value_elicitation_prompt {
      max_attempts = 2

      message {
        content_type = "PlainText"
        content      = "What size pizza would you like? We have small, medium, large, and extra large."
      }
    }
  }

  slot {
    name           = "PizzaCrust"
    slot_type      = aws_lex_slot_type.pizza_crust.name
    slot_type_version = "$LATEST"
    description    = "The type of crust"
    priority       = 2

    value_elicitation_prompt {
      max_attempts = 2

      message {
        content_type = "PlainText"
        content      = "What type of crust would you like? Thin, thick, stuffed, or gluten free?"
      }
    }
  }

  slot {
    name           = "PizzaTopping"
    slot_type      = aws_lex_slot_type.pizza_topping.name
    slot_type_version = "$LATEST"
    description    = "The pizza topping"
    priority       = 3

    value_elicitation_prompt {
      max_attempts = 2

      message {
        content_type = "PlainText"
        content      = "What topping would you like on your pizza?"
      }
    }
  }

  confirmation_prompt {
    max_attempts = 2

    message {
      content_type = "PlainText"
      content      = "I'll order a {PizzaSize} {PizzaCrust} crust pizza with {PizzaTopping}. Is that correct?"
    }
  }

  rejection_statement {
    message {
      content_type = "PlainText"
      content      = "Okay, I've cancelled your pizza order."
    }
  }

  fulfillment_activity {
    type = "ReturnIntent"
  }
}

# Intent 2: CheckOrderStatus
resource "aws_lex_intent" "check_order_status" {
  name        = "CheckOrderStatus"
  description = "Intent to check the status of an existing order"

  sample_utterances = [
    "What's the status of my order",
    "Where is my pizza",
    "Is my pizza ready",
    "Check my order status",
    "When will my pizza arrive",
    "Track my order"
  ]

  slot {
    name           = "OrderNumber"
    slot_type      = "AMAZON.NUMBER"
    description    = "The order number to check"
    priority       = 1

    value_elicitation_prompt {
      max_attempts = 2

      message {
        content_type = "PlainText"
        content      = "What's your order number?"
      }
    }
  }

  fulfillment_activity {
    type = "ReturnIntent"
  }
}

# Intent 3: CancelOrder
resource "aws_lex_intent" "cancel_order" {
  name        = "CancelOrder"
  description = "Intent to cancel an existing order"

  sample_utterances = [
    "I want to cancel my order",
    "Cancel my pizza order",
    "I need to cancel",
    "Please cancel my order",
    "I don't want the pizza anymore"
  ]

  slot {
    name           = "OrderNumber"
    slot_type      = "AMAZON.NUMBER"
    description    = "The order number to cancel"
    priority       = 1

    value_elicitation_prompt {
      max_attempts = 2

      message {
        content_type = "PlainText"
        content      = "What's your order number that you'd like to cancel?"
      }
    }
  }

  confirmation_prompt {
    max_attempts = 2

    message {
      content_type = "PlainText"
      content      = "Are you sure you want to cancel order number {OrderNumber}?"
    }
  }

  rejection_statement {
    message {
      content_type = "PlainText"
      content      = "Okay, I won't cancel your order."
    }
  }

  fulfillment_activity {
    type = "ReturnIntent"
  }
}

# Intent 4: ModifyOrder
resource "aws_lex_intent" "modify_order" {
  name        = "ModifyOrder"
  description = "Intent to modify an existing order"

  sample_utterances = [
    "I want to change my order",
    "Modify my order",
    "Can I update my pizza order",
    "I need to change something on my order",
    "Change my pizza"
  ]

  slot {
    name           = "OrderNumber"
    slot_type      = "AMAZON.NUMBER"
    description    = "The order number to modify"
    priority       = 1

    value_elicitation_prompt {
      max_attempts = 2

      message {
        content_type = "PlainText"
        content      = "What's your order number?"
      }
    }
  }

  slot {
    name           = "ModificationType"
    slot_type      = "AMAZON.FreeText"
    description    = "What the user wants to change"
    priority       = 2

    value_elicitation_prompt {
      max_attempts = 2

      message {
        content_type = "PlainText"
        content      = "What would you like to change about your order?"
      }
    }
  }

  fulfillment_activity {
    type = "ReturnIntent"
  }
}

# Intent 5: GetMenu
resource "aws_lex_intent" "get_menu" {
  name        = "GetMenu"
  description = "Intent to view the pizza menu"

  sample_utterances = [
    "What's on the menu",
    "Show me the menu",
    "What pizzas do you have",
    "What are your options",
    "Tell me about your pizzas",
    "What do you offer"
  ]

  fulfillment_activity {
    type = "ReturnIntent"
  }

  conclusion_statement {
    message {
      content_type = "PlainText"
      content      = "We offer pizzas in small, medium, large, and extra large sizes with thin, thick, stuffed, or gluten-free crust. Toppings include pepperoni, mushrooms, onions, sausage, bacon, extra cheese, black olives, and green peppers. Would you like to place an order?"
    }
  }
}

# Main Lex Bot
resource "aws_lex_bot" "pizza_bot" {
  name        = "PizzaOrderingBot"
  description = "Bot for ordering pizzas"
  voice_id    = "Salli"
  locale      = "en-US"
  child_directed = false

  abort_statement {
    message {
      content_type = "PlainText"
      content      = "Sorry, I'm having trouble understanding. Please call our store at 555-PIZZA for assistance."
    }
  }

  clarification_prompt {
    max_attempts = 2

    message {
      content_type = "PlainText"
      content      = "I didn't understand that. Can you please rephrase? You can say things like 'order a pizza', 'check my order', or 'view the menu'."
    }
  }

  intent {
    intent_name    = aws_lex_intent.order_pizza.name
    intent_version = "$LATEST"
  }

  intent {
    intent_name    = aws_lex_intent.check_order_status.name
    intent_version = "$LATEST"
  }

  intent {
    intent_name    = aws_lex_intent.cancel_order.name
    intent_version = "$LATEST"
  }

  intent {
    intent_name    = aws_lex_intent.modify_order.name
    intent_version = "$LATEST"
  }

  intent {
    intent_name    = aws_lex_intent.get_menu.name
    intent_version = "$LATEST"
  }

  depends_on = [
    aws_lex_intent.order_pizza,
    aws_lex_intent.check_order_status,
    aws_lex_intent.cancel_order,
    aws_lex_intent.modify_order,
    aws_lex_intent.get_menu
  ]
}

# Bot Alias
resource "aws_lex_bot_alias" "pizza_bot_prod" {
  name        = "Production"
  description = "Production alias for PizzaOrderingBot"
  bot_name    = aws_lex_bot.pizza_bot.name
  bot_version = "$LATEST"
}
