    "{CrustType} crust please"
  ]

  confirmation_prompt {
    max_attempts = 2
    message {
      content      = "Okay, so you want a {PizzaSize} {PizzaTopping} pizza with {CrustType} crust and a {Drink}. Is that right, little buddy?"
      content_type = "PlainText"
