  slot {
    name           = "PizzaTopping"
    slot_constraint = "Required"
    slot_type      = aws_lex_slot_type.pizza_topping.name
    priority       = 2

    value_elicitation_prompt {
      max_attempts = 2
      message {
        content      = "What yummy topping would you like? We have cheese, pepperoni, mushrooms, olives, pineapple, or ham!"
        content_type = "PlainText"
      }
      message {
        content      = "What do you want on your pizza? Pick your favorite topping!"
        content_type = "PlainText"
      }
