terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

provider "aws" {
  region = "us-east-1"
}

# IAM Role for Lex Bot
resource "aws_iam_role" "lex_bot_role" {
  name = "pizza_bot_role_kids"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "lex.amazonaws.com"
        }
      }
    ]
  })
}

resource "aws_iam_role_policy" "lex_bot_policy" {
  name = "pizza_bot_policy_kids"
  role = aws_iam_role.lex_bot_role.id

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect = "Allow"
        Action = [
          "polly:SynthesizeSpeech",
          "comprehend:DetectSentiment"
        ]
        Resource = "*"
      }
    ]
  })
}

# Custom Slot Type for Pizza Size
resource "aws_lex_slot_type" "pizza_size" {
  name                     = "PizzaSizeKids"
  description              = "Pizza sizes for kids"
  create_version           = false
  value_selection_strategy = "ORIGINAL_VALUE"

  enumeration_value {
    value    = "small"
    synonyms = ["tiny", "little", "mini", "kid size", "small one"]
  }

  enumeration_value {
    value    = "medium"
    synonyms = ["regular", "normal", "not too big"]
  }

  enumeration_value {
    value    = "large"
    synonyms = ["big", "huge", "giant", "super big"]
  }
}

# Custom Slot Type for Pizza Toppings (Kid-friendly)
resource "aws_lex_slot_type" "pizza_topping" {
  name                     = "PizzaToppingKids"
  description              = "Kid-friendly pizza toppings"
  create_version           = false
  value_selection_strategy = "ORIGINAL_VALUE"

  enumeration_value {
    value    = "cheese"
    synonyms = ["plain cheese", "just cheese", "cheesy", "extra cheese"]
  }

  enumeration_value {
    value    = "pepperoni"
    synonyms = ["pepperonis", "spicy circles", "red circles"]
  }

  enumeration_value {
    value    = "mushrooms"
    synonyms = ["mushroom", "fungi", "little umbrellas"]
  }

  enumeration_value {
    value    = "olives"
    synonyms = ["black olives", "green olives", "little black circles"]
  }

  enumeration_value {
    value    = "pineapple"
    synonyms = ["pineapples", "yellow fruit", "sweet circles"]
  }

  enumeration_value {
    value    = "ham"
    synonyms = ["canadian bacon", "pink ham", "bacon"]
  }
}

# Custom Slot Type for Crust Type
resource "aws_lex_slot_type" "crust_type" {
  name                     = "CrustTypeKids"
  description              = "Types of pizza crust for kids"
  create_version           = false
  value_selection_strategy = "ORIGINAL_VALUE"

  enumeration_value {
    value    = "thin"
    synonyms = ["skinny", "flat", "crispy", "crunchy"]
  }

  enumeration_value {
    value    = "thick"
    synonyms = ["fluffy", "puffy", "soft", "bread-like"]
  }

  enumeration_value {
    value    = "stuffed"
    synonyms = ["cheesy crust", "filled", "cheese inside", "cheese stuffed"]
  }
}

# Custom Slot Type for Drink
resource "aws_lex_slot_type" "drink_type" {
  name                     = "DrinkTypeKids"
  description              = "Kid-friendly drinks"
  create_version           = false
  value_selection_strategy = "ORIGINAL_VALUE"

  enumeration_value {
    value    = "juice"
    synonyms = ["apple juice", "orange juice", "fruit juice"]
  }

  enumeration_value {
    value    = "soda"
    synonyms = ["pop", "coke", "sprite", "fizzy drink"]
  }

  enumeration_value {
    value    = "milk"
    synonyms = ["chocolate milk", "white milk", "cold milk"]
  }

  enumeration_value {
    value    = "water"
    synonyms = ["cold water", "ice water"]
  }
}

# Intent: OrderPizza
resource "aws_lex_intent" "order_pizza" {
  name                     = "OrderPizzaKids"
  description              = "Intent for kids to order pizza"
  create_version           = false
  sample_utterances        = [
    "I want pizza",
    "Can I have a pizza",
    "I would like to order a pizza",
    "Pizza please",
    "I want to order pizza",
    "Can we get pizza",
    "I'm hungry for pizza",
    "Let's get pizza",
    "I want a yummy pizza",
    "Order me a pizza",
    "Pizza time",
    "I need pizza",
    "Gimme pizza",
    "Make me a pizza",
    "I want a {PizzaSize} pizza",
    "Can I get a {PizzaSize} {PizzaTopping} pizza",
    "I want {PizzaTopping} on my pizza",
    "A {PizzaSize} pizza with {PizzaTopping}",
    "I like {PizzaTopping} pizza",
    "{CrustType} crust please"
  ]

  confirmation_prompt {
    max_attempts = 2
    message {
      content      = "Okay, so you want a {PizzaSize} {PizzaTopping} pizza with {CrustType} crust and a {Drink}. Is that right, little buddy?"
      content_type = "PlainText"
    }
    message {
      content      = "Let me make sure - you want a {PizzaSize} pizza with yummy {PizzaTopping} on {CrustType} crust, and a {Drink} to drink. Correct?"
      content_type = "PlainText"
    }
  }

  rejection_statement {
    message {
      content      = "No problem! Let's start over. What kind of pizza would you like?"
      content_type = "PlainText"
    }
  }

  # Pizza Size Slot
  slot {
    name           = "PizzaSize"
    slot_constraint = "Required"
    slot_type      = aws_lex_slot_type.pizza_size.name
    priority       = 1

    value_elicitation_prompt {
      max_attempts = 2
      message {
        content      = "What size pizza would you like? We have small, medium, or large!"
        content_type = "PlainText"
      }
      message {
        content      = "How big of a pizza do you want? Small like a frisbee, medium like a plate, or large like a big tray?"
        content_type = "PlainText"
      }
    }
  }

  # Pizza Topping Slot
  slot {
    name           = "PizzaTopping"
    slot_constraint = "Required"
    slot_type      = aws_lex_slot_type.pizza_topping.name
    priority       = 2

    value_elicitation_prompt {
      max_attempts = 2
      message {
        content      = "What yummy topping would you like? We have cheese, pepperoni, mushrooms, olives, pineapple, or ham!"
        content_type = "PlainText"
      }
      message {
        content      = "What do you want on your pizza? Pick your favorite topping!"
        content_type = "PlainText"
      }
    }
  }

  # Crust Type Slot
  slot {
    name           = "CrustType"
    slot_constraint = "Required"
    slot_type      = aws_lex_slot_type.crust_type.name
    priority       = 3

    value_elicitation_prompt {
      max_attempts = 2
      message {
        content      = "What kind of crust do you want? Thin and crispy, thick and fluffy, or stuffed with cheese?"
        content_type = "PlainText"
      }
      message {
        content      = "How do you want your pizza crust? Thin like a cracker, thick like bread, or stuffed with gooey cheese?"
        content_type = "PlainText"
      }
    }
  }

  # Drink Slot
  slot {
    name           = "Drink"
    slot_constraint = "Required"
    slot_type      = aws_lex_slot_type.drink_type.name
    priority       = 4

    value_elicitation_prompt {
      max_attempts = 2
      message {
        content      = "What would you like to drink with your pizza? Juice, soda, milk, or water?"
        content_type = "PlainText"
      }
      message {
        content      = "Don't forget a drink! What sounds good - juice, soda, milk, or water?"
        content_type = "PlainText"
      }
    }
  }

  fulfillment_activity {
    type = "ReturnIntent"
  }
}

# Intent: Greeting
resource "aws_lex_intent" "greeting" {
  name              = "GreetingKids"
  description       = "Friendly greeting for kids"
  create_version    = false
  sample_utterances = [
    "Hi",
    "Hello",
    "Hey",
    "Hi there",
