# Lambda Function
data "archive_file" "lambda_zip" {
  type        = "zip"
  output_path = "${path.module}/lambda_function.zip"

  source {
    content  = <<-EOF
import json
import logging

logger = logging.getLogger()
logger.setLevel(logging.INFO)

def lambda_handler(event, context):
    logger.info('Received event: ' + json.dumps(event))

    invocation_source = event.get('invocationSource')
    session_attributes = event.get('sessionAttributes', {})

    if invocation_source == 'DialogCodeHook':
        return {
            'sessionAttributes': session_attributes,
            'dialogAction': {
                'type': 'Delegate',
                'slots': event['currentIntent']['slots']
            }
        }

    elif invocation_source == 'FulfillmentCodeHook':
        slots = event['currentIntent']['slots']
        pizza_type = slots.get('PizzaType')
        size = slots.get('Size')
        crust = slots.get('Crust')

        message = f"Your {size} {pizza_type} pizza with {crust} crust has been ordered! Estimated delivery time is 30 minutes."

        return {
            'sessionAttributes': session_attributes,
            'dialogAction': {
                'type': 'Close',
                'fulfillmentState': 'Fulfilled',
                'message': {
                    'contentType': 'PlainText',
                    'content': message
                }
            }
        }

    return {
        'sessionAttributes': session_attributes,
        'dialogAction': {
            'type': 'Close',
            'fulfillmentState': 'Failed',
            'message': {
                'contentType': 'PlainText',
                'content': 'Sorry, I could not process your order.'
            }
        }
    }
EOF
    filename = "index.py"
  }
}

