    slot_type      = aws_lex_slot_type.pizza_type.name
    slot_type_version = "$LATEST"
    priority       = 1

    value_elicitation_prompt {
      max_attempts = 2

      message {
        content      = "What type of pizza would you like? We have Pepperoni, Margherita, Hawaiian, Supreme, and Vegetarian."
        content_type = "PlainText"
      }
