    slot_type      = aws_lex_slot_type.size.name
    slot_type_version = "$LATEST"
    priority       = 2

    value_elicitation_prompt {
      max_attempts = 2

      message {
        content      = "What size would you like? Small, Medium, Large, or Extra Large?"
        content_type = "PlainText"
      }
    }
