resource "aws_lexv2models_intent" "tell_story_intent" {
  bot_id      = aws_lexv2models_bot.children_bot.id
  bot_version = "DRAFT"
  locale_id   = aws_lexv2models_bot_locale.english_locale.locale_id
  name        = "TellStoryIntent"
  description = "Tell a story to the child"

  sample_utterance {
    utterance = "Tell me a story"
  }
  sample_utterance {
    utterance = "I want to hear a story"
  }
  sample_utterance {
    utterance = "Can you tell me a story"
  }
  sample_utterance {
    utterance = "Story please"
  }

  slot {
    name           = "StoryType"
    slot_type_id   = aws_lexv2models_slot_type.story_type.id
    description    = "Type of story the child wants"
    priority       = 1

    value_elicitation_setting {
      default_value_specification {
