data "aws_caller_identity" "current" {}

data "aws_region" "current" {}

# IAM Role for Connect to assume for SAML
resource "aws_iam_role" "connect_saml" {
  name = "connect-saml-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "connect.amazonaws.com"
        }
      }
    ]
  })
}

# IAM Policy for SAML configuration
resource "aws_iam_role_policy" "connect_saml" {
  name = "connect-saml-policy"
  role = aws_iam_role.connect_saml.id

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect = "Allow"
        Action = [
          "s3:GetObject",
          "s3:ListBucket"
        ]
        Resource = "*"
      }
    ]
  })
}

# S3 bucket for SAML metadata
resource "aws_s3_bucket" "saml_metadata" {
  bucket = "connect-saml-metadata-${data.aws_caller_identity.current.account_id}-${data.aws_region.current.name}"
}

# S3 bucket versioning
resource "aws_s3_bucket_versioning" "saml_metadata" {
  bucket = aws_s3_bucket.saml_metadata.id
  versioning_configuration {
    status = "Enabled"
  }
}

# S3 bucket server-side encryption
resource "aws_s3_bucket_server_side_encryption_configuration" "saml_metadata" {
  bucket = aws_s3_bucket.saml_metadata.id

  rule {
    apply_server_side_encryption_by_default {
      sse_algorithm = "AES256"
    }
  }
}

# S3 bucket public access block
resource "aws_s3_bucket_public_access_block" "saml_metadata" {
  bucket = aws_s3_bucket.saml_metadata.id

  block_public_acls       = true
  block_public_policy     = true
  ignore_public_acls      = true
  restrict_public_buckets = true
}

# Amazon Connect Instance with SAML identity management
resource "aws_connect_instance" "saml_instance" {
  identity_management_type = "SAML"
  inbound_calls_enabled    = true
  outbound_calls_enabled   = true
  instance_alias           = "saml-connect-instance"

  # SAML specific configuration
  directory_id = null # Not used for SAML type

  # Optional: Tags
  tags = {
    Name        = "SAML Connect Instance"
    Environment = "Production"
  }
}

# Lambda function for Lex bot (required for bot association)
resource "aws_iam_role" "lex_lambda" {
  name = "lex-lambda-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "lambda.amazonaws.com"
        }
      }
    ]
  })
}

resource "aws_iam_role_policy_attachment" "lex_lambda_basic" {
  role       = aws_iam_role.lex_lambda.name
  policy_arn = "arn:aws:iam::aws:policy/service-role/AWSLambdaBasicExecutionRole"
}

resource "aws_lambda_function" "lex_bot" {
  filename      = "lambda_function_payload.zip"
  function_name = "lex-bot-fulfillment"
  role          = aws_iam_role.lex_lambda.arn
  handler       = "index.handler"
  runtime       = "python3.9"

  # Placeholder for actual Lambda code
  # In production, use archive_file data source or S3 bucket
  source_code_hash = filebase64sha256("lambda_function_payload.zip")

  environment {
    variables = {
      LOG_LEVEL = "INFO"
    }
  }
}

# CloudWatch Log Group for Lambda
resource "aws_cloudwatch_log_group" "lex_lambda" {
  name              = "/aws/lambda/${aws_lambda_function.lex_bot.function_name}"
  retention_in_days = 14
}

# Lex Bot
resource "aws_lex_bot" "example" {
  name                        = "ConnectExampleBot"
  description                 = "Example bot for Amazon Connect"
  locale                      = "en-US"
  voice_id                    = "Joanna"
  idle_session_ttl_in_seconds = 300
  process_behavior            = "BUILD"

  abort_statement {
    message {
      content      = "Sorry, I didn't understand that. Please try again."
      content_type = "PlainText"
    }
  }

  clarification_prompt {
    max_attempts = 2

    message {
      content      = "I didn't understand you, what would you like to do?"
      content_type = "PlainText"
    }
  }

  intent {
    intent_name    = aws_lex_intent.greeting.name
    intent_version = aws_lex_intent.greeting.version
  }

  intent {
    intent_name    = aws_lex_intent.fallback.name
    intent_version = aws_lex_intent.fallback.version
  }
}

# Lex Intent - Greeting
resource "aws_lex_intent" "greeting" {
  name        = "GreetingIntent"
  description = "Greeting intent for the bot"

  sample_utterances = [
    "Hello",
    "Hi",
    "Hey",
    "Good morning",
    "Good afternoon"
  ]

  fulfillment_activity {
    type = "ReturnIntent"
  }

  conclusion_statement {
    message {
      content      = "Hello! How can I help you today?"
      content_type = "PlainText"
    }
  }
}

# Lex Intent - Fallback
resource "aws_lex_intent" "fallback" {
  name        = "FallbackIntent"
  description = "Fallback intent when no other intent matches"

  sample_utterances = [
    "I don't know",
    "Help",
    "What can you do"
  ]

  fulfillment_activity {
    type = "ReturnIntent"
  }

  conclusion_statement {
    message {
      content      = "I can help you with various tasks. What would you like to do?"
      content_type = "PlainText"
    }
  }
}

