provider "aws" {
  region = "us-east-1"
}

# S3 bucket for Flink application code
resource "aws_s3_bucket" "flink_code" {
  bucket = "flink-application-code-${data.aws_caller_identity.current.account_id}"
}

resource "aws_s3_bucket_versioning" "flink_code" {
  bucket = aws_s3_bucket.flink_code.id
  versioning_configuration {
    status = "Enabled"
  }
}

# IAM role for Kinesis Analytics Application
resource "aws_iam_role" "kinesis_analytics" {
  name = "kinesis-analytics-flink-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "kinesisanalytics.amazonaws.com"
        }
      }
    ]
  })
}

# IAM policy for Kinesis Analytics Application
resource "aws_iam_role_policy" "kinesis_analytics" {
  name = "kinesis-analytics-flink-policy"
  role = aws_iam_role.kinesis_analytics.id

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect = "Allow"
        Action = [
          "kinesis:*",
          "s3:GetObject",
          "s3:GetObjectVersion",
          "s3:ListBucket",
          "logs:CreateLogGroup",
          "logs:CreateLogStream",
          "logs:PutLogEvents",
          "cloudwatch:PutMetricData"
        ]
        Resource = "*"
      }
    ]
  })
}

# CloudWatch Log Group for Flink application
resource "aws_cloudwatch_log_group" "flink" {
  name              = "/aws/kinesisanalytics/flink-application"
  retention_in_days = 7
}

# CloudWatch Log Stream for Flink application
resource "aws_cloudwatch_log_stream" "flink" {
  name           = "flink-application-logs"
  log_group_name = aws_cloudwatch_log_group.flink.name
}

# Kinesis Data Streams - Input stream
resource "aws_kinesis_stream" "input" {
  name             = "flink-input-stream"
  shard_count      = 2
  retention_period = 24

  stream_mode_details {
    stream_mode = "PROVISIONED"
  }
}

# Kinesis Data Streams - Output stream
resource "aws_kinesis_stream" "output" {
  name             = "flink-output-stream"
  shard_count      = 2
  retention_period = 24

  stream_mode_details {
    stream_mode = "PROVISIONED"
  }
}

# Kinesis Analytics V2 Application - Apache Flink
resource "aws_kinesisanalyticsv2_application" "flink" {
  name                   = "flink-application"
  runtime_environment    = "FLINK-1_18"
  service_execution_role = aws_iam_role.kinesis_analytics.arn

  application_configuration {
    application_code_configuration {
      code_content {
        s3_content_location {
          bucket_arn = aws_s3_bucket.flink_code.arn
          file_key   = "flink-application.jar"
        }
      }
      code_content_type = "ZIPFILE"
    }

    flink_application_configuration {
      checkpoint_configuration {
        configuration_type = "DEFAULT"
      }

      monitoring_configuration {
        configuration_type = "CUSTOM"
        log_level          = "INFO"
        metrics_level      = "APPLICATION"
      }

      parallelism_configuration {
        auto_scaling_enabled = true
        configuration_type   = "CUSTOM"
        parallelism          = 2
        parallelism_per_kpu  = 1
      }
    }

    environment_properties {
      property_group {
        property_group_id = "InputStreamProperties"

        property_map = {
          "INPUT_STREAM_NAME" = aws_kinesis_stream.input.name
          "AWS_REGION"        = "us-east-1"
        }
      }

      property_group {
        property_group_id = "OutputStreamProperties"

        property_map = {
          "OUTPUT_STREAM_NAME" = aws_kinesis_stream.output.name
          "AWS_REGION"         = "us-east-1"
        }
      }
    }
  }

  cloudwatch_logging_options {
    log_stream_arn = aws_cloudwatch_log_stream.flink.arn
  }

  tags = {
    Environment = "dev"
    Application = "flink"
  }
}

# VPC Configuration (optional - for VPC-based applications)
resource "aws_vpc" "main" {
  cidr_block           = "10.0.0.0/16"
  enable_dns_hostnames = true
  enable_dns_support   = true

  tags = {
    Name = "flink-vpc"
  }
}

