  bucket = aws_s3_bucket.firehose_bucket.id
  versioning_configuration {
    status = "Enabled"
  }
}

resource "aws_iam_role" "firehose_role" {
  name = "firehose_redshift_role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "firehose.amazonaws.com"
        }
      }
    ]
  })
}

resource "aws_iam_role_policy" "firehose_policy" {
  name = "firehose_redshift_policy"
  role = aws_iam_role.firehose_role.id

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect = "Allow"
        Action = [
          "s3:AbortMultipartUpload",
          "s3:GetBucketLocation",
          "s3:GetObject",
          "s3:ListBucket",
          "s3:ListBucketMultipartUploads",
          "s3:PutObject"
        ]
        Resource = [
          aws_s3_bucket.firehose_bucket.arn,
          "${aws_s3_bucket.firehose_bucket.arn}/*"
        ]
      },
      {
        Effect = "Allow"
        Action = [
          "redshift:DescribeClusters",
          "redshift:DescribeClusterSubnetGroups"
        ]
        Resource = "*"
      },
      {
        Effect = "Allow"
        Action = [
          "redshift:GetClusterCredentials"
        ]
        Resource = aws_redshift_cluster.example.arn
      }
    ]
  })
}

resource "aws_kinesis_firehose_delivery_stream" "redshift_stream" {
  name        = "terraform-kinesis-firehose-redshift-stream"
  destination = "redshift"

  redshift_configuration {
    role_arn        = aws_iam_role.firehose_role.arn
    cluster_jdbcurl = "jdbc:redshift://${aws_redshift_cluster.example.endpoint}/${aws_redshift_cluster.example.database_name}"

    username = aws_redshift_cluster.example.master_username
    password = aws_redshift_cluster.example.master_password

    data_table_name    = "my_table"
    data_table_columns = "column1, column2, column3"
    copy_options       = "delimiter '|'" # optional

    s3_configuration {
      role_arn   = aws_iam_role.firehose_role.arn
      bucket_arn = aws_s3_bucket.firehose_bucket.arn

      prefix             = "redshift/"
      error_output_prefix = "errors/"
      buffer_size        = 10
      buffer_interval    = 400
      compression_format = "GZIP"
    }

    processing_configuration {
      enabled = false
    }

    cloudwatch_logging_options {
      enabled         = true
      log_group_name  = "/aws/kinesisfirehose/terraform-kinesis-firehose-redshift-stream"
      log_stream_name = "DestinationDelivery"
    }

    retry_duration = 300
  }

  depends_on = [aws_iam_role_policy.firehose_policy]
}
