data "aws_caller_identity" "current" {}
data "aws_region" "current" {}

# IAM Role for Firehose
resource "aws_iam_role" "firehose" {
  name = "firehose_opensearch_role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "firehose.amazonaws.com"
        }
      }
    ]
  })
}

# IAM Policy for Firehose to access OpenSearch Serverless
resource "aws_iam_role_policy" "firehose_opensearch" {
  name = "firehose_opensearch_policy"
  role = aws_iam_role.firehose.id

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect = "Allow"
        Action = [
          "aoss:APIAccessAll"
        ]
        Resource = "*"
      },
      {
        Effect = "Allow"
        Action = [
          "s3:AbortMultipartUpload",
          "s3:GetBucketLocation",
          "s3:GetObject",
          "s3:ListBucket",
          "s3:ListBucketMultipartUploads",
          "s3:PutObject"
        ]
        Resource = [
          aws_s3_bucket.firehose_backup.arn,
          "${aws_s3_bucket.firehose_backup.arn}/*"
        ]
      },
      {
        Effect = "Allow"
        Action = [
          "logs:PutLogEvents"
        ]
        Resource = [
          aws_cloudwatch_log_stream.firehose.arn
        ]
      }
    ]
  })
}

# S3 Bucket for backup/failed records
resource "aws_s3_bucket" "firehose_backup" {
  bucket = "firehose-backup-${data.aws_caller_identity.current.account_id}-${data.aws_region.current.name}"
}

resource "aws_s3_bucket_versioning" "firehose_backup" {
  bucket = aws_s3_bucket.firehose_backup.id
  versioning_configuration {
    status = "Enabled"
  }
}

# CloudWatch Log Group for Firehose
resource "aws_cloudwatch_log_group" "firehose" {
  name              = "/aws/kinesisfirehose/opensearch-delivery-stream"
  retention_in_days = 7
}

resource "aws_cloudwatch_log_stream" "firehose" {
  name           = "DestinationDelivery"
  log_group_name = aws_cloudwatch_log_group.firehose.name
}

# OpenSearch Serverless Collection
resource "aws_opensearchserverless_collection" "firehose_destination" {
  name = "firehose-collection"

  type = "SEARCH"

  depends_on = [aws_opensearchserverless_security_policy.encryption]
}

# Encryption policy for OpenSearch Serverless
resource "aws_opensearchserverless_security_policy" "encryption" {
  name = "firehose-encryption-policy"
  type = "encryption"

  policy = jsonencode({
    Rules = [
      {
        ResourceType = "collection"
        Resource = [
          "collection/firehose-collection"
        ]
      }
    ],
    AWSOwnedKey = true
  })
}

# Network policy for OpenSearch Serverless
resource "aws_opensearchserverless_security_policy" "network" {
  name = "firehose-network-policy"
  type = "network"

  policy = jsonencode([
    {
      Rules = [
        {
          ResourceType = "collection"
          Resource = [
            "collection/firehose-collection"
          ]
        },
        {
          ResourceType = "dashboard"
          Resource = [
            "collection/firehose-collection"
          ]
        }
      ],
      AllowFromPublic = true
    }
  ])

  depends_on = [aws_opensearchserverless_collection.firehose_destination]
}

# Data access policy for OpenSearch Serverless
resource "aws_opensearchserverless_access_policy" "firehose_access" {
  name = "firehose-access-policy"
  type = "data"

  policy = jsonencode([
    {
      Rules = [
        {
          ResourceType = "index"
          Resource = [
            "index/firehose-collection/*"
          ]
          Permission = [
            "aoss:CreateIndex",
            "aoss:UpdateIndex",
            "aoss:DescribeIndex",
            "aoss:WriteDocument"
          ]
        },
        {
          ResourceType = "collection"
          Resource = [
            "collection/firehose-collection"
          ]
          Permission = [
            "aoss:DescribeCollectionItems"
          ]
        }
      ],
      Principal = [
        aws_iam_role.firehose.arn
      ]
    }
  ])

  depends_on = [aws_opensearchserverless_collection.firehose_destination]
}

# Kinesis Firehose Delivery Stream
resource "aws_kinesis_firehose_delivery_stream" "opensearch_serverless" {
  name        = "opensearch-serverless-delivery-stream"
  destination = "opensearchserverless"

  opensearchserverless_configuration {
    collection_endpoint = aws_opensearchserverless_collection.firehose_destination.collection_endpoint
    index_name          = "firehose-index"
    s3_backup_mode      = "FailedDocumentsOnly"

    s3_configuration {
      role_arn   = aws_iam_role.firehose.arn
      bucket_arn = aws_s3_bucket.firehose_backup.arn
      prefix     = "failed/"
    }

    cloudwatch_logging_options {
      enabled         = true
      log_group_name  = aws_cloudwatch_log_group.firehose.name
      log_stream_name = aws_cloudwatch_log_stream.firehose.name
    }

    buffering_interval = 60
    buffering_size     = 5
    retry_duration     = 300
  }

  depends_on = [
    aws_opensearchserverless_access_policy.firehose_access,
    aws_opensearchserverless_security_policy.network
  ]
}

