data "aws_caller_identity" "current" {}

data "aws_region" "current" {}

# VPC Configuration
resource "aws_vpc" "main" {
  cidr_block           = "10.0.0.0/16"
  enable_dns_hostnames = true
  enable_dns_support   = true

  tags = {
    Name = "firehose-opensearch-vpc"
  }
}

resource "aws_subnet" "private" {
  count             = 2
  vpc_id            = aws_vpc.main.id
  cidr_block        = "10.0.${count.index + 1}.0/24"
  availability_zone = data.aws_availability_zones.available.names[count.index]

  tags = {
    Name = "firehose-private-subnet-${count.index + 1}"
  }
}

data "aws_availability_zones" "available" {
  state = "available"
}

resource "aws_security_group" "opensearch" {
  name_prefix = "opensearch-sg-"
  vpc_id      = aws_vpc.main.id

  ingress {
    from_port   = 443
    to_port     = 443
    protocol    = "tcp"
    cidr_blocks = [aws_vpc.main.cidr_block]
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }

  tags = {
    Name = "opensearch-security-group"
  }

  lifecycle {
    create_before_destroy = true
  }
}

# IAM Role for Firehose
resource "aws_iam_role" "firehose" {
  name = "firehose_opensearch_role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "firehose.amazonaws.com"
        }
      }
    ]
  })
}

resource "aws_iam_role_policy" "firehose" {
  name = "firehose_opensearch_policy"
  role = aws_iam_role.firehose.id

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect = "Allow"
        Action = [
          "es:DescribeDomain",
          "es:DescribeDomains",
          "es:DescribeDomainConfig",
          "es:ESHttpPost",
          "es:ESHttpPut"
        ]
        Resource = [
          aws_opensearch_domain.main.arn,
          "${aws_opensearch_domain.main.arn}/*"
        ]
      },
      {
        Effect = "Allow"
        Action = [
          "es:ESHttpGet"
        ]
        Resource = [
          "${aws_opensearch_domain.main.arn}/_all/_settings",
          "${aws_opensearch_domain.main.arn}/_cluster/stats",
          "${aws_opensearch_domain.main.arn}/index-name-*/_mapping/type-name",
          "${aws_opensearch_domain.main.arn}/roletest*/_mapping/roletest",
          "${aws_opensearch_domain.main.arn}/_nodes",
          "${aws_opensearch_domain.main.arn}/_nodes/stats",
          "${aws_opensearch_domain.main.arn}/_nodes/*/stats",
          "${aws_opensearch_domain.main.arn}/_stats",
          "${aws_opensearch_domain.main.arn}/index-name-*/_stats",
          "${aws_opensearch_domain.main.arn}/roletest*/_stats"
        ]
      },
      {
        Effect = "Allow"
        Action = [
          "logs:PutLogEvents"
        ]
        Resource = [
          aws_cloudwatch_log_stream.firehose.arn
        ]
      },
      {
        Effect = "Allow"
        Action = [
          "kinesis:DescribeStream",
          "kinesis:GetShardIterator",
          "kinesis:GetRecords",
          "kinesis:ListShards"
        ]
        Resource = "arn:aws:kinesis:${data.aws_region.current.name}:${data.aws_caller_identity.current.account_id}:stream/*"
      },
      {
        Effect = "Allow"
        Action = [
          "ec2:DescribeVpcs",
          "ec2:DescribeVpcAttribute",
          "ec2:DescribeSubnets",
          "ec2:DescribeSecurityGroups",
          "ec2:DescribeNetworkInterfaces",
          "ec2:CreateNetworkInterface",
          "ec2:CreateNetworkInterfacePermission",
          "ec2:DeleteNetworkInterface"
        ]
        Resource = "*"
      }
    ]
  })
}

# S3 Bucket for Firehose Backup
resource "aws_s3_bucket" "firehose_backup" {
  bucket_prefix = "firehose-backup-"
}

resource "aws_s3_bucket_versioning" "firehose_backup" {
  bucket = aws_s3_bucket.firehose_backup.id
  versioning_configuration {
    status = "Enabled"
  }
}

# CloudWatch Log Group for Firehose
resource "aws_cloudwatch_log_group" "firehose" {
  name              = "/aws/kinesisfirehose/opensearch-delivery-stream"
  retention_in_days = 7
}

resource "aws_cloudwatch_log_stream" "firehose" {
  name           = "OpenSearchDelivery"
  log_group_name = aws_cloudwatch_log_group.firehose.name
}

# OpenSearch Domain
resource "aws_opensearch_domain" "main" {
  domain_name    = "firehose-destination"
  engine_version = "OpenSearch_2.5"

  cluster_config {
    instance_type  = "t3.small.search"
    instance_count = 2
  }

  vpc_options {
    subnet_ids         = aws_subnet.private[*].id
    security_group_ids = [aws_security_group.opensearch.id]
  }

  ebs_options {
    ebs_enabled = true
    volume_size = 10
  }

  encrypt_at_rest {
    enabled = true
  }

  node_to_node_encryption {
    enabled = true
  }

  domain_endpoint_options {
    enforce_https       = true
    tls_security_policy = "Policy-Min-TLS-1-2-2019-07"
  }

  access_policies = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect = "Allow"
        Principal = {
          AWS = "*"
        }
        Action = "es:*"
        Resource = "arn:aws:es:${data.aws_region.current.name}:${data.aws_caller_identity.current.account_id}:domain/firehose-destination/*"
        Condition = {
          IpAddress = {
            "aws:SourceIp" = [aws_vpc.main.cidr_block]
          }
        }
      }
    ]
  })

  tags = {
    Name = "firehose-destination"
  }
}

# VPC Endpoint for Firehose
resource "aws_vpc_endpoint" "firehose" {
  vpc_id              = aws_vpc.main.id
  service_name        = "com.amazonaws.${data.aws_region.current.name}.kinesis-firehose"
  vpc_endpoint_type   = "Interface"
  subnet_ids          = aws_subnet.private[*].id
  security_group_ids  = [aws_security_group.opensearch.id]
  private_dns_enabled = true
}

# Kinesis Firehose Delivery Stream
resource "aws_kinesis_firehose_delivery_stream" "main" {
  name        = "opensearch-delivery-stream"
  destination = "opensearch"

  opensearch_configuration {
    domain_arn = aws_opensearch_domain.main.arn
    role_arn   = aws_iam_role.firehose.arn

    index_name = "firehose-index"
    type_name  = "_doc"

    s3_configuration {
      role_arn   = aws_iam_role.firehose.arn
      bucket_arn = aws_s3_bucket.firehose_backup.arn

      buffering_size     = 10
      buffering_interval = 400
      compression_format = "GZIP"
    }

    cloudwatch_logging_options {
      enabled         = true
      log_group_name  = aws_cloudwatch_log_group.firehose.name
      log_stream_name = aws_cloudwatch_log_stream.firehose.name
    }

    vpc_configuration {
      subnet_ids         = aws_subnet.private[*].id
      security_group_ids = [aws_security_group.opensearch.id]
      role_arn           = aws_iam_role.firehose.arn
    }

    processing_configuration {
      enabled = false
    }
  }

  depends_on = [aws_opensearch_domain.main, aws_vpc_endpoint.firehose]
}

# Outputs
output "firehose_delivery_stream_name" {
  value = aws_kinesis_firehose_delivery_stream.main.name
}

output "opensearch_domain_endpoint" {
  value = aws_opensearch_domain.main.endpoint
}

output "s3_backup_bucket" {
  value = aws_s3_bucket.firehose_backup.id
}

output "vpc_id" {
  value = aws_vpc.main.id
}
```

