  region = "us-east-1"
}

# IAM Role for Kinesis Analytics Application
resource "aws_iam_role" "kinesis_analytics" {
  name = "kinesis-analytics-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "kinesisanalytics.amazonaws.com"
        }
      }
    ]
  })
}

# IAM Policy for Kinesis Analytics
resource "aws_iam_role_policy" "kinesis_analytics" {
  name = "kinesis-analytics-policy"
  role = aws_iam_role.kinesis_analytics.id

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect = "Allow"
        Action = [
          "kinesis:*",
          "firehose:*"
        ]
        Resource = "*"
      },
      {
        Effect = "Allow"
        Action = [
          "logs:PutLogEvents",
          "logs:CreateLogStream",
          "logs:CreateLogGroup",
          "logs:DescribeLogGroups",
          "logs:DescribeLogStreams"
        ]
        Resource = "*"
      }
    ]
  })
}

# CloudWatch Log Group for Kinesis Analytics
resource "aws_cloudwatch_log_group" "kinesis_analytics" {
  name              = "/aws/kinesisanalytics/sql-application"
  retention_in_days = 7
}

# CloudWatch Log Stream for Kinesis Analytics
resource "aws_cloudwatch_log_stream" "kinesis_analytics" {
  name           = "sql-application-log-stream"
  log_group_name = aws_cloudwatch_log_group.kinesis_analytics.name
}

# Input Kinesis Stream
resource "aws_kinesis_stream" "input" {
  name             = "sql-application-input-stream"
  shard_count      = 1
  retention_period = 24

  stream_mode_details {
    stream_mode = "PROVISIONED"
  }
}

# Output Kinesis Stream
resource "aws_kinesis_stream" "output" {
  name             = "sql-application-output-stream"
  shard_count      = 1
  retention_period = 24

  stream_mode_details {
    stream_mode = "PROVISIONED"
  }
}

# Kinesis Analytics V2 Application - SQL Application
resource "aws_kinesisanalyticsv2_application" "sql_application" {
  name                   = "sql-analytics-application"
  runtime_environment    = "SQL-1_0"
  service_execution_role = aws_iam_role.kinesis_analytics.arn

  application_configuration {
    sql_application_configuration {
      input {
        name_prefix = "SOURCE_SQL_STREAM"

        kinesis_streams_input {
          resource_arn = aws_kinesis_stream.input.arn
        }

        input_schema {
          record_format {
            record_format_type = "JSON"
            mapping_parameters {
              json_mapping_parameters {
                record_row_path = "$"
              }
            }
          }

          record_encoding = "UTF-8"

          record_columns {
            name     = "event_time"
            sql_type = "TIMESTAMP"
            mapping  = "$.event_time"
          }
          record_columns {
            name     = "sensor_id"
            sql_type = "INTEGER"
            mapping  = "$.sensor_id"
          }
          record_columns {
            name     = "temperature"
            sql_type = "DOUBLE"
            mapping  = "$.temperature"
          }
        }
      }

      output {
        name = "DESTINATION_SQL_STREAM"

        kinesis_streams_output {
          resource_arn = aws_kinesis_stream.output.arn
        }

        destination_schema {
          record_format_type = "JSON"
        }
      }

      reference_data_source {
        table_name = "REFERENCE_DATA"

        s3_reference_data_source {
          bucket_arn = aws_s3_bucket.reference_data.arn
          file_key   = "reference-data.json"
        }

        reference_schema {
          record_format {
            record_format_type = "JSON"
            mapping_parameters {
              json_mapping_parameters {
                record_row_path = "$"
              }
            }
          }

          record_encoding = "UTF-8"

          record_columns {
            name     = "sensor_id"
            sql_type = "INTEGER"
            mapping  = "$.sensor_id"
          }
          record_columns {
            name     = "sensor_location"
            sql_type = "VARCHAR(64)"
            mapping  = "$.sensor_location"
          }
        }
      }
    }
  }

  cloudwatch_logging_options {
    log_stream_arn = aws_cloudwatch_log_stream.kinesis_analytics.arn
  }

  tags = {
    Environment = "Production"
    Application = "SQLAnalytics"
  }

  depends_on = [
    aws_iam_role_policy.kinesis_analytics,
    aws_cloudwatch_log_stream.kinesis_analytics
  ]
}

# S3 Bucket for Reference Data
resource "aws_s3_bucket" "reference_data" {
  bucket = "kinesis-analytics-reference-data-${random_id.bucket_suffix.hex}"
}

resource "random_id" "bucket_suffix" {
  byte_length = 4
}

# S3 Bucket Versioning
resource "aws_s3_bucket_versioning" "reference_data" {
  bucket = aws_s3_bucket.reference_data.id
  versioning_configuration {
    status = "Enabled"
  }
}

# S3 Object for Reference Data
resource "aws_s3_object" "reference_data" {
  bucket  = aws_s3_bucket.reference_data.id
  key     = "reference-data.json"
  content = jsonencode([
    { "sensor_id" = 1, "sensor_location" = "Building A - Floor 1" },
    { "sensor_id" = 2, "sensor_location" = "Building A - Floor 2" },
    { "sensor_id" = 3, "sensor_location" = "Building B - Floor 1" }
  ])

  content_type = "application/json"
}

# Outputs
output "application_name" {
  description = "Name of the Kinesis Analytics SQL Application"
  value       = aws_kinesisanalyticsv2_application.sql_application.name
}

output "application_arn" {
  description = "ARN of the Kinesis Analytics SQL Application"
  value       = aws_kinesisanalyticsv2_application.sql_application.arn
}

output "input_stream_name" {
  description = "Name of the input Kinesis stream"
  value       = aws_kinesis_stream.input.name
}

output "output_stream_name" {
  description = "Name of the output Kinesis stream"
  value       = aws_kinesis_stream.output.name
}

