          ]
        }
      }
    }
  }

  custom_document_enrichment_configuration {
    inline_configurations {
      condition {
        condition_document_attribute_key = "_source_uri"
        operator                         = "Equals"
        condition_on_value {
          string_value = "https://example.com"
        }
      }
      target {
        target_document_attribute_key = "category"
        target_value {
          string_value = "web"
        }
      }
      document_content_deletion = false
    }
  }

  description = "Example Kendra data source with proxy configuration"
  role_arn    = aws_iam_role.kendra_data_source.arn

  schedule = "cron(0 12 * * ? *)"

  tags = {
    Environment = "production"
    Project     = "kendra-search"
  }
}

