provider "aws" {
  region = "us-east-1"
}

provider "aws" {
  alias  = "eu-central-1"
  region = "eu-central-1"
}

# Route 53 Health Check for us-east-1 endpoint
resource "aws_route53_health_check" "us_east_1" {
  fqdn              = "us-east-1.example.com"
  port              = 443
  type              = "HTTPS"
  resource_path     = "/health"
  failure_threshold = 3
  request_interval  = 30

  regions = ["us-east-1", "us-west-2", "eu-west-1"]

  tags = {
    Name = "us-east-1-health-check"
  }
}

# Route 53 Health Check for eu-central-1 endpoint
resource "aws_route53_health_check" "eu_central_1" {
  fqdn              = "eu-central-1.example.com"
  port              = 443
  type              = "HTTPS"
  resource_path     = "/health"
  failure_threshold = 3
  request_interval  = 30

  regions = ["us-east-1", "us-west-2", "eu-west-1"]

  tags = {
    Name = "eu-central-1-health-check"
  }
}

# Route 53 Zone
resource "aws_route53_zone" "primary" {
  name = "primary.example.com"

  tags = {
    Name = "primary"
  }
}

# Route 53 Record with Latency-based Routing Policy
resource "aws_route53_record" "us_east_1_latency" {
  zone_id = aws_route53_zone.primary.zone_id
  name    = "app.primary.example.com"
  type    = "A"

