      kubectl patch deployment coredns \n        -n kube-system \n        --type json \n        -p='[{"op": "remove", "path": "/spec/template/metadata/annotations/eks.amazonaws.com~1compute-type"}]' \n        --server=${data.aws_eks_cluster.cluster.endpoint} \n        --certificate-authority=/tmp/ca.crt \n        --token=${data.aws_eks_cluster_auth.cluster.token}
    EOT

    environment = {
      KUBECONFIG = "/dev/null"
    }
  }

  provisioner "local-exec" {
    command = <<-EOT
      echo "${data.aws_eks_cluster.cluster.certificate_authority[0].data}" | base64 -d > /tmp/ca.crt
    EOT
  }

  depends_on = [aws_eks_fargate_profile.kube_system]
}
```

