extracted_code:
# Data sources for EKS service and caller identity
data "aws_caller_identity" "current" {}

data "aws_partition" "current" {}

# IAM Role for EKS Cluster
resource "aws_iam_role" "demo_eks" {
  name = "demo_eks"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "eks.amazonaws.com"
        }
      }
    ]
  })

  tags = {
    Name = "demo_eks"
  }
}

# Attach AmazonEKSClusterPolicy to the IAM role
resource "aws_iam_role_policy_attachment" "demo_eks_cluster_policy" {
  policy_arn = "arn:aws:iam::aws:policy/AmazonEKSClusterPolicy"
  role       = aws_iam_role.demo_eks.name
}

# Attach AmazonEKSVPCResourceController to the IAM role
resource "aws_iam_role_policy_attachment" "demo_eks_vpc_resource_controller" {
  policy_arn = "arn:aws:iam::aws:policy/AmazonEKSVPCResourceController"
  role       = aws_iam_role.demo_eks.name
}

# VPC Configuration
data "aws_availability_zones" "available" {
  state = "available"
}

resource "aws_vpc" "demo_eks" {
  cidr_block           = "10.0.0.0/16"
  enable_dns_hostnames = true
  enable_dns_support   = true

  tags = {
    Name = "demo_eks"
    "kubernetes.io/cluster/demo_eks" = "shared"
  }
}

resource "aws_internet_gateway" "demo_eks" {
  vpc_id = aws_vpc.demo_eks.id

  tags = {
    Name = "demo_eks"
  }
}

resource "aws_subnet" "demo_eks_private" {
  count = 3

  vpc_id            = aws_vpc.demo_eks.id
  cidr_block        = cidrsubnet(aws_vpc.demo_eks.cidr_block, 8, count.index)
  availability_zone = data.aws_availability_zones.available.names[count.index]

  tags = {
    Name = "demo_eks-private-${count.index + 1}"
    "kubernetes.io/cluster/demo_eks" = "shared"
    "kubernetes.io/role/internal-elb" = "1"
  }
}

resource "aws_subnet" "demo_eks_public" {
  count = 3

  vpc_id                  = aws_vpc.demo_eks.id
  cidr_block              = cidrsubnet(aws_vpc.demo_eks.cidr_block, 8, count.index + 3)
  availability_zone       = data.aws_availability_zones.available.names[count.index]
  map_public_ip_on_launch = true

  tags = {
    Name = "demo_eks-public-${count.index + 1}"
    "kubernetes.io/cluster/demo_eks" = "shared"
    "kubernetes.io/role/elb" = "1"
  }
}

resource "aws_eip" "demo_eks_nat" {
  count  = 3
  domain = "vpc"

  tags = {
    Name = "demo_eks-nat-${count.index + 1}"
  }
}

resource "aws_nat_gateway" "demo_eks" {
  count = 3

  allocation_id = aws_eip.demo_eks_nat[count.index].id
  subnet_id     = aws_subnet.demo_eks_public[count.index].id

  tags = {
    Name = "demo_eks-nat-${count.index + 1}"
  }

  depends_on = [aws_internet_gateway.demo_eks]
}

resource "aws_route_table" "demo_eks_public" {
  vpc_id = aws_vpc.demo_eks.id

  route {
    cidr_block = "0.0.0.0/0"
    gateway_id = aws_internet_gateway.demo_eks.id
  }

  tags = {
    Name = "demo_eks-public"
  }
}

resource "aws_route_table" "demo_eks_private" {
  count = 3

  vpc_id = aws_vpc.demo_eks.id

  route {
    cidr_block     = "0.0.0.0/0"
    nat_gateway_id = aws_nat_gateway.demo_eks[count.index].id
  }

  tags = {
    Name = "demo_eks-private-${count.index + 1}"
  }
}

resource "aws_route_table_association" "demo_eks_public" {
  count = 3

  subnet_id      = aws_subnet.demo_eks_public[count.index].id
  route_table_id = aws_route_table.demo_eks_public.id
}

resource "aws_route_table_association" "demo_eks_private" {
  count = 3

  subnet_id      = aws_subnet.demo_eks_private[count.index].id
  route_table_id = aws_route_table.demo_eks_private[count.index].id
}

# Security Group for EKS Cluster
resource "aws_security_group" "demo_eks_cluster" {
  name        = "demo_eks_cluster"
  description = "Security group for EKS cluster"
  vpc_id      = aws_vpc.demo_eks.id

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }

  tags = {
    Name = "demo_eks_cluster"
  }
}

# EKS Cluster
resource "aws_eks_cluster" "demo_eks" {
  name     = "demo_eks"
  role_arn = aws_iam_role.demo_eks.arn
  version  = "1.29"

  vpc_config {
    subnet_ids              = concat(aws_subnet.demo_eks_private[*].id, aws_subnet.demo_eks_public[*].id)
    security_group_ids      = [aws_security_group.demo_eks_cluster.id]
    endpoint_private_access = true
    endpoint_public_access  = true
    public_access_cidrs     = ["0.0.0.0/0"]
  }

  enabled_cluster_log_types = ["api", "audit", "authenticator", "controllerManager", "scheduler"]

  depends_on = [
    aws_iam_role_policy_attachment.demo_eks_cluster_policy,
    aws_iam_role_policy_attachment.demo_eks_vpc_resource_controller,
    aws_nat_gateway.demo_eks,
  ]

  tags = {
    Name = "demo_eks"
  }
}

# KMS Key for EKS encryption (optional but recommended)
resource "aws_kms_key" "demo_eks" {
  description             = "EKS Secret Encryption Key"
  deletion_window_in_days = 7
  enable_key_rotation     = true

  tags = {
    Name = "demo_eks"
  }
}

resource "aws_kms_alias" "demo_eks" {
  name          = "alias/demo_eks"
  target_key_id = aws_kms_key.demo_eks.key_id
}

# Outputs
output "cluster_endpoint" {
  description = "Endpoint for EKS control plane"
  value       = aws_eks_cluster.demo_eks.endpoint
}

output "cluster_name" {
  description = "EKS cluster name"
  value       = aws_eks_cluster.demo_eks.name
}

output "cluster_arn" {
  description = "EKS cluster ARN"
  value       = aws_eks_cluster.demo_eks.arn
}

output "cluster_certificate_authority_data" {
  description = "Base64 encoded certificate data required to communicate with the cluster"
  value       = aws_eks_cluster.demo_eks.certificate_authority[0].data
}

output "cluster_security_group_id" {
  description = "Security group ID attached to the EKS cluster"
  value       = aws_security_group.demo_eks_cluster.id
}

output "cluster_iam_role_name" {
  description = "IAM role name associated with EKS cluster"
  value       = aws_iam_role.demo_eks.name
}

output "cluster_iam_role_arn" {
  description = "IAM role ARN associated with EKS cluster"
  value       = aws_iam_role.demo_eks.arn
}

output "vpc_id" {
  description = "VPC ID"
  value       = aws_vpc.demo_eks.id
}

output "private_subnet_ids" {
  description = "Private subnet IDs"
  value       = aws_subnet.demo_eks_private[*].id
}

output "public_subnet_ids" {
