  ignore_public_acls      = true
  block_public_acls       = true
  block_public_policy     = false
  restrict_public_buckets = true
}


resource "aws_s3_bucket_policy" "put_object" {
  bucket = aws_s3_bucket.cg-data-from-web.id
  policy = jsonencode({
    Version = "2012-10-17"
