data "aws_iam_policy_document" "sns_topic_policy" {
  statement {
    sid    = "AllowS3ToPublishToSNS"
    effect = "Allow"

    principals {
      type        = "Service"
      identifiers = ["s3.amazonaws.com"]
    }

    actions   = ["SNS:Publish"]
    resources = ["arn:aws:sns:*:*:${local.topic_name}"]

    condition {
      test     = "ArnLike"
      variable = "aws:SourceArn"
      values   = ["arn:aws:s3:::${local.bucket_name}"]
    }
  }
}

resource "aws_sns_topic" "s3_event_notifications" {
  name   = local.topic_name
  policy = data.aws_iam_policy_document.sns_topic_policy.json
}

resource "aws_s3_bucket" "bucket" {
  bucket = local.bucket_name
}

resource "aws_s3_bucket_notification" "bucket_notification" {
  bucket = aws_s3_bucket.bucket.id

  topic {
    topic_arn     = aws_sns_topic.s3_event_notifications.arn
    events        = ["s3:ObjectCreated:*"]
    filter_suffix = ".log"
  }

  depends_on = [aws_sns_topic_policy.sns_topic_policy_attachment]
}

# Create an explicit topic policy attachment to ensure proper ordering
resource "aws_sns_topic_policy" "sns_topic_policy_attachment" {
  arn    = aws_sns_topic.s3_event_notifications.arn
  policy = data.aws_iam_policy_document.sns_topic_policy.json
}

