# VPC and Subnet configuration for ElastiCache
resource "aws_vpc" "main" {
  cidr_block           = "10.0.0.0/16"
  enable_dns_hostnames = true
  enable_dns_support   = true

  tags = {
    Name = "elasticache-vpc"
  }
}

resource "aws_subnet" "private_1" {
  vpc_id            = aws_vpc.main.id
  cidr_block        = "10.0.1.0/24"
  availability_zone = "us-east-1a"

  tags = {
    Name = "elasticache-subnet-1"
  }
}

resource "aws_subnet" "private_2" {
  vpc_id            = aws_vpc.main.id
  cidr_block        = "10.0.2.0/24"
  availability_zone = "us-east-1b"

  tags = {
    Name = "elasticache-subnet-2"
  }
}

# Subnet group for ElastiCache
resource "aws_elasticache_subnet_group" "memcached" {
  name       = "memcached-subnet-group"
  subnet_ids = [aws_subnet.private_1.id, aws_subnet.private_2.id]

  tags = {
    Name = "Memcached subnet group"
  }
}

# Security group for Memcached
resource "aws_security_group" "memcached" {
  name        = "memcached-security-group"
  description = "Security group for Memcached cluster"
  vpc_id      = aws_vpc.main.id

  ingress {
    description = "Memcached port"
    from_port   = 11211
    to_port     = 11211
    protocol    = "tcp"
    cidr_blocks = [aws_vpc.main.cidr_block]
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }

  tags = {
    Name = "memcached-sg"
  }
}

# Parameter group for Memcached
resource "aws_elasticache_parameter_group" "memcached" {
  family = "memcached1.6"
  name   = "memcached-params"

  parameter {
    name  = "max_item_size"
    value = "10485760"
  }

  tags = {
    Name = "Memcached parameter group"
  }
}

# Memcached Cluster
resource "aws_elasticache_cluster" "memcached" {
  cluster_id           = "memcached-cluster"
  engine               = "memcached"
  engine_version       = "1.6.17"
  node_type            = "cache.t3.micro"
  num_cache_nodes      = 2
  parameter_group_name = aws_elasticache_parameter_group.memcached.name
  port                 = 11211
  subnet_group_name    = aws_elasticache_subnet_group.memcached.name
  security_group_ids   = [aws_security_group.memcached.id]
  az_mode              = "cross-az"

  tags = {
    Name        = "Memcached Cluster"
    Environment = "production"
  }
}

# Outputs
output "memcached_cluster_address" {
  description = "The DNS name of the Memcached cluster"
  value       = aws_elasticache_cluster.memcached.cluster_address
}

output "memcached_configuration_endpoint" {
  description = "The configuration endpoint for the Memcached cluster"
  value       = aws_elasticache_cluster.memcached.configuration_endpoint
}

output "memcached_port" {
  description = "The port number of the Memcached cluster"
  value       = aws_elasticache_cluster.memcached.port
}

