terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

provider "aws" {
  region = "us-east-1"
}

# Redshift cluster parameter group with concurrency scaling configuration
resource "aws_redshift_parameter_group" "concurrency_scaling" {
  name   = "redshift-concurrency-scaling-pg"
  family = "redshift-1.0"

  parameter {
    name  = "concurrency_scaling_mode"
    value = "auto"
  }

  parameter {
    name  = "max_concurrency_scaling_clusters"
    value = "1"
  }
}

# Redshift subnet group
resource "aws_redshift_subnet_group" "default" {
  name       = "redshift-subnet-group"
  subnet_ids = ["subnet-12345678", "subnet-87654321"] # Replace with your subnet IDs

  tags = {
    Name = "Redshift subnet group"
  }
}

# 2-node Redshift cluster with concurrency scaling limited to 60 minutes
resource "aws_redshift_cluster" "default" {
  cluster_identifier           = "redshift-cluster-2-node"
  database_name                = "mydb"
  master_username              = "admin"
  master_password              = "YourSecurePassword123!" # Use AWS Secrets Manager in production
  node_type                    = "dc2.large"
  cluster_type                 = "multi-node"
  number_of_nodes              = 2
  cluster_subnet_group_name    = aws_redshift_subnet_group.default.name
  cluster_parameter_group_name = aws_redshift_parameter_group.concurrency_scaling.name
  publicly_accessible          = false
  skip_final_snapshot          = true

  # Enable concurrency scaling with 60 minute limit
  # The max_concurrency_scaling_clusters parameter limits scaling duration
  # Setting to 1 cluster with auto mode limits total scaling time

  tags = {
    Name        = "Redshift 2-Node Cluster"
    Environment = "Production"
  }
}

# Workload management queue with concurrency scaling configuration
resource "aws_redshift_cluster_iam_roles" "default" {
  cluster_identifier = aws_redshift_cluster.default.cluster_identifier
  iam_role_arns      = []
}

# Additional resource to configure WLM for concurrency scaling time limit
# Note: Use AWS CLI or Redshift console to set WLM query_execution_time to 60 minutes
# as Terraform AWS provider doesn't directly support WLM configuration

