  database_name             = "dev"
  master_username           = "admin"
  master_password           = "YourStrongPassword123!"
  node_type                 = "dc2.large"
  cluster_type              = "multi-node"
  number_of_nodes           = 2
  cluster_subnet_group_name = aws_redshift_subnet_group.redshift_subnet_group.name
  vpc_security_group_ids    = [aws_security_group.redshift_sg.id]
  iam_roles                 = [aws_iam_role.redshift_role.arn]

  skip_final_snapshot = true

  tags = {
    Name = "redshift-2node-cluster"
  }
}

# Redshift Endpoint Authorization
resource "aws_redshift_endpoint_authorization" "endpoint_auth" {
  cluster_identifier = aws_redshift_cluster.redshift_cluster.cluster_identifier
  account            = "012345678910"
}

