resource "aws_redshift_subnet_group" "redshift_subnet_group" {
  name       = "redshift-subnet-group"
  subnet_ids = [aws_subnet.redshift_subnet_1.id, aws_subnet.redshift_subnet_2.id]

  tags = {
    Name = "redshift-subnet-group"
  }
}

# Security group for RedShift
resource "aws_security_group" "redshift_security_group" {
  name_prefix = "redshift-sg-"
  vpc_id      = aws_vpc.redshift_vpc.id

  ingress {
    from_port   = 5439
    to_port     = 5439
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"]
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }

  tags = {
    Name = "redshift-security-group"
  }
}

# IAM role for RedShift
resource "aws_iam_role" "redshift_role" {
  name = "redshift-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "redshift.amazonaws.com"
        }
      }
    ]
  })
}

# RedShift cluster
resource "aws_redshift_cluster" "redshift_cluster" {
  cluster_identifier  = "redshift-cluster-1"
  database_name       = "dev"
  master_username     = "admin"
  master_password     = "Password1234!" # Change this in production and use secrets manager
  node_type           = "dc2.large"
  cluster_type        = "single-node"
  number_of_nodes     = 1

  vpc_security_group_ids = [aws_security_group.redshift_security_group.id]
  cluster_subnet_group_name = aws_redshift_subnet_group.redshift_subnet_group.name

  iam_roles = [aws_iam_role.redshift_role.arn]

  automated_snapshot_retention_period = 7
  preferred_maintenance_window        = "sun:03:00-sun:04:00"

  skip_final_snapshot = true

  tags = {
    Name = "redshift-cluster-1"
  }
}

# EventBridge rule to trigger snapshot every 12 hours
resource "aws_cloudwatch_event_rule" "redshift_snapshot_schedule" {
  name                = "redshift-snapshot-schedule"
  description         = "Trigger RedShift snapshot every 12 hours"
  schedule_expression = "rate(12 hours)"
}

# EventBridge target to trigger Lambda or directly call RedShift API
# Using Lambda to create snapshot via AWS SDK
resource "aws_cloudwatch_event_target" "redshift_snapshot_target" {
  rule      = aws_cloudwatch_event_rule.redshift_snapshot_schedule.name
  target_id = "RedshiftSnapshotLambda"
  arn       = aws_lambda_function.redshift_snapshot_lambda.arn
}

# IAM role for Lambda
resource "aws_iam_role" "lambda_role" {
  name = "redshift-snapshot-lambda-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "lambda.amazonaws.com"
        }
      }
    ]
  })
}

resource "aws_iam_role_policy" "lambda_policy" {
  name = "redshift-snapshot-lambda-policy"
  role = aws_iam_role.lambda_role.id

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect = "Allow"
        Action = [
          "logs:CreateLogGroup",
          "logs:CreateLogStream",
          "logs:PutLogEvents"
        ]
        Resource = "arn:aws:logs:*:*:*"
      },
      {
        Effect = "Allow"
        Action = [
          "redshift:CreateClusterSnapshot"
        ]
        Resource = "*"
      }
    ]
  })
}

# Lambda function to create RedShift snapshot
resource "aws_lambda_function" "redshift_snapshot_lambda" {
  filename         = data.archive_file.lambda_zip.output_path
  function_name    = "redshift-create-snapshot"
  role             = aws_iam_role.lambda_role.arn
  handler          = "index.handler"
  runtime          = "python3.11"
  timeout          = 60
  source_code_hash = data.archive_file.lambda_zip.output_base64sha256

  environment {
    variables = {
      CLUSTER_IDENTIFIER = aws_redshift_cluster.redshift_cluster.cluster_identifier
    }
  }
}

data "archive_file" "lambda_zip" {
  type        = "zip"
  output_path = "${path.module}/lambda_function.zip"

  source {
    content  = <<-EOF
import boto3
import os
from datetime import datetime

def handler(event, context):
    client = boto3.client('redshift')
    cluster_id = os.environ['CLUSTER_IDENTIFIER']
    snapshot_id = f"{cluster_id}-snapshot-{datetime.now().strftime('%Y%m%d-%H%M%S')}"

    try:
        response = client.create_cluster_snapshot(
            SnapshotIdentifier=snapshot_id,
            ClusterIdentifier=cluster_id,
            Tags=[
                {
                    'Key': 'CreatedBy',
                    'Value': 'ScheduledSnapshot'
                }
            ]
        )
        print(f"Snapshot created: {snapshot_id}")
        return {
            'statusCode': 200,
            'body': f"Snapshot {snapshot_id} creation initiated"
        }
    except Exception as e:
        print(f"Error creating snapshot: {str(e)}")
        raise e
EOF
    filename = "index.py"
  }
}

# Lambda permission for EventBridge
resource "aws_lambda_permission" "allow_eventbridge" {
  statement_id  = "AllowExecutionFromEventBridge"
  action        = "lambda:InvokeFunction"
  function_name = aws_lambda_function.redshift_snapshot_lambda.function_name
  principal     = "events.amazonaws.com"
  source_arn    = aws_cloudwatch_event_rule.redshift_snapshot_schedule.arn
}

