  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect = "Allow"
        Action = [
          "s3:GetObject",
          "s3:ListBucket"
        ]
        Resource = "*"
      }
    ]
  })
}

# Redshift Parameter Group
resource "aws_redshift_parameter_group" "redshift_params" {
  name   = "redshift-params"
  family = "redshift-1.0"

  parameter {
    name  = "enable_user_activity_logging"
    value = "true"
  }

  parameter {
    name  = "require_ssl"
    value = "true"
  }
}

# Highly Available Redshift Cluster
resource "aws_redshift_cluster" "redshift_cluster" {
  cluster_identifier        = "redshift-ha-cluster"
  database_name             = "mydb"
  master_username           = "admin"
  master_password           = "YourSecurePassword123!" # Use AWS Secrets Manager in production
  node_type                 = "ra3.xlplus"             # RA3 nodes for managed storage and better HA
  cluster_type              = "multi-node"
  number_of_nodes           = 2
  publicly_accessible       = false
  vpc_security_group_ids    = [aws_security_group.redshift_sg.id]
  cluster_subnet_group_name = aws_redshift_subnet_group.redshift_subnet_group.name
  iam_roles                 = [aws_iam_role.redshift_role.arn]
  parameter_group_name      = aws_redshift_parameter_group.redshift_params.name

  # High Availability settings
  automated_snapshot_retention_period = 7
  preferred_maintenance_window        = "sun:03:00-sun:04:00"

  # Enhanced VPC routing
  enhanced_vpc_routing = true

  # Encryption
  encrypted = true

  # Logging
  logging {
    enable               = true
    log_destination_type = "cloudwatch"
  }

  tags = {
    Name        = "redshift-ha-cluster"
    Environment = "production"
  }

  skip_final_snapshot = true # Set to false in production
}

# Redshift Cluster Snapshot Schedule for additional backup
resource "aws_redshift_snapshot_schedule" "daily" {
  identifier  = "daily-snapshot"
  description = "Daily snapshot schedule"
  definitions = ["rate(24 hours)"]

  tags = {
    Name = "daily-snapshot"
  }
}

resource "aws_redshift_snapshot_schedule_association" "default" {
  cluster_identifier  = aws_redshift_cluster.redshift_cluster.id
  schedule_identifier = aws_redshift_snapshot_schedule.daily.id
}

# CloudWatch Alarm for Redshift Health
resource "aws_cloudwatch_metric_alarm" "redshift_health" {
  alarm_name          = "redshift-cluster-health"
  comparison_operator = "LessThanThreshold"
  evaluation_periods  = "1"
  metric_name         = "HealthStatus"
  namespace           = "AWS/Redshift"
  period              = "300"
  statistic           = "Average"
  threshold           = "1"
  alarm_description   = "This metric monitors Redshift cluster health"
  alarm_actions       = [] # Add SNS topic ARN for notifications

  dimensions = {
    ClusterIdentifier = aws_redshift_cluster.redshift_cluster.id
  }
}

# Outputs
output "redshift_cluster_endpoint" {
  description = "The endpoint of the Redshift cluster"
  value       = aws_redshift_cluster.redshift_cluster.endpoint
}

output "redshift_cluster_id" {
  description = "The ID of the Redshift cluster"
  value       = aws_redshift_cluster.redshift_cluster.id
}

output "redshift_database_name" {
  description = "The name of the database"
  value       = aws_redshift_cluster.redshift_cluster.database_name
}

