# Update primary cluster with subnet group and security group
resource "aws_redshift_cluster" "primary_updated" {
  provider = aws.primary

  cluster_identifier        = "primary-redshift-cluster"
  database_name             = "mydb"
  master_username           = "admin"
  master_password           = "YourStrongPassword123!"
  node_type                 = "dc2.large"
  number_of_nodes           = 2
  cluster_type              = "multi-node"
  port                      = 5439
  publicly_accessible       = false
  cluster_subnet_group_name = aws_redshift_subnet_group.primary.name
  vpc_security_group_ids    = [aws_security_group.primary_redshift.id]

  skip_final_snapshot = true

  snapshot_copy {
    destination_region = "us-east-2"
    retention_period   = 7
  }

  tags = {
    Name = "Primary Redshift Cluster"
  }

  lifecycle {
    create_before_destroy = true
  }
}

# Update secondary cluster with subnet group and security group
resource "aws_redshift_cluster" "secondary_updated" {
  provider = aws.secondary

  cluster_identifier        = "secondary-redshift-cluster"
  database_name             = "mydb"
  master_username           = "admin"
  master_password           = "YourStrongPassword123!"
  node_type                 = "dc2.large"
  number_of_nodes           = 2
  cluster_type              = "multi-node"
  port                      = 5439
  publicly_accessible       = false
  cluster_subnet_group_name = aws_redshift_subnet_group.secondary.name
  vpc_security_group_ids    = [aws_security_group.secondary_redshift.id]

  skip_final_snapshot = true

  tags = {
    Name = "Secondary Redshift Cluster"
  }

  lifecycle {
    create_before_destroy = true
  }
}
