# Route Table
resource "aws_route_table" "redshift_rt" {
  vpc_id = aws_vpc.redshift_vpc.id

  route {
    cidr_block = "0.0.0.0/0"
    gateway_id = aws_internet_gateway.redshift_igw.id
  }

  tags = {
    Name = "redshift-rt"
  }
}

# Route Table Associations
resource "aws_route_table_association" "redshift_rta_1" {
  subnet_id      = aws_subnet.redshift_subnet_1.id
  route_table_id = aws_route_table.redshift_rt.id
}

resource "aws_route_table_association" "redshift_rta_2" {
  subnet_id      = aws_subnet.redshift_subnet_2.id
  route_table_id = aws_route_table.redshift_rt.id
}

# Redshift Subnet Group
resource "aws_redshift_subnet_group" "redshift_subnet_group" {
  name       = "redshift-subnet-group"
  subnet_ids = [aws_subnet.redshift_subnet_1.id, aws_subnet.redshift_subnet_2.id]

  tags = {
    Name = "redshift-subnet-group"
  }
}

# Security Group for Redshift
resource "aws_security_group" "redshift_sg" {
  name_prefix = "redshift-sg-"
  vpc_id      = aws_vpc.redshift_vpc.id

  ingress {
    from_port   = 5439
    to_port     = 5439
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"]
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }

  tags = {
    Name = "redshift-sg"
  }
}

# IAM Role for Redshift
resource "aws_iam_role" "redshift_role" {
  name = "redshift-cluster-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "redshift.amazonaws.com"
        }
      }
    ]
  })
}

# Redshift Cluster
resource "aws_redshift_cluster" "redshift_cluster" {
  cluster_identifier        = "my-redshift-cluster"
  database_name             = "mydb"
  master_username           = "adminuser"
  master_password           = "SuperSecretPassword123!"
  node_type                 = "dc2.large"
  number_of_nodes           = 2
  cluster_type              = "multi-node"
  vpc_security_group_ids    = [aws_security_group.redshift_sg.id]
  cluster_subnet_group_name = aws_redshift_subnet_group.redshift_subnet_group.name
  publicly_accessible       = true
  iam_roles                 = [aws_iam_role.redshift_role.arn]

  skip_final_snapshot = true

  tags = {
    Name = "my-redshift-cluster"
  }
}

# Redshift Endpoint Access
resource "aws_redshift_endpoint_access" "redshift_endpoint" {
  cluster_identifier  = aws_redshift_cluster.redshift_cluster.cluster_identifier
  endpoint_name       = "my-redshift-endpoint"
  subnet_group_name   = aws_redshift_subnet_group.redshift_subnet_group.name
  vpc_security_group_ids = [aws_security_group.redshift_sg.id]
}

# Outputs
output "redshift_cluster_endpoint" {
  description = "The endpoint of the Redshift cluster"
  value       = aws_redshift_cluster.redshift_cluster.endpoint
}

output "redshift_endpoint_address" {
  description = "The address of the Redshift endpoint access"
  value       = aws_redshift_endpoint_access.redshift_endpoint.address
}
```

