  function_name = aws_lambda_function.example_lambda.function_name

  input = jsonencode({
    key1 = "value1"
    key2 = "value2"
  })

  depends_on = [aws_lambda_function.example_lambda]
}

# Output the invocation result
output "lambda_invocation_result" {
  value = jsondecode(aws_lambda_invocation.example_lambda_invocation.result)
}

