data "aws_region" "current" {}

data "aws_caller_identity" "current" {}

variable "function_name" {
  description = "Name of the Lambda function"
  type        = string
  default     = "my-lambda-function"
}

variable "alias_name" {
  description = "Name for the Lambda alias"
  type        = string
  default     = "live"
}

variable "function_version" {
  description = "Lambda function version to point the alias to"
  type        = string
  default     = "$LATEST"
}

variable "description" {
  description = "Description of the alias"
  type        = string
  default     = "Production alias"
}

variable "routing_config" {
  description = "Routing configuration for alias (for canary deployments)"
  type = object({
    additional_version_weights = map(number)
  })
  default = null
}

resource "aws_lambda_alias" "this" {
  name             = var.alias_name
  description      = var.description
  function_name    = aws_lambda_function.this.arn
  function_version = var.function_version

  dynamic "routing_config" {
    for_each = var.routing_config != null ? [var.routing_config] : []
    content {
      additional_version_weights = routing_config.value.additional_version_weights
    }
  }
}

resource "aws_lambda_function" "this" {
  function_name = var.function_name
  role          = aws_iam_role.lambda_role.arn
  handler       = "index.handler"
  runtime       = "python3.11"
  filename      = "lambda_function_payload.zip"
  source_code_hash = filebase64sha256("lambda_function_payload.zip")

  publish = true

  lifecycle {
    ignore_changes = [
      filename,
      source_code_hash,
    ]
  }
}

resource "aws_iam_role" "lambda_role" {
  name = "${var.function_name}-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "lambda.amazonaws.com"
        }
      }
    ]
  })
}

resource "aws_iam_role_policy_attachment" "lambda_basic_execution" {
  role       = aws_iam_role.lambda_role.name
  policy_arn = "arn:aws:iam::aws:policy/service-role/AWSLambdaBasicExecutionRole"
}

output "lambda_alias_arn" {
  description = "ARN of the Lambda alias"
  value       = aws_lambda_alias.this.arn
}

output "lambda_alias_invoke_arn" {
  description = "Invoke ARN of the Lambda alias"
  value       = aws_lambda_alias.this.invoke_arn
}

output "lambda_alias_name" {
  description = "Name of the Lambda alias"
  value       = aws_lambda_alias.this.name
}

output "lambda_alias_function_version" {
  description = "Lambda function version the alias points to"
  value       = aws_lambda_alias.this.function_version
}

