terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

provider "aws" {
  region = "us-east-1"
}

# DynamoDB Table
resource "aws_dynamodb_table" "example" {
  name           = "example-table"
  billing_mode   = "PAY_PER_REQUEST"
  hash_key       = "id"

  attribute {
    name = "id"
    type = "S"
  }

  stream_enabled   = true
  stream_view_type = "NEW_AND_OLD_IMAGES"
}

# Kinesis Data Stream
resource "aws_kinesis_stream" "example" {
  name             = "example-stream"
  shard_count      = 1

  encryption_type = "KMS"
  kms_key_id      = "alias/aws/kinesis"
}

# IAM Role for DynamoDB to write to Kinesis
resource "aws_iam_role" "dynamodb_kinesis" {
  name = "dynamodb-kinesis-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "dynamodb.amazonaws.com"
        }
      }
    ]
  })
}

# IAM Policy for DynamoDB to write to Kinesis
resource "aws_iam_role_policy" "dynamodb_kinesis" {
  name = "dynamodb-kinesis-policy"
  role = aws_iam_role.dynamodb_kinesis.id

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect = "Allow"
        Action = [
          "kinesis:PutRecord",
          "kinesis:PutRecords"
        ]
        Resource = aws_kinesis_stream.example.arn
      }
    ]
  })
}

# DynamoDB Kinesis Streaming Destination
resource "aws_dynamodb_kinesis_streaming_destination" "example" {
  stream_arn = aws_kinesis_stream.example.arn
  table_name = aws_dynamodb_table.example.name

  depends_on = [aws_iam_role_policy.dynamodb_kinesis]
}

