terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

# Primary region provider
provider "aws" {
  alias  = "primary"
  region = "us-east-1"
}

# Replica region provider
provider "aws" {
  alias  = "replica"
  region = "eu-west-1"
}

# DynamoDB Global Table in primary region
resource "aws_dynamodb_global_table" "example" {
  provider = aws.primary

  name = "example-global-table"

  billing_mode = "PAY_PER_REQUEST"

  hash_key  = "id"
  range_key = "sort_key"

  attribute {
    name = "id"
    type = "S"
  }

  attribute {
    name = "sort_key"
    type = "S"
  }

  replica {
    region_name = "us-east-1"
  }

  replica {
    region_name = "eu-west-1"
  }
}

# IAM role for DynamoDB Streams (if needed for replication)
resource "aws_iam_role" "dynamodb_replication" {
  provider = aws.primary

  name = "dynamodb-replication-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "dynamodb.amazonaws.com"
        }
      }
    ]
  })
}

# Optional: CloudWatch alarm for table metrics
resource "aws_cloudwatch_metric_alarm" "dynamodb_consumed_read_capacity" {
  provider = aws.primary

  alarm_name          = "dynamodb-consumed-read-capacity"
  comparison_operator = "GreaterThanThreshold"
  evaluation_periods  = "2"
  metric_name         = "ConsumedReadCapacityUnits"
  namespace           = "AWS/DynamoDB"
  period              = "120"
  statistic           = "Average"
  threshold           = "80"
  alarm_description   = "This metric monitors DynamoDB consumed read capacity"
  alarm_actions       = []

  dimensions = {
    TableName = aws_dynamodb_global_table.example.name
  }
}

