  domain_id         = aws_sagemaker_domain.example.id
  user_profile_name = "example-user-profile"

  user_settings {
    execution_role  = aws_iam_role.example.arn

    sharing_settings {
      notebook_output_option = "Allowed"
      s3_output_path         = "s3://${aws_s3_bucket.example.bucket}/sagemaker-output"
      s3_kms_key_id          = aws_kms_key.example.arn
    }

    tensor_board_app_settings {
      default_resource_spec {
        instance_type       = "ml.t3.medium"
        lifecycle_config_arn = aws_sagemaker_studio_lifecycle_config.example.arn
        sagemaker_image_arn = "arn:aws:sagemaker:us-east-1:123456789012:image/tensorflow-2.11-cpu"
      }
    }

    kernel_gateway_app_settings {
      default_resource_spec {
        instance_type = "ml.t3.medium"
      }

      custom_image {
        image_name     = "custom-kernel"
        image_version_number = 1
        app_image_config_name = "custom-kernel-config"
      }
    }

    jupyter_server_app_settings {
      default_resource_spec {
        instance_type = "ml.t3.medium"
      }
    }

    r_session_app_settings {
      default_resource_spec {
        instance_type = "ml.t3.medium"
      }
    }

    canvas_app_settings {
      time_series_forecasting_settings {
        status = "ENABLED"
      }

      model_register_settings {
        status = "ENABLED"
      }

      workspace_settings {
        s3_workspace_path = "s3://${aws_s3_bucket.example.bucket}/canvas-workspace"
      }
    }

    code_editor_app_settings {
      default_resource_spec {
        instance_type = "ml.t3.medium"
      }
    }

    jupyter_lab_app_settings {
      default_resource_spec {
        instance_type = "ml.t3.medium"
      }
    }

    security_groups = [aws_security_group.example.id]
  }

  tags = {
    Name        = "example-user-profile"
    Environment = "dev"
  }
}

