terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

provider "aws" {
  region = "us-east-1"
}

# Get the SageMaker kmeans image URI
data "aws_sagemaker_prebuilt_ecr_image" "kmeans" {
  repository_name = "kmeans"
  image_tag       = "1"
}

# IAM role for SageMaker model
data "aws_iam_policy_document" "sagemaker_assume_role" {
  statement {
    actions = ["sts:AssumeRole"]
    principals {
      type        = "Service"
      identifiers = ["sagemaker.amazonaws.com"]
    }
  }
}

resource "aws_iam_role" "sagemaker_model_role" {
  name               = "sagemaker-kmeans-model-role"
  assume_role_policy = data.aws_iam_policy_document.sagemaker_assume_role.json
}

resource "aws_iam_role_policy_attachment" "sagemaker_full_access" {
  role       = aws_iam_role.sagemaker_model_role.name
  policy_arn = "arn:aws:iam::aws:policy/AmazonSageMakerFullAccess"
}

# S3 bucket for model artifacts (optional - for when you have trained model data)
resource "aws_s3_bucket" "model_artifacts" {
  bucket_prefix = "sagemaker-kmeans-model-"
}

resource "aws_s3_bucket_versioning" "model_artifacts" {
  bucket = aws_s3_bucket.model_artifacts.id
  versioning_configuration {
    status = "Enabled"
  }
}

# SageMaker model
resource "aws_sagemaker_model" "kmeans" {
  name               = "kmeans-model"
  execution_role_arn = aws_iam_role.sagemaker_model_role.arn

  primary_container {
    image = data.aws_sagemaker_prebuilt_ecr_image.kmeans.registry_path

    # Optional: Specify model data URL if you have a pre-trained model
    # model_data_url = "s3://${aws_s3_bucket.model_artifacts.bucket}/model/model.tar.gz"

    environment = {
      SAGEMAKER_PROGRAM          = "kmeans"
      SAGEMAKER_SUBMIT_DIRECTORY = "/opt/ml/model/code"
    }
  }

  tags = {
    Name = "kmeans-model"
  }
}

