# Data source to get the current AWS account ID and region
data "aws_caller_identity" "current" {}
data "aws_region" "current" {}

# IAM role for SageMaker
resource "aws_iam_role" "sagemaker_execution_role" {
  name = "sagemaker-execution-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "sagemaker.amazonaws.com"
        }
      }
    ]
  })
}

resource "aws_iam_role_policy_attachment" "sagemaker_full_access" {
  role       = aws_iam_role.sagemaker_execution_role.name
  policy_arn = "arn:aws:iam::aws:policy/AmazonSageMakerFullAccess"
}

# S3 bucket for model artifacts (optional but recommended)
resource "aws_s3_bucket" "model_artifacts" {
  bucket = "sagemaker-model-artifacts-${data.aws_caller_identity.current.account_id}-${data.aws_region.current.name}"
}

resource "aws_s3_bucket_versioning" "model_artifacts" {
  bucket = aws_s3_bucket.model_artifacts.id
  versioning_configuration {
    status = "Enabled"
  }
}

# Example model data (you would typically upload your actual model)
# This is a placeholder - replace with your actual model artifact
resource "aws_s3_object" "model_artifact" {
  bucket  = aws_s3_bucket.model_artifacts.id
  key     = "model/model.tar.gz"
  content = "placeholder" # Replace with actual model file or use source/path
}

# SageMaker Model
resource "aws_sagemaker_model" "example" {
  name               = "example-model"
  execution_role_arn = aws_iam_role.sagemaker_execution_role.arn

  primary_container {
    image = "${data.aws_caller_identity.current.account_id}.dkr.ecr.${data.aws_region.current.name}.amazonaws.com/my-model:latest"
    # Or use a pre-built AWS image, e.g.:
    # image = "763104351884.dkr.ecr.${data.aws_region.current.name}.amazonaws.com/pytorch-inference:2.0.0-cpu-py310-ubuntu20.04-sagemaker"

    model_data_url = "s3://${aws_s3_bucket.model_artifacts.id}/model/model.tar.gz"

    environment = {
      SAGEMAKER_PROGRAM          = "inference.py"
      SAGEMAKER_SUBMIT_DIRECTORY = "/opt/ml/model/code"
      SAGEMAKER_CONTAINER_LOG_LEVEL = "20"
      SAGEMAKER_REGION           = data.aws_region.current.name
    }
  }

  tags = {
    Name = "example-model"
  }
}

# SageMaker Endpoint Configuration
resource "aws_sagemaker_endpoint_configuration" "example" {
  name = "example-endpoint-config"

  production_variants {
    variant_name           = "variant-one"
    model_name             = aws_sagemaker_model.example.name
    initial_instance_count = 1
    instance_type          = "ml.t2.medium"

    # Optional: Use serverless inference instead of instance-based
    # serverless_config {
    #   max_concurrency   = 5
    #   memory_size_in_mb = 2048
    # }

    # Optional: Enable auto-scaling
    # initial_variant_weight = 1.0

    # Optional: Async inference configuration
    # async_inference_config {
    #   output_config {
    #     s3_output_path = "s3://${aws_s3_bucket.model_artifacts.id}/async-output/"
    #   }
    # }
  }

  # Optional: Enable data capture for monitoring
  # data_capture_config {
  #   enable_capture = true
  #   initial_sampling_percentage = 100
  #   destination_s3_uri = "s3://${aws_s3_bucket.model_artifacts.id}/data-capture/"
  #   capture_options {
  #     capture_mode = "Input"
  #   }
  #   capture_options {
  #     capture_mode = "Output"
  #   }
  #   capture_content_type_header {
  #     csv_content_types = ["text/csv"]
  #     json_content_types = ["application/json"]
  #   }
  # }

  tags = {
    Name = "example-endpoint-config"
  }
}

# SageMaker Endpoint
resource "aws_sagemaker_endpoint" "example" {
  name                 = "example-endpoint"
  endpoint_config_name = aws_sagemaker_endpoint_configuration.example.name

  tags = {
    Name = "example-endpoint"
  }
}

# Optional: Auto-scaling policy for the endpoint
resource "aws_appautoscaling_target" "sagemaker_target" {
  max_capacity       = 4
  min_capacity       = 1
  resource_id        = "endpoint/${aws_sagemaker_endpoint.example.name}/variant/variant-one"
  scalable_dimension = "sagemaker:variant:DesiredInstanceCount"
  service_namespace  = "sagemaker"
}

resource "aws_appautoscaling_policy" "sagemaker_policy" {
  name               = "sagemaker-cpu-utilization"
  policy_type        = "TargetTrackingScaling"
  resource_id        = aws_appautoscaling_target.sagemaker_target.resource_id
  scalable_dimension = aws_appautoscaling_target.sagemaker_target.scalable_dimension
  service_namespace  = aws_appautoscaling_target.sagemaker_target.service_namespace

  target_tracking_scaling_policy_configuration {
    predefined_metric_specification {
      predefined_metric_type = "SageMakerVariantInvocationsPerInstance"
    }
    target_value       = 100.0
    scale_in_cooldown  = 300
    scale_out_cooldown = 300
  }
}

# Outputs
output "sagemaker_endpoint_name" {
  description = "The name of the SageMaker endpoint"
  value       = aws_sagemaker_endpoint.example.name
}

output "sagemaker_endpoint_arn" {
  description = "The ARN of the SageMaker endpoint"
  value       = aws_sagemaker_endpoint.example.arn
}

output "sagemaker_endpoint_config_name" {
  description = "The name of the SageMaker endpoint configuration"
  value       = aws_sagemaker_endpoint_configuration.example.name
}

output "sagemaker_model_name" {
  description = "The name of the SageMaker model"
  value       = aws_sagemaker_model.example.name
}

