# IAM Role for ElastiCache User Authentication
resource "aws_iam_role" "elasticache_user_role" {
  name = "elasticache-user-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "elasticache.amazonaws.com"
        }
      }
    ]
  })
}

# IAM Policy for ElastiCache Access
resource "aws_iam_policy" "elasticache_access_policy" {
  name        = "elasticache-access-policy"
  description = "Policy for ElastiCache user access"

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect = "Allow"
        Action = [
          "elasticache:Connect"
        ]
        Resource = "*"
      }
    ]
  })
}

# Attach policy to role
resource "aws_iam_role_policy_attachment" "elasticache_policy_attach" {
  role       = aws_iam_role.elasticache_user_role.name
  policy_arn = aws_iam_policy.elasticache_access_policy.arn
}

# ElastiCache User Group with IAM Authentication
