  user_id       = "iam-auth-user"
  user_name     = "iam-auth-user"
  access_string = "on ~* +@all"
  engine        = "REDIS"
  authentication_mode {
    type = "iam"
  }
}

# ElastiCache Replication Group (Redis)
resource "aws_elasticache_replication_group" "example" {
  replication_group_id       = "example-redis-cluster"
  description                = "Example Redis cluster with IAM authentication"
  engine                     = "redis"
  engine_version             = "7.0"
  node_type                  = "cache.t3.micro"
  num_cache_clusters         = 2
  automatic_failover_enabled = true
  multi_az_enabled           = true
  at_rest_encryption_enabled = true
  transit_encryption_enabled = true
  auth_token                 = null # Not needed with IAM auth

  user_group_ids = [aws_elasticache_user_group.example.user_group_id]

  tags = {
    Name = "example-redis-cluster"
  }
}

# IAM User Policy for ElastiCache IAM Authentication
