# Variables
variable "elasticache_user_name" {
  description = "Name of the ElastiCache user"
  type        = string
  default     = "app-user"
}

variable "elasticache_user_password" {
  description = "Password for the ElastiCache user"
  type        = string
  sensitive   = true
}

variable "elasticache_subnet_group_name" {
  description = "Name of the ElastiCache subnet group"
  type        = string
}

variable "vpc_id" {
  description = "VPC ID for the ElastiCache security group"
  type        = string
}

variable "allowed_cidr_blocks" {
  description = "CIDR blocks allowed to access ElastiCache"
  type        = list(string)
  default     = []
}

# ElastiCache User Group
resource "aws_elasticache_user_group" "main" {
  engine        = "redis"
  user_group_id = "app-user-group"
  user_ids      = [aws_elasticache_user.default.id, aws_elasticache_user.custom.id]
}

# Default ElastiCache User (required for user groups)
resource "aws_elasticache_user" "default" {
  user_id       = "default"
  user_name     = "default"
  access_string = "on ~* +@all"
  engine        = "redis"
  passwords     = [var.elasticache_user_password]
}

# Custom ElastiCache User with password authentication
resource "aws_elasticache_user" "custom" {
  user_id       = var.elasticache_user_name
  user_name     = var.elasticache_user_name
  access_string = "on ~app:* +@read +@write -@admin"
  engine        = "redis"
  passwords     = [var.elasticache_user_password]

  authentication_mode {
    type      = "password"
    passwords = [var.elasticache_user_password]
  }
}

# ElastiCache Subnet Group
resource "aws_elasticache_subnet_group" "main" {
  name       = var.elasticache_subnet_group_name
  subnet_ids = data.aws_subnets.private.ids
}

# Data source for subnets
data "aws_subnets" "private" {
  filter {
    name   = "vpc-id"
    values = [var.vpc_id]
  }
}

# Security Group for ElastiCache
resource "aws_security_group" "elasticache" {
  name_prefix = "elasticache-"
  vpc_id      = var.vpc_id

  ingress {
    from_port   = 6379
    to_port     = 6379
    protocol    = "tcp"
    cidr_blocks = var.allowed_cidr_blocks
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }

  tags = {
    Name = "elasticache-security-group"
  }
}

# ElastiCache Redis Cluster with ACL enabled
resource "aws_elasticache_replication_group" "main" {
  replication_group_id       = "app-redis-cluster"
  description                = "Redis cluster with password authentication"
  engine                     = "redis"
  engine_version             = "7.0"
  node_type                  = "cache.t3.micro"
  num_cache_clusters         = 2
  automatic_failover_enabled = true
  multi_az_enabled           = true

  subnet_group_name  = aws_elasticache_subnet_group.main.name
  security_group_ids = [aws_security_group.elasticache.id]

  user_group_ids = [aws_elasticache_user_group.main.user_group_id]

  at_rest_encryption_enabled = true
  transit_encryption_enabled = true

  snapshot_retention_limit = 7
  snapshot_window          = "05:00-06:00"
  maintenance_window       = "sun:07:00-sun:08:00"

  tags = {
    Name = "app-redis-cluster"
  }
}

# Secrets Manager for secure password storage
resource "aws_secretsmanager_secret" "elasticache_password" {
  name                    = "elasticache/${var.elasticache_user_name}/password"
  description             = "Password for ElastiCache user ${var.elasticache_user_name}"
  recovery_window_in_days = 7
}

resource "aws_secretsmanager_secret_version" "elasticache_password" {
  secret_id     = aws_secretsmanager_secret.elasticache_password.id
  secret_string = var.elasticache_user_password
}

# Outputs
output "elasticache_endpoint" {
  description = "ElastiCache cluster endpoint"
  value       = aws_elasticache_replication_group.main.primary_endpoint_address
}

output "elasticache_user_group_id" {
  description = "ElastiCache user group ID"
  value       = aws_elasticache_user_group.main.user_group_id
}

output "elasticache_user_id" {
  description = "ElastiCache custom user ID"
  value       = aws_elasticache_user.custom.user_id
}

