provider "aws" {
  region = "us-east-1"
}

# VPC and Networking for MSK
data "aws_availability_zones" "available" {
  state = "available"
}

resource "aws_vpc" "msk_vpc" {
  cidr_block           = "10.0.0.0/16"
  enable_dns_hostnames = true
  enable_dns_support   = true

  tags = {
    Name = "msk-vpc"
  }
}

resource "aws_subnet" "msk_subnets" {
  count             = 3
  vpc_id            = aws_vpc.msk_vpc.id
  cidr_block        = "10.0.${count.index + 1}.0/24"
  availability_zone = data.aws_availability_zones.available.names[count.index]

  tags = {
    Name = "msk-subnet-${count.index + 1}"
  }
}

resource "aws_security_group" "msk_security_group" {
  name_prefix = "msk-sg-"
  vpc_id      = aws_vpc.msk_vpc.id

  ingress {
    from_port   = 0
    to_port     = 65535
    protocol    = "tcp"
    cidr_blocks = [aws_vpc.msk_vpc.cidr_block]
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }

  tags = {
    Name = "msk-security-group"
  }
}

# MSK Cluster
resource "aws_msk_cluster" "msk_cluster" {
  cluster_name           = "debezium-msk-cluster"
  kafka_version          = "3.5.1"
  number_of_broker_nodes = 3

  broker_node_group_info {
    instance_type  = "kafka.t3.small"
    client_subnets = aws_subnet.msk_subnets[*].id
    security_groups = [aws_security_group.msk_security_group.id]

    storage_info {
      ebs_storage_info {
        volume_size = 100
      }
    }
  }

  encryption_info {
    encryption_in_transit {
      client_broker = "TLS"
      in_cluster    = true
    }
  }

  client_authentication {
    unauthenticated = true
  }

  tags = {
    Name = "debezium-msk-cluster"
  }
}

# S3 Bucket for MSK Connect Custom Plugin
resource "aws_s3_bucket" "msk_connect_bucket" {
  bucket_prefix = "msk-connect-plugins-"

  tags = {
    Name = "msk-connect-plugins"
  }
}

resource "aws_s3_bucket_versioning" "msk_connect_bucket_versioning" {
  bucket = aws_s3_bucket.msk_connect_bucket.id
  versioning_configuration {
    status = "Enabled"
  }
}

resource "aws_s3_object" "debezium_plugin" {
  bucket = aws_s3_bucket.msk_connect_bucket.id
  key    = "debezium.zip"
  source = "debezium.zip"

  # The file debezium.zip should exist in the working directory
  # or use content_base64 if you have the zip content
}

# MSK Connect Custom Plugin
resource "aws_mskconnect_custom_plugin" "debezium_plugin" {
  name         = "debezium-postgres-plugin"
  description  = "Debezium PostgreSQL CDC connector plugin"
  content_type = "ZIP"

  location {
    s3 {
      bucket_arn = aws_s3_bucket.msk_connect_bucket.arn
      file_key   = aws_s3_object.debezium_plugin.key
    }
  }

  depends_on = [aws_s3_object.debezium_plugin]
}

# IAM Role for MSK Connect
resource "aws_iam_role" "msk_connect_role" {
  name = "msk-connect-execution-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "kafkaconnect.amazonaws.com"
        }
      }
    ]
  })
}

resource "aws_iam_role_policy" "msk_connect_policy" {
  name = "msk-connect-policy"
  role = aws_iam_role.msk_connect_role.id

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect = "Allow"
        Action = [
          "kafka-cluster:Connect",
          "kafka-cluster:AlterCluster",
          "kafka-cluster:DescribeCluster",
          "kafka-cluster:DescribeClusterDynamicConfiguration",
          "kafka-cluster:AlterClusterDynamicConfiguration",
          "kafka-cluster:WriteData",
          "kafka-cluster:ReadData",
          "kafka-cluster:DescribeTopic",
          "kafka-cluster:CreateTopic",
          "kafka-cluster:AlterTopic",
          "kafka-cluster:DeleteTopic",
          "kafka-cluster:DescribeGroup",
          "kafka-cluster:AlterGroup",
          "kafka-cluster:DeleteGroup"
        ]
        Resource = "*"
      },
      {
        Effect = "Allow"
        Action = [
          "s3:GetObject",
          "s3:ListBucket"
        ]
        Resource = [
          aws_s3_bucket.msk_connect_bucket.arn,
          "${aws_s3_bucket.msk_connect_bucket.arn}/*"
        ]
      },
      {
        Effect = "Allow"
        Action = [
          "logs:CreateLogGroup",
          "logs:CreateLogStream",
          "logs:PutLogEvents"
        ]
        Resource = "*"
      }
    ]
  })
}

# CloudWatch Log Group for MSK Connect
resource "aws_cloudwatch_log_group" "msk_connect_logs" {
  name              = "/aws/mskconnect/debezium-connector"
  retention_in_days = 7
}

# MSK Connect Connector
resource "aws_mskconnect_connector" "debezium_connector" {
  name = "debezium-postgres-connector"

  kafkaconnect_version = "2.7.1"

  capacity {
    autoscaling {
      mcu_count        = 1
      min_worker_count = 1
      max_worker_count = 2

      scale_in_policy {
        cpu_utilization_percentage = 20
      }

      scale_out_policy {
        cpu_utilization_percentage = 80
      }
    }
  }

  connector_configuration = {
    "connector.class"                = "io.debezium.connector.postgresql.PostgresConnector"
    "tasks.max"                      = "1"
    "database.hostname"              = "your-postgres-host.amazonaws.com"
    "database.port"                  = "5432"
    "database.user"                  = "debezium"
    "database.password"              = "your-password"
    "database.dbname"                = "your-database"
    "database.server.name"           = "dbserver1"
    "table.include.list"             = "public.your_table"
    "plugin.name"                    = "pgoutput"
    "slot.name"                      = "debezium_slot"
    "publication.name"               = "dbz_publication"
    "topic.prefix"                   = "dbserver1"
    "schema.include.list"            = "public"
    "tombstones.on.delete"           = "true"
    "decimal.handling.mode"          = "string"
    "time.precision.mode"            = "connect"
    "key.converter"                  = "org.apache.kafka.connect.json.JsonConverter"
    "key.converter.schemas.enable"   = "false"
    "value.converter"                = "org.apache.kafka.connect.json.JsonConverter"
    "value.converter.schemas.enable" = "false"
    "transforms"                     = "unwrap"
    "transforms.unwrap.type"         = "io.debezium.transforms.ExtractNewRecordState"
    "transforms.unwrap.drop.tombstones" = "false"
    "transforms.unwrap.delete.handling.mode" = "rewrite"
  }

  kafka_cluster {
    apache_kafka_cluster {
      bootstrap_servers = aws_msk_cluster.msk_cluster.bootstrap_brokers_tls

      vpc {
        security_groups = [aws_security_group.msk_security_group.id]
        subnets         = aws_subnet.msk_subnets[*].id
      }
    }
  }

  kafka_cluster_client_authentication {
    authentication_type = "NONE"
  }

  kafka_cluster_encryption_in_transit {
    encryption_type = "TLS"
  }

  plugin {
    custom_plugin {
      arn      = aws_mskconnect_custom_plugin.debezium_plugin.arn
      revision = aws_mskconnect_custom_plugin.debezium_plugin.latest_revision
    }
  }

  service_execution_role_arn = aws_iam_role.msk_connect_role.arn

  log_delivery {
    worker_log_delivery {
      cloudwatch_logs {
        enabled   = true
        log_group = aws_cloudwatch_log_group.msk_connect_logs.name
      }
    }
  }

  depends_on = [
    aws_mskconnect_custom_plugin.debezium_plugin,
    aws_iam_role_policy.msk_connect_policy
  ]
}

# Outputs
output "msk_cluster_arn" {
  description = "ARN of the MSK cluster"
  value       = aws_msk_cluster.msk_cluster.arn
}

output "msk_bootstrap_brokers_tls" {
  description = "TLS connection host:port pairs"
  value       = aws_msk_cluster.msk_cluster.bootstrap_brokers_tls
  sensitive   = true
}

output "msk_connect_custom_plugin_arn" {
  description = "ARN of the MSK Connect custom plugin"
  value       = aws_mskconnect_custom_plugin.debezium_plugin.arn
}

output "msk_connect_connector_arn" {
  description = "ARN of the MSK Connect connector"
  value       = aws_mskconnect_connector.debezium_connector.arn
}
