terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

provider "aws" {
  region = "us-east-1"
}

resource "aws_rds_cluster" "mysql_cluster" {
  cluster_identifier      = "mysql-cluster"
  engine                  = "aurora-mysql"
  engine_version          = "8.0.mysql_aurora.3.05.2"
  database_name           = "mydb"
  master_username         = "admin"
  master_password         = var.master_password
  db_subnet_group_name    = aws_db_subnet_group.mysql_subnet_group.name
  vpc_security_group_ids  = [aws_security_group.mysql_sg.id]
  backup_retention_period = 7
  preferred_backup_window = "07:00-09:00"
  skip_final_snapshot     = true

  storage_encrypted = true
}

resource "aws_rds_cluster_instance" "cluster_instances" {
  count              = 3
  identifier         = "mysql-cluster-instance-${count.index + 1}"
  cluster_identifier = aws_rds_cluster.mysql_cluster.id
  instance_class     = "db.r6g.large"
  engine             = aws_rds_cluster.mysql_cluster.engine
  availability_zone  = "us-east-1${["a", "b", "c"][count.index]}"
}

resource "aws_db_subnet_group" "mysql_subnet_group" {
  name       = "mysql-subnet-group"
  subnet_ids = aws_subnet.mysql_subnets[*].id

  tags = {
    Name = "MySQL subnet group"
  }
}

resource "aws_vpc" "mysql_vpc" {
  cidr_block           = "10.0.0.0/16"
  enable_dns_hostnames = true
  enable_dns_support   = true

  tags = {
    Name = "mysql-vpc"
  }
}

resource "aws_subnet" "mysql_subnets" {
  count             = 3
  vpc_id            = aws_vpc.mysql_vpc.id
  cidr_block        = "10.0.${count.index + 1}.0/24"
  availability_zone = "us-east-1${["a", "b", "c"][count.index]}"

  tags = {
    Name = "mysql-subnet-${count.index + 1}"
  }
}

resource "aws_security_group" "mysql_sg" {
  name        = "mysql-security-group"
  description = "Security group for MySQL cluster"
  vpc_id      = aws_vpc.mysql_vpc.id

  ingress {
    from_port   = 3306
    to_port     = 3306
    protocol    = "tcp"
    cidr_blocks = ["10.0.0.0/16"]
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }

  tags = {
    Name = "mysql-sg"
  }
}

resource "aws_internet_gateway" "mysql_igw" {
  vpc_id = aws_vpc.mysql_vpc.id

  tags = {
    Name = "mysql-igw"
  }
}

resource "aws_route_table" "mysql_rt" {
  vpc_id = aws_vpc.mysql_vpc.id

  route {
    cidr_block = "0.0.0.0/0"
    gateway_id = aws_internet_gateway.mysql_igw.id
  }

  tags = {
    Name = "mysql-rt"
  }
}

resource "aws_route_table_association" "mysql_rta" {
  count          = 3
  subnet_id      = aws_subnet.mysql_subnets[count.index].id
  route_table_id = aws_route_table.mysql_rt.id
}

variable "master_password" {
  description = "Master password for the MySQL cluster"
  type        = string
  sensitive   = true
}

output "cluster_endpoint" {
  value = aws_rds_cluster.mysql_cluster.endpoint
}

output "cluster_reader_endpoint" {
  value = aws_rds_cluster.mysql_cluster.reader_endpoint
}

