extracted_code:
# DynamoDB Table with TTL for data expiration
resource "aws_dynamodb_table" "example" {
  name         = "example-table"
  billing_mode = "PAY_PER_REQUEST"
  hash_key     = "id"

  attribute {
    name = "id"
    type = "S"
  }

  attribute {
    name = "expiration_timestamp"
    type = "N"
  }

  ttl {
    attribute_name = "expiration_timestamp"
    enabled        = true
  }
}

# S3 Bucket with lifecycle expiration rule
resource "aws_s3_bucket" "example" {
  bucket = "example-bucket-with-ttl"
}

resource "aws_s3_bucket_lifecycle_configuration" "example" {
  bucket = aws_s3_bucket.example.id

  rule {
    id     = "expire-old-objects"
    status = "Enabled"

    expiration {
      days = 90
    }

    filter {
      prefix = "temp/"
    }
  }
}

# ElastiCache Redis with key expiration (TTL) support
resource "aws_elasticache_cluster" "example" {
  cluster_id           = "example-redis"
  engine               = "redis"
  node_type            = "cache.t3.micro"
  num_cache_nodes      = 1
  parameter_group_name = aws_elasticache_parameter_group.example.name
  port                 = 6379
}

resource "aws_elasticache_parameter_group" "example" {
  family = "redis7"
  name   = "example-params"

  parameter {
    name  = "maxmemory-policy"
    value = "allkeys-lru"
  }
}

# DocumentDB TTL support
resource "aws_docdb_cluster" "example" {
  cluster_identifier = "example-docdb"
  engine             = "docdb"
  master_username    = "admin"
  master_password    = "changeme123"
}

resource "aws_docdb_cluster_instance" "example" {
  identifier         = "example-instance"
  cluster_identifier = aws_docdb_cluster.example.id
  instance_class     = "db.t3.medium"
}

# CloudWatch Logs retention (TTL for logs)
resource "aws_cloudwatch_log_group" "example" {
  name              = "/aws/lambda/example"
  retention_in_days = 30
}

# SQS Queue with message retention (TTL)
resource "aws_sqs_queue" "example" {
  name                       = "example-queue"
  message_retention_seconds  = 345600  # 4 days
  visibility_timeout_seconds = 30
}

# Kinesis Data Stream with data retention (TTL)
resource "aws_kinesis_stream" "example" {
  name             = "example-stream"
  shard_count      = 1
  retention_period = 48  # hours
}

reference:
