provider "aws" {
  region = "us-east-1"
}

# VPC and networking resources for Neptune
resource "aws_vpc" "neptune_vpc" {
  cidr_block           = "10.0.0.0/16"
  enable_dns_hostnames = true
  enable_dns_support   = true

  tags = {
    Name = "neptune-vpc"
  }
}

resource "aws_subnet" "neptune_subnet_1" {
  vpc_id            = aws_vpc.neptune_vpc.id
  cidr_block        = "10.0.1.0/24"
  availability_zone = "us-east-1a"

  tags = {
    Name = "neptune-subnet-1"
  }
}

resource "aws_subnet" "neptune_subnet_2" {
  vpc_id            = aws_vpc.neptune_vpc.id
  cidr_block        = "10.0.2.0/24"
  availability_zone = "us-east-1b"

  tags = {
    Name = "neptune-subnet-2"
  }
}

resource "aws_neptune_subnet_group" "neptune_subnet_group" {
  name       = "neptune-subnet-group"
  subnet_ids = [aws_subnet.neptune_subnet_1.id, aws_subnet.neptune_subnet_2.id]

  tags = {
    Name = "neptune-subnet-group"
  }
}

# Security group for Neptune
resource "aws_security_group" "neptune_security_group" {
  name_prefix = "neptune-sg-"
  vpc_id      = aws_vpc.neptune_vpc.id

  ingress {
    from_port   = 8182
    to_port     = 8182
    protocol    = "tcp"
    cidr_blocks = ["10.0.0.0/16"]
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }

  tags = {
    Name = "neptune-security-group"
  }
}

# Custom Neptune parameter group
resource "aws_neptune_parameter_group" "custom_parameter_group" {
  family = "neptune1.2"
  name   = "custom-neptune-parameter-group"

  parameter {
    name  = "neptune_query_timeout"
    value = "120000"
  }

  parameter {
    name  = "neptune_slow_query_log_threshold"
    value = "5000"
  }

  tags = {
    Name = "custom-neptune-parameter-group"
  }
}

# Neptune cluster
resource "aws_neptune_cluster" "neptune_cluster" {
  cluster_identifier                   = "neptune-cluster"
  engine                               = "neptune"
