  region = "us-east-1"
}

# VPC and Subnet Configuration for Neptune
data "aws_availability_zones" "available" {
  state = "available"
}

resource "aws_vpc" "neptune_vpc" {
  cidr_block           = "10.0.0.0/16"
  enable_dns_hostnames = true
  enable_dns_support   = true

  tags = {
    Name = "neptune-vpc"
  }
}

resource "aws_subnet" "neptune_subnet_1" {
  vpc_id            = aws_vpc.neptune_vpc.id
  cidr_block        = "10.0.1.0/24"
  availability_zone = data.aws_availability_zones.available.names[0]

  tags = {
    Name = "neptune-subnet-1"
  }
}

resource "aws_subnet" "neptune_subnet_2" {
  vpc_id            = aws_vpc.neptune_vpc.id
  cidr_block        = "10.0.2.0/24"
  availability_zone = data.aws_availability_zones.available.names[1]

  tags = {
    Name = "neptune-subnet-2"
  }
}

resource "aws_db_subnet_group" "neptune_subnet_group" {
  name       = "neptune-subnet-group"
  subnet_ids = [aws_subnet.neptune_subnet_1.id, aws_subnet.neptune_subnet_2.id]

  tags = {
    Name = "Neptune subnet group"
  }
}

# Security Group for Neptune
resource "aws_security_group" "neptune_security_group" {
  name_prefix = "neptune-sg-"
  vpc_id      = aws_vpc.neptune_vpc.id

  ingress {
    from_port   = 8182
    to_port     = 8182
    protocol    = "tcp"
    cidr_blocks = [aws_vpc.neptune_vpc.cidr_block]
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }

  tags = {
    Name = "neptune-security-group"
  }

  lifecycle {
    create_before_destroy = true
  }
}

# Custom Cluster Parameter Group
resource "aws_neptune_cluster_parameter_group" "custom_cluster_pg" {
  family      = "neptune1.2"
  name        = "custom-neptune-cluster-pg"
  description = "Custom Neptune cluster parameter group"

  parameter {
    name  = "neptune_query_timeout"
    value = "120000"
  }

  parameter {
    name  = "neptune_enable_audit_log"
    value = "1"
  }
}

# Custom DB Parameter Group
resource "aws_neptune_parameter_group" "custom_db_pg" {
  family      = "neptune1.2"
  name        = "custom-neptune-db-pg"
  description = "Custom Neptune DB parameter group"

  parameter {
    name  = "neptune_query_timeout"
    value = "60000"
  }
}

# Neptune Cluster
resource "aws_neptune_cluster" "main" {
  cluster_identifier                   = "neptune-cluster-demo"
  engine                               = "neptune"
  engine_version                       = "1.2.0.0"
  db_cluster_parameter_group_name      = aws_neptune_cluster_parameter_group.custom_cluster_pg.name
  db_subnet_group_name                 = aws_db_subnet_group.neptune_subnet_group.name
  vpc_security_group_ids               = [aws_security_group.neptune_security_group.id]
  skip_final_snapshot                  = true
  iam_database_authentication_enabled  = false
  storage_encrypted                    = true

  tags = {
    Name = "neptune-cluster-demo"
  }
}

# Neptune Cluster Instance
resource "aws_neptune_cluster_instance" "main" {
  identifier                   = "neptune-instance-demo"
  cluster_identifier           = aws_neptune_cluster.main.id
  instance_class               = "db.r5.large"
  engine                       = "neptune"
  neptune_parameter_group_name = aws_neptune_parameter_group.custom_db_pg.name
  auto_minor_version_upgrade   = true
  apply_immediately            = true

  tags = {
    Name = "neptune-instance-demo"
  }
}

# Outputs
output "neptune_cluster_endpoint" {
  description = "Neptune cluster endpoint"
  value       = aws_neptune_cluster.main.endpoint
}

output "neptune_cluster_reader_endpoint" {
  description = "Neptune cluster reader endpoint"
  value       = aws_neptune_cluster.main.reader_endpoint
}

output "neptune_instance_endpoint" {
  description = "Neptune instance endpoint"
  value       = aws_neptune_cluster_instance.main.endpoint
}
```

