# Data source for current AWS account
data "aws_caller_identity" "current" {}

# Data source for current AWS region
data "aws_region" "current" {}

# KMS key for Chime Voice Connector encryption
resource "aws_kms_key" "chime_encryption" {
  description             = "KMS key for Chime Voice Connector encryption"
  deletion_window_in_days = 30
  enable_key_rotation     = true

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Sid    = "Enable IAM User Permissions"
        Effect = "Allow"
        Principal = {
          AWS = "arn:aws:iam::${data.aws_caller_identity.current.account_id}:root"
        }
        Action   = "kms:*"
        Resource = "*"
      },
      {
        Sid    = "Allow Chime Service"
        Effect = "Allow"
        Principal = {
          Service = "chime.amazonaws.com"
        }
        Action = [
          "kms:Encrypt",
          "kms:Decrypt",
          "kms:GenerateDataKey*"
        ]
        Resource = "*"
      }
    ]
  })
}

resource "aws_kms_alias" "chime_encryption" {
  name          = "alias/chime-voice-connector-encryption"
  target_key_id = aws_kms_key.chime_encryption.key_id
}

# SNS Topic for Chime Voice Connector notifications
resource "aws_sns_topic" "chime_notifications" {
  name = "chime-voice-connector-notifications"

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Sid    = "Allow Chime Service"
        Effect = "Allow"
        Principal = {
          Service = "chime.amazonaws.com"
        }
        Action   = "SNS:Publish"
        Resource = "arn:aws:sns:${data.aws_region.current.name}:${data.aws_caller_identity.current.account_id}:chime-voice-connector-notifications"
      }
    ]
  })
}

# Chime Voice Connector with encryption
resource "aws_chime_voice_connector" "this" {
  name               = "voice-connector-encrypted"
  require_encryption = true

  aws_region = data.aws_region.current.name
}

# Chime Voice Connector Streaming Configuration
# Note: AWS Provider doesn't have a native resource for streaming configuration
# Using aws_chimesdkmediapipelines_media_insights_pipeline_configuration as alternative
# or aws_chime_voice_connector_logging for logging configuration

# For streaming configuration, we need to use the AWS CLI or SDK directly
# as Terraform AWS provider doesn't have a dedicated resource for voice connector streaming
# Using null_resource with local-exec as a workaround

resource "null_resource" "chime_voice_connector_streaming" {
  triggers = {
    voice_connector_id = aws_chime_voice_connector.this.id
    sns_topic_arn      = aws_sns_topic.chime_notifications.arn
  }

  provisioner "local-exec" {
    command = <<-EOT
      aws chime put-voice-connector-streaming-configuration \n        --voice-connector-id ${aws_chime_voice_connector.this.id} \n        --streaming-configuration '{
          "DataRetentionInHours": 5,
          "Disabled": false,
          "StreamingNotificationTargets": [
            {
              "NotificationTarget": "SNS",
              "NotificationTargetArn": "${aws_sns_topic.chime_notifications.arn}"
            }
          ],
          "MediaInsightsConfiguration": {
            "Disabled": true
          }
        }'
    EOT
  }

  depends_on = [aws_chime_voice_connector.this, aws_sns_topic.chime_notifications]
}

# Alternative: Using terraform_data for destroy-time cleanup
resource "terraform_data" "chime_voice_connector_streaming_cleanup" {
  triggers_replace = [aws_chime_voice_connector.this.id]

  provisioner "local-exec" {
    when    = destroy
    command = <<-EOT
      aws chime delete-voice-connector-streaming-configuration \n        --voice-connector-id ${self.triggers_replace[0]} || true
    EOT
  }
}

# Outputs
output "voice_connector_id" {
  description = "The ID of the Chime Voice Connector"
  value       = aws_chime_voice_connector.this.id
}

output "voice_connector_outbound_host_name" {
  description = "The outbound host name of the Chime Voice Connector"
  value       = aws_chime_voice_connector.this.outbound_host_name
}

output "kms_key_arn" {
  description = "The ARN of the KMS key used for encryption"
  value       = aws_kms_key.chime_encryption.arn
}

output "sns_topic_arn" {
  description = "The ARN of the SNS topic for notifications"
  value       = aws_sns_topic.chime_notifications.arn
}

