terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

provider "aws" {
  region = "us-east-1"
}

# Data source to get current account ID and region
data "aws_caller_identity" "current" {}
data "aws_region" "current" {}

# Create the Chime Voice Connector
resource "aws_chime_voice_connector" "this" {
  name               = "example-voice-connector"
  require_encryption = true

  aws_region = "us-east-1"
}

# Create a Kinesis Stream for media streaming
resource "aws_kinesis_stream" "media_stream" {
  name             = "chime-voice-connector-media-stream"
  shard_count      = 1

  stream_mode_details {
    stream_mode = "PROVISIONED"
  }
}

# IAM Role for Chime Voice Connector to write to Kinesis
resource "aws_iam_role" "chime_kinesis_role" {
  name = "chime-voice-connector-kinesis-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "voiceconnector.chime.amazonaws.com"
        }
      }
    ]
  })
}

# IAM Policy for Chime Voice Connector to write to Kinesis
resource "aws_iam_role_policy" "chime_kinesis_policy" {
  name = "chime-voice-connector-kinesis-policy"
  role = aws_iam_role.chime_kinesis_role.id

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect = "Allow"
        Action = [
          "kinesis:PutRecord",
          "kinesis:PutRecords"
        ]
        Resource = aws_kinesis_stream.media_stream.arn
      }
    ]
  })
}

# Create the Voice Connector Streaming Configuration
resource "aws_chime_voice_connector_streaming" "this" {
  voice_connector_id = aws_chime_voice_connector.this.id

  data_retention_in_hours = 24
  disabled                = false

  streaming_notification_targets {
    notification_target = "EventBridge"
  }

  media_stream_configuration {
    enabled = true

    media_stream_type = "Audio"

    media_stream_sink_arn = aws_kinesis_stream.media_stream.arn
  }

  depends_on = [aws_iam_role_policy.chime_kinesis_policy]
}

# Optional: Create an EventBridge rule to capture streaming events
resource "aws_cloudwatch_event_rule" "chime_streaming_events" {
  name        = "chime-voice-connector-streaming-events"
  description = "Capture Chime Voice Connector streaming events"

  event_pattern = jsonencode({
    source = ["aws.chime"]
    detail-type = ["Chime Voice Connector Streaming Status"]
  })
}

# Optional: EventBridge target (e.g., CloudWatch Log Group)
resource "aws_cloudwatch_log_group" "chime_events" {
  name              = "/aws/events/chime-voice-connector"
  retention_in_days = 7
}

resource "aws_cloudwatch_event_target" "chime_events_to_logs" {
  rule      = aws_cloudwatch_event_rule.chime_streaming_events.name
  target_id = "ChimeEventsToLogs"
  arn       = aws_cloudwatch_log_group.chime_events.arn
}

# Outputs
output "voice_connector_id" {
  description = "The ID of the Chime Voice Connector"
  value       = aws_chime_voice_connector.this.id
}

output "voice_connector_outbound_host_name" {
  description = "The outbound host name of the Chime Voice Connector"
  value       = aws_chime_voice_connector.this.outbound_host_name
}

output "kinesis_stream_arn" {
  description = "The ARN of the Kinesis stream for media streaming"
  value       = aws_kinesis_stream.media_stream.arn
}

output "kinesis_stream_name" {
  description = "The name of the Kinesis stream for media streaming"
  value       = aws_kinesis_stream.media_stream.name
}

