terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

provider "aws" {
  region = "us-east-1"
}

# SNS Topic for Redshift notifications
resource "aws_sns_topic" "redshift_notifications" {
  name = "redshift-cluster-notifications"

  tags = {
    Name = "Redshift Notifications"
  }
}

# SNS Topic Policy to allow Redshift to publish
data "aws_iam_policy_document" "sns_topic_policy" {
  statement {
    sid    = "AllowRedshiftToPublish"
    effect = "Allow"

    principals {
      type        = "Service"
      identifiers = ["redshift.amazonaws.com"]
    }

    actions   = ["SNS:Publish"]
    resources = [aws_sns_topic.redshift_notifications.arn]
  }
}

resource "aws_sns_topic_policy" "redshift_notifications" {
  arn    = aws_sns_topic.redshift_notifications.arn
  policy = data.aws_iam_policy_document.sns_topic_policy.json
}

# Optional: Email subscription for notifications
resource "aws_sns_topic_subscription" "email" {
  topic_arn = aws_sns_topic.redshift_notifications.arn
  protocol  = "email"
  endpoint  = "admin@example.com" # Replace with actual email
}

# IAM Role for Redshift
data "aws_iam_policy_document" "redshift_assume_role" {
  statement {
    effect = "Allow"

    principals {
      type        = "Service"
      identifiers = ["redshift.amazonaws.com"]
    }

    actions = ["sts:AssumeRole"]
  }
}

resource "aws_iam_role" "redshift_role" {
  name               = "redshift-cluster-role"
  assume_role_policy = data.aws_iam_policy_document.redshift_assume_role.json

  tags = {
    Name = "Redshift Cluster Role"
  }
}

# VPC and Networking for Redshift
data "aws_availability_zones" "available" {
  state = "available"
}

resource "aws_vpc" "redshift_vpc" {
  cidr_block           = "10.0.0.0/16"
  enable_dns_hostnames = true
  enable_dns_support   = true

  tags = {
    Name = "redshift-vpc"
  }
}

resource "aws_internet_gateway" "redshift_igw" {
  vpc_id = aws_vpc.redshift_vpc.id

  tags = {
    Name = "redshift-igw"
  }
}

resource "aws_subnet" "redshift_subnet_1" {
  vpc_id            = aws_vpc.redshift_vpc.id
  cidr_block        = "10.0.1.0/24"
  availability_zone = data.aws_availability_zones.available.names[0]

  tags = {
    Name = "redshift-subnet-1"
  }
}

resource "aws_subnet" "redshift_subnet_2" {
  vpc_id            = aws_vpc.redshift_vpc.id
  cidr_block        = "10.0.2.0/24"
  availability_zone = data.aws_availability_zones.available.names[1]

  tags = {
    Name = "redshift-subnet-2"
  }
}

resource "aws_redshift_subnet_group" "redshift_subnet_group" {
  name       = "redshift-subnet-group"
  subnet_ids = [aws_subnet.redshift_subnet_1.id, aws_subnet.redshift_subnet_2.id]

  tags = {
    Name = "Redshift Subnet Group"
  }
}

# Security Group for Redshift
resource "aws_security_group" "redshift_sg" {
  name        = "redshift-security-group"
  description = "Security group for Redshift cluster"
  vpc_id      = aws_vpc.redshift_vpc.id

  ingress {
    from_port   = 5439
    to_port     = 5439
    protocol    = "tcp"
    cidr_blocks = ["10.0.0.0/16"]
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }

  tags = {
    Name = "Redshift Security Group"
  }
}

# Redshift Parameter Group
resource "aws_redshift_parameter_group" "redshift_params" {
  name   = "redshift-parameter-group"
  family = "redshift-1.0"

  parameter {
    name  = "require_ssl"
    value = "true"
  }

  parameter {
    name  = "enable_user_activity_logging"
    value = "true"
  }

  tags = {
    Name = "Redshift Parameter Group"
  }
}

# Redshift Cluster
resource "aws_redshift_cluster" "main" {
  cluster_identifier = "redshift-cluster"
  database_name      = "mydb"
  master_username    = "admin"
  master_password    = "ChangeMe123!" # Use AWS Secrets Manager in production

  node_type           = "dc2.large"
  cluster_type        = "single-node"
  number_of_nodes     = 1
  skip_final_snapshot = true

  vpc_security_group_ids    = [aws_security_group.redshift_sg.id]
  cluster_subnet_group_name = aws_redshift_subnet_group.redshift_subnet_group.name
  cluster_parameter_group_name = aws_redshift_parameter_group.redshift_params.name

  publicly_accessible  = false
  encrypted            = true
  enhanced_vpc_routing = true

  iam_roles = [aws_iam_role.redshift_role.arn]

  # Logging configuration
  logging {
    enable               = true
    log_destination_type = "cloudwatch"
  }

  tags = {
    Name        = "Redshift Cluster"
    Environment = "production"
  }
}

# Redshift Event Subscription for notifications
resource "aws_redshift_event_subscription" "cluster_events" {
  name          = "redshift-cluster-events"
  sns_topic_arn = aws_sns_topic.redshift_notifications.arn

  source_type = "cluster"
  source_ids  = [aws_redshift_cluster.main.id]

  severity = "INFO"

  event_categories = [
    "configuration",
    "management",
    "monitoring",
    "security",
    "pending"
  ]

  enabled = true

  tags = {
    Name = "Redshift Cluster Events"
  }

  depends_on = [aws_sns_topic_policy.redshift_notifications]
}

# Redshift Event Subscription for cluster parameter group events
resource "aws_redshift_event_subscription" "parameter_group_events" {
  name          = "redshift-parameter-group-events"
  sns_topic_arn = aws_sns_topic.redshift_notifications.arn

  source_type = "cluster-parameter-group"
  source_ids  = [aws_redshift_parameter_group.redshift_params.name]

  severity = "INFO"

  event_categories = [
    "configuration",
    "management"
  ]

  enabled = true

  tags = {
    Name = "Redshift Parameter Group Events"
  }

  depends_on = [aws_sns_topic_policy.redshift_notifications]
}

# CloudWatch Alarms for Redshift monitoring
resource "aws_cloudwatch_metric_alarm" "cpu_utilization" {
  alarm_name          = "redshift-cpu-utilization"
  comparison_operator = "GreaterThanThreshold"
  evaluation_periods  = "2"
  metric_name         = "CPUUtilization"
  namespace           = "AWS/Redshift"
  period              = "300"
  statistic           = "Average"
  threshold           = "80"
  alarm_description   = "This metric monitors Redshift CPU utilization"
  alarm_actions       = [aws_sns_topic.redshift_notifications.arn]

  dimensions = {
    ClusterIdentifier = aws_redshift_cluster.main.cluster_identifier
  }
}

resource "aws_cloudwatch_metric_alarm" "storage_utilization" {
  alarm_name          = "redshift-storage-utilization"
  comparison_operator = "GreaterThanThreshold"
  evaluation_periods  = "2"
  metric_name         = "PercentageDiskSpaceUsed"
  namespace           = "AWS/Redshift"
  period              = "300"
  statistic           = "Average"
  threshold           = "85"
  alarm_description   = "This metric monitors Redshift storage utilization"
  alarm_actions       = [aws_sns_topic.redshift_notifications.arn]

  dimensions = {
    ClusterIdentifier = aws_redshift_cluster.main.cluster_identifier
  }
}

# Outputs
output "redshift_cluster_endpoint" {
  description = "The endpoint of the Redshift cluster"
  value       = aws_redshift_cluster.main.endpoint
}

output "redshift_cluster_id" {
  description = "The ID of the Redshift cluster"
  value       = aws_redshift_cluster.main.cluster_identifier
}

output "sns_topic_arn" {
  description = "The ARN of the SNS topic for Redshift notifications"
  value       = aws_sns_topic.redshift_notifications.arn
}

