}

# Redshift parameter group with custom parameters
resource "aws_redshift_parameter_group" "example" {
  name        = "example-redshift-parameter-group"
  family      = "redshift-1.0"
  description = "Example parameter group for Redshift cluster"

  parameter {
    name  = "enable_user_activity_logging"
    value = "true"
  }

  parameter {
    name  = "max_concurrency_scaling_clusters"
    value = "1"
  }

  parameter {
    name  = "query_group"
    value = "default"
  }

  parameter {
    name  = "statement_timeout"
    value = "3600"
  }

