      {
        query_group = []
        query_groups = []
        user_group  = []
        user_groups = []
        name        = "Default queue"
        memory_percent = 50
        priority    = 5
        queue_type  = "auto"
        auto_wlm    = true
      }
    ])
  }

  tags = {
    Environment = "example"
    ManagedBy   = "terraform"
  }
}

