terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

provider "aws" {
  region = "us-east-1"
}

# SNS Topic for Redshift notifications
resource "aws_sns_topic" "redshift_notifications" {
  name = "redshift-parameter-group-events"
}

# Email subscription for notifications (optional - replace with your email)
resource "aws_sns_topic_subscription" "email_subscription" {
  topic_arn = aws_sns_topic.redshift_notifications.arn
  protocol  = "email"
  endpoint  = "admin@example.com"
}

# Redshift parameter group with custom parameters
resource "aws_redshift_parameter_group" "example" {
  name        = "example-redshift-parameter-group"
  family      = "redshift-1.0"
  description = "Example parameter group for Redshift cluster"

  parameter {
    name  = "enable_user_activity_logging"
    value = "true"
  }

  parameter {
    name  = "max_concurrency_scaling_clusters"
    value = "1"
  }

  parameter {
    name  = "query_group"
    value = "default"
  }

  parameter {
    name  = "statement_timeout"
    value = "3600"
  }

  parameter {
    name  = "wlm_json_configuration"
    value = jsonencode([
      {
        query_group = []
        query_groups = []
        user_group  = []
        user_groups = []
        name        = "Default queue"
        memory_percent = 50
        priority    = 5
        queue_type  = "auto"
        auto_wlm    = true
      }
    ])
  }

  tags = {
    Environment = "example"
    ManagedBy   = "terraform"
  }
}

# Event subscription for parameter group events
resource "aws_redshift_event_subscription" "parameter_group_events" {
  name          = "redshift-parameter-group-events"
  sns_topic_arn = aws_sns_topic.redshift_notifications.arn

  source_type = "cluster-parameter-group"
  source_ids  = [aws_redshift_parameter_group.example.name]

  event_categories = [
    "configuration",
    "management",
  ]

  severity = "INFO"

  tags = {
    Environment = "example"
    ManagedBy   = "terraform"
  }
}

# Redshift subnet group
resource "aws_redshift_subnet_group" "example" {
  name       = "example-redshift-subnet-group"
  subnet_ids = [aws_subnet.example1.id, aws_subnet.example2.id]

  tags = {
    Environment = "example"
    ManagedBy   = "terraform"
  }
}

# VPC and networking resources
resource "aws_vpc" "example" {
  cidr_block           = "10.0.0.0/16"
  enable_dns_hostnames = true

  tags = {
    Name        = "example-vpc"
    Environment = "example"
  }
}

resource "aws_subnet" "example1" {
  vpc_id            = aws_vpc.example.id
  cidr_block        = "10.0.1.0/24"
  availability_zone = "us-east-1a"

  tags = {
    Name = "example-subnet-1"
  }
}

resource "aws_subnet" "example2" {
  vpc_id            = aws_vpc.example.id
  cidr_block        = "10.0.2.0/24"
  availability_zone = "us-east-1b"

  tags = {
    Name = "example-subnet-2"
  }
}

# Security group for Redshift
resource "aws_security_group" "redshift" {
  name        = "example-redshift-sg"
  description = "Security group for Redshift cluster"
  vpc_id      = aws_vpc.example.id

  ingress {
    from_port   = 5439
    to_port     = 5439
    protocol    = "tcp"
    cidr_blocks = ["10.0.0.0/16"]
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }

  tags = {
    Environment = "example"
    ManagedBy   = "terraform"
  }
}

# IAM role for Redshift
resource "aws_iam_role" "redshift" {
  name = "example-redshift-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "redshift.amazonaws.com"
        }
      }
    ]
  })

  tags = {
    Environment = "example"
    ManagedBy   = "terraform"
  }
}

# Redshift cluster using the parameter group
resource "aws_redshift_cluster" "example" {
  cluster_identifier        = "example-redshift-cluster"
  database_name             = "exampledb"
  master_username           = "adminuser"
  master_password           = "ExamplePassword123!"
  node_type                 = "dc2.large"
  cluster_type              = "single-node"
  cluster_subnet_group_name = aws_redshift_subnet_group.example.name
  vpc_security_group_ids    = [aws_security_group.redshift.id]
  cluster_parameter_group_name = aws_redshift_parameter_group.example.name

  iam_roles = [aws_iam_role.redshift.arn]

  automated_snapshot_retention_period = 7
  preferred_maintenance_window        = "sun:03:00-sun:04:00"

  logging {
    enable               = true
    log_destination_type = "cloudwatch"
    log_exports          = ["connectionlog", "useractivitylog", "userlog"]
  }

  tags = {
    Environment = "example"
    ManagedBy   = "terraform"
  }
}

# Additional event subscription for cluster events
resource "aws_redshift_event_subscription" "cluster_events" {
  name          = "redshift-cluster-events"
  sns_topic_arn = aws_sns_topic.redshift_notifications.arn

  source_type = "cluster"
  source_ids  = [aws_redshift_cluster.example.id]

  event_categories = [
    "configuration",
    "management",
    "monitoring",
    "security",
  ]

  severity = "INFO"

  tags = {
    Environment = "example"
    ManagedBy   = "terraform"
  }
}
```

