terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

provider "aws" {
  region = "us-east-1"
}

# Source bucket for which inventory will be generated
resource "aws_s3_bucket" "source_bucket" {
  bucket_prefix = "source-bucket-"
}

resource "aws_s3_bucket_versioning" "source_bucket_versioning" {
  bucket = aws_s3_bucket.source_bucket.id
  versioning_configuration {
    status = "Enabled"
  }
}

# Destination bucket for storing inventory reports
resource "aws_s3_bucket" "inventory_bucket" {
  bucket_prefix = "inventory-bucket-"
}

resource "aws_s3_bucket_versioning" "inventory_bucket_versioning" {
  bucket = aws_s3_bucket.inventory_bucket.id
  versioning_configuration {
    status = "Enabled"
  }
}

# Block public access for both buckets
resource "aws_s3_bucket_public_access_block" "source_bucket" {
  bucket = aws_s3_bucket.source_bucket.id

  block_public_acls       = true
  block_public_policy     = true
  ignore_public_acls      = true
  restrict_public_buckets = true
}

resource "aws_s3_bucket_public_access_block" "inventory_bucket" {
  bucket = aws_s3_bucket.inventory_bucket.id

  block_public_acls       = true
  block_public_policy     = true
  ignore_public_acls      = true
  restrict_public_buckets = true
}

# Bucket policy to allow source bucket to put inventory reports in destination bucket
data "aws_iam_policy_document" "inventory_bucket_policy" {
  statement {
    sid    = "AllowInventoryReports"
    effect = "Allow"
    principals {
      type        = "Service"
      identifiers = ["s3.amazonaws.com"]
    }
    actions   = ["s3:PutObject"]
    resources = ["${aws_s3_bucket.inventory_bucket.arn}/*"]
    condition {
      test     = "StringEquals"
      variable = "aws:SourceAccount"
      values   = [data.aws_caller_identity.current.account_id]
    }
    condition {
      test     = "StringEquals"
      variable = "s3:x-amz-acl"
      values   = ["bucket-owner-full-control"]
    }
  }
}

resource "aws_s3_bucket_policy" "inventory_bucket" {
  bucket = aws_s3_bucket.inventory_bucket.id
  policy = data.aws_iam_policy_document.inventory_bucket_policy.json
}

data "aws_caller_identity" "current" {}

# S3 Inventory configuration for weekly CSV reports of all current object versions
resource "aws_s3_bucket_inventory" "source_bucket_inventory" {
  bucket = aws_s3_bucket.source_bucket.id
  name   = "weekly-csv-inventory"

  included_object_versions = "Current"

  schedule {
    frequency = "Weekly"
  }

  destination {
    bucket {
      format     = "CSV"
      bucket_arn = aws_s3_bucket.inventory_bucket.arn
      prefix     = "inventory-reports/"
    }
  }

  optional_fields = [
    "Size",
    "LastModifiedDate",
    "StorageClass",
    "ETag",
    "IsMultipartUploaded",
    "ReplicationStatus",
    "EncryptionStatus",
    "ObjectLockRetainUntilDate",
    "ObjectLockMode",
    "ObjectLockLegalHoldStatus",
    "IntelligentTieringAccessTier",
    "BucketKeyStatus",
    "ChecksumAlgorithm"
  ]

  depends_on = [aws_s3_bucket_policy.inventory_bucket]
}

# Output the bucket names
output "source_bucket_name" {
  value = aws_s3_bucket.source_bucket.bucket
}

output "inventory_bucket_name" {
  value = aws_s3_bucket.inventory_bucket.bucket
}

output "source_bucket_arn" {
  value = aws_s3_bucket.source_bucket.arn
}

output "inventory_bucket_arn" {
  value = aws_s3_bucket.inventory_bucket.arn
}
