```hcl
terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

provider "aws" {
  region = var.aws_region
}

variable "aws_region" {
  description = "AWS region"
  type        = string
  default     = "us-east-1"
}

variable "github_repo_url" {
  description = "GitHub repository URL containing student code"
  type        = string
}

variable "github_oauth_token" {
  description = "GitHub OAuth token for accessing private repositories"
  type        = string
  sensitive   = true
}

variable "autograder_project_name" {
  description = "Name of the CodeBuild project"
  type        = string
  default     = "cs-autograder"
}

variable "buildspec_file" {
  description = "Path to buildspec file in the repository"
  type        = string
  default     = "buildspec.yml"
}

# S3 bucket for storing build artifacts and autograder results
resource "aws_s3_bucket" "autograder_artifacts" {
  bucket = "${var.autograder_project_name}-artifacts-${random_string.bucket_suffix.result}"
}

resource "random_string" "bucket_suffix" {
  length  = 8
  special = false
  upper   = false
}

resource "aws_s3_bucket_versioning" "autograder_artifacts" {
  bucket = aws_s3_bucket.autograder_artifacts.id
  versioning_configuration {
    status = "Enabled"
  }
}

resource "aws_s3_bucket_lifecycle_configuration" "autograder_artifacts" {
  bucket = aws_s3_bucket.autograder_artifacts.id

  rule {
    id     = "expire-old-builds"
    status = "Enabled"

    expiration {
      days = 90
    }

    noncurrent_version_expiration {
      noncurrent_days = 30
    }
  }
}

# S3 bucket for storing autograder results
resource "aws_s3_bucket" "autograder_results" {
  bucket = "${var.autograder_project_name}-results-${random_string.bucket_suffix.result}"
}

resource "aws_s3_bucket_versioning" "autograder_results" {
  bucket = aws_s3_bucket.autograder_results.id
  versioning_configuration {
    status = "Enabled"
  }
}

# IAM Role for CodeBuild
resource "aws_iam_role" "codebuild_role" {
  name = "${var.autograder_project_name}-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "codebuild.amazonaws.com"
        }
      }
    ]
  })
}

resource "aws_iam_role_policy" "codebuild_policy" {
  name = "${var.autograder_project_name}-policy"
  role = aws_iam_role.codebuild_role.id

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect = "Allow"
        Action = [
          "logs:CreateLogGroup",
          "logs:CreateLogStream",
          "logs:PutLogEvents"
        ]
        Resource = "*"
      },
      {
        Effect = "Allow"
        Action = [
          "s3:GetObject",
          "s3:GetObjectVersion",
          "s3:PutObject"
        ]
        Resource = [
          aws_s3_bucket.autograder_artifacts.arn,
          "${aws_s3_bucket.autograder_artifacts.arn}/*",
          aws_s3_bucket.autograder_results.arn,
          "${aws_s3_bucket.autograder_results.arn}/*"
        ]
      }
    ]
  })
}

# CodeBuild project for autograder
resource "aws_codebuild_project" "autograder" {
  name          = var.autograder_project_name
  description   = "Auto-grader for CS class assignments"
  build_timeout = "60"
  service_role  = aws_iam_role.codebuild_role.arn

  artifacts {
    type = "S3"
    location = aws_s3_bucket.autograder_artifacts.bucket
    path = "/"
    packaging = "ZIP"
    name = "build-output.zip"
  }

  environment {
    compute_type                = "BUILD_GENERAL1_SMALL"
    image                       = "aws/codebuild/amazonlinux2-x86_64-standard:4.0"
    type                        = "LINUX_CONTAINER"
    image_pull_credentials_type = "CODEBUILD"
    privileged_mode             = true

    environment_variable {
      name  = "RESULTS_BUCKET"
      value = aws_s3_bucket.autograder_results.bucket
    }

    environment_variable {
      name  = "GRADING_ENV"
      value = "production"
    }
  }

  source {
    type            = "GITHUB"
    location        = var.github_repo_url
    git_clone_depth = 1
    buildspec       = var.buildspec_file

    auth {
      type     = "OAUTH"
      resource = aws_codebuild_source_credential.github_token.arn
    }
  }

  source_version = "main"

  logs_config {
    cloudwatch_logs {
      group_name  = "/aws/codebuild/${var.autograder_project_name}"
      stream_name = "build-log"
    }

    s3_logs {
      status   = "ENABLED"
      location = "${aws_s3_bucket.autograder_artifacts.id}/build-logs"
    }
  }

  tags = {
    Environment = "production"
    Project     = "cs-autograder"
  }
}

# GitHub OAuth token for CodeBuild
resource "aws_codebuild_source_credential" "github_token" {
  auth_type   = "PERSONAL_ACCESS_TOKEN"
  server_type = "GITHUB"
  token       = var.github_oauth_token
}

# CloudWatch Log Group for CodeBuild
resource "aws_cloudwatch_log_group" "autograder" {
  name              = "/aws/codebuild/${var.autograder_project_name}"
  retention_in_days = 30
}

# Webhook for automatic builds on GitHub push (optional - for continuous grading)
resource "aws_codebuild_webhook" "autograder" {
  project_name = aws_codebuild_project.autograder.name

  filter_group {
    filter {
      type    = "EVENT"
      pattern = "PUSH"
    }

    filter {
      type    = "HEAD_REF"
      pattern = "^refs/heads/main$"
    }
  }

  filter_group {
    filter {
      type    = "EVENT"
      pattern = "PULL_REQUEST_CREATED,PULL_REQUEST_UPDATED"
    }
  }
}

# Example buildspec.yml content (stored in SSM Parameter Store for reference)
resource "aws_ssm_parameter" "buildspec_example" {
  name  = "/${var.autograder_project_name}/buildspec-example"
  type  = "String"
  value = <<-EOT
    version: 0.2

    phases:
      pre_build:
        commands:
          - echo "Starting autograder for $$CODEBUILD_SOURCE_VERSION"
          - pip install -r requirements.txt || true

      build:
        commands:
          - echo "Running student code in isolated environment..."
          - python -m pytest tests/ --json-report --json-report-file=results.json || true
          - ./run_autograder.sh || true

      post_build:
        commands:
          - echo "Uploading results to S3..."
          - aws s3 cp results.json s3://$$RESULTS_BUCKET/$$CODEBUILD_BUILD_ID/results.json
          - aws s3 cp test-output/ s3://$$RESULTS_BUCKET/$$CODEBUILD_BUILD_ID/ --recursive || true
          - echo "Autograder complete"

    artifacts:
      files:
        - results.json
        - '**/*'
      base-directory: .
  EOT
}

# SNS Topic for autograder notifications
resource "aws_sns_topic" "autograder_notifications" {
  name = "${var.autograder_project_name}-notifications"
}

# EventBridge rule for build state changes
resource "aws_cloudwatch_event_rule" "build_events" {
  name        = "${var.autograder_project_name}-build-events"
  description = "Capture CodeBuild state changes"

  event_pattern = jsonencode({
    source      = ["aws.codebuild"]
    detail-type = ["CodeBuild Build State Change"]
    detail = {
      project-name = [var.autograder_project_name]
    }
  })
}

resource "aws_cloudwatch_event_target" "sns_target" {
  rule      = aws_cloudwatch_event_rule.build_events.name
  target_id = "SendToSNS"
  arn       = aws_sns_topic.autograder_notifications.arn
}

# Outputs
output "codebuild_project_name" {
  description = "Name of the CodeBuild project"
  value       = aws_codebuild_project.autograder.name
}

output "codebuild_project_arn" {
  description = "ARN of the CodeBuild project"
  value       = aws_codebuild_project.autograder.arn
}

output "artifacts_bucket" {
  description = "S3 bucket for build artifacts"
  value       = aws_s3_bucket.autograder_artifacts.bucket
}

output "results_bucket" {
  description = "S3 bucket for autograder results"
  value       = aws_s3_bucket.autograder_results.bucket
}

output "webhook_url" {
  description = "Webhook URL for GitHub integration"
  value       = aws_codebuild_webhook.autograder.payload_url
  sensitive   = true
}
```

