terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

provider "aws" {
  region = "us-east-1"
}

# Variables
variable "github_repository_url" {
  description = "GitHub repository URL containing student code"
  type        = string
  default     = "https://github.com/example/cs-class-repo"
}

variable "github_token_secret_arn" {
  description = "ARN of Secrets Manager secret containing GitHub personal access token"
  type        = string
}

# S3 Bucket for storing autograder results and artifacts
