# CloudWatch Log Group for CodeBuild
resource "aws_cloudwatch_log_group" "autograder" {
  name              = "/aws/codebuild/cs-autograder"
  retention_in_days = 30
}

# CodeBuild Project for Autograder
resource "aws_codebuild_project" "autograder" {
  name          = "cs-autograder"
  description   = "Autograder for CS class assignments"
  service_role  = aws_iam_role.codebuild_role.arn
  build_timeout = "60"

  artifacts {
    type = "S3"
    location = aws_s3_bucket.autograder_artifacts.bucket
    path = "build-output"
    namespace_type = "BUILD_ID"
    packaging = "ZIP"
  }

  environment {
    compute_type                = "BUILD_GENERAL1_SMALL"
    image                       = "aws/codebuild/amazonlinux2-x86_64-standard:4.0"
    type                        = "LINUX_CONTAINER"
    image_pull_credentials_type = "CODEBUILD"
    privileged_mode             = false

    environment_variable {
      name  = "RESULTS_BUCKET"
      value = aws_s3_bucket.autograder_results.bucket
    }

    environment_variable {
      name  = "STUDENT_ID"
      value = "placeholder"
      type  = "PLAINTEXT"
    }
  }

  source {
    type            = "GITHUB"
    location        = var.github_repository_url
    git_clone_depth = 1
    buildspec       = <<-EOT
      version: 0.2

      phases:
        pre_build:
          commands:
            - echo "Starting autograder for student: $STUDENT_ID"
            - pip install -r requirements.txt || true
        build:
          commands:
            - echo "Running tests..."
            - python -m pytest tests/ --json-report --json-report-file=results.json || true
            - python run_autograder.py || true
        post_build:
          commands:
            - echo "Uploading results to S3..."
            - |
              aws s3 cp results.json s3://$RESULTS_BUCKET/$STUDENT_ID/$(date +%Y%m%d-%H%M%S)-results.json || \n              echo '{"status": "completed", "timestamp": "'$(date -Iseconds)'"}' | \n              aws s3 cp - s3://$RESULTS_BUCKET/$STUDENT_ID/$(date +%Y%m%d-%H%M%S)-results.json
            - echo "Autograder complete"

      artifacts:
        files:
          - results.json
          - '**/*'
        discard-paths: no
    EOT
  }

  logs_config {
    cloudwatch_logs {
      group_name  = aws_cloudwatch_log_group.autograder.name
      stream_name = "autograder-logs"
    }
  }

  tags = {
    Purpose = "CS Autograder"
  }
}

# CodeBuild Webhook for automatic triggers (optional - triggers on push)
resource "aws_codebuild_webhook" "autograder" {
  project_name = aws_codebuild_project.autograder.name
  build_type   = "BUILD"

  filter_group {
    filter {
      type    = "EVENT"
      pattern = "PUSH"
    }
    filter {
      type    = "HEAD_REF"
      pattern = "^refs/heads/main$"
    }
  }
}

# Lambda function to trigger autograder runs (for API-based grading)
resource "aws_iam_role" "lambda_role" {
  name = "cs-autograder-lambda-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "lambda.amazonaws.com"
        }
      }
    ]
  })
}

resource "aws_iam_role_policy" "lambda_policy" {
  name = "cs-autograder-lambda-policy"
  role = aws_iam_role.lambda_role.id

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect = "Allow"
        Action = [
          "logs:CreateLogGroup",
          "logs:CreateLogStream",
          "logs:PutLogEvents"
        ]
        Resource = "arn:aws:logs:*:*:*"
      },
      {
        Effect = "Allow"
        Action = [
          "codebuild:StartBuild"
        ]
        Resource = aws_codebuild_project.autograder.arn
      }
    ]
  })
}

resource "aws_lambda_function" "trigger_autograder" {
  function_name = "cs-autograder-trigger"
  role          = aws_iam_role.lambda_role.arn
  handler       = "index.handler"
  runtime       = "python3.11"
  timeout       = 30

  filename         = data.archive_file.lambda_zip.output_path
  source_code_hash = data.archive_file.lambda_zip.output_base64sha256

  environment {
    variables = {
      CODEBUILD_PROJECT_NAME = aws_codebuild_project.autograder.name
    }
  }
}

data "archive_file" "lambda_zip" {
  type        = "zip"
  output_path = "${path.module}/lambda_function.zip"

  source {
    content  = <<-EOF
      import json
      import boto3
      import os

      codebuild = boto3.client('codebuild')

      def handler(event, context):
          student_id = event.get('student_id', 'unknown')
          assignment = event.get('assignment', 'default')

          response = codebuild.start_build(
              projectName=os.environ['CODEBUILD_PROJECT_NAME'],
              environmentVariablesOverride=[
                  {
                      'name': 'STUDENT_ID',
                      'value': student_id,
                      'type': 'PLAINTEXT'
                  },
                  {
                      'name': 'ASSIGNMENT',
                      'value': assignment,
                      'type': 'PLAINTEXT'
                  }
              ]
          )

          return {
              'statusCode': 200,
              'body': json.dumps({
                  'buildId': response['build']['id'],
                  'studentId': student_id
              })
          }
    EOF
    filename = "index.py"
  }
}

# API Gateway to expose Lambda function
resource "aws_api_gateway_rest_api" "autograder_api" {
  name        = "cs-autograder-api"
  description = "API to trigger autograder runs"

  endpoint_configuration {
    types = ["REGIONAL"]
  }
}

resource "aws_api_gateway_resource" "grade" {
  rest_api_id = aws_api_gateway_rest_api.autograder_api.id
  parent_id   = aws_api_gateway_rest_api.autograder_api.root_resource_id
  path_part   = "grade"
}

resource "aws_api_gateway_method" "grade_post" {
  rest_api_id   = aws_api_gateway_rest_api.autograder_api.id
  resource_id   = aws_api_gateway_resource.grade.id
  http_method   = "POST"
  authorization_type = "NONE"
}

resource "aws_api_gateway_integration" "lambda_integration" {
  rest_api_id = aws_api_gateway_rest_api.autograder_api.id
  resource_id = aws_api_gateway_resource.grade.id
  http_method = aws_api_gateway_method.grade_post.http_method

  integration_http_method = "POST"
  type                    = "AWS_PROXY"
  uri                     = aws_lambda_function.trigger_autograder.invoke_arn
}

resource "aws_lambda_permission" "api_gateway" {
  statement_id  = "AllowAPIGatewayInvoke"
  action        = "lambda:InvokeFunction"
  function_name = aws_lambda_function.trigger_autograder.function_name
  principal     = "apigateway.amazonaws.com"
  source_arn    = "${aws_api_gateway_rest_api.autograder_api.execution_arn}/*/*"
}

resource "aws_api_gateway_deployment" "autograder" {
  depends_on = [
    aws_api_gateway_integration.lambda_integration
  ]

  rest_api_id = aws_api_gateway_rest_api.autograder_api.id
  stage_name  = "prod"
}

# DynamoDB table for tracking grading jobs
resource "aws_dynamodb_table" "grading_jobs" {
  name         = "cs-autograder-jobs"
  billing_mode = "PAY_PER_REQUEST"
  hash_key     = "jobId"

  attribute {
    name = "jobId"
    type = "S"
  }

  attribute {
    name = "studentId"
    type = "S"
  }

  global_secondary_index {
    name            = "StudentIdIndex"
    hash_key        = "studentId"
    projection_type = "ALL"
  }

  point_in_time_recovery {
    enabled = true
  }

  tags = {
    Purpose = "CS Autograder"
  }
}

# IAM policy for CodeBuild to write to DynamoDB
resource "aws_iam_role_policy" "codebuild_dynamodb_policy" {
  name = "cs-autograder-dynamodb-policy"
  role = aws_iam_role.codebuild_role.id

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect = "Allow"
        Action = [
          "dynamodb:PutItem",
          "dynamodb:UpdateItem",
          "dynamodb:GetItem"
        ]
        Resource = aws_dynamodb_table.grading_jobs.arn
      }
    ]
  })
}

# Data sources
data "aws_caller_identity" "current" {}

# Outputs
output "results_bucket" {
  value = aws_s3_bucket.autograder_results.bucket
}

output "api_endpoint" {
  value = "${aws_api_gateway_deployment.autograder.invoke_url}/grade"
}

output "codebuild_project" {
  value = aws_codebuild_project.autograder.name
}

