}

# CodeBuild Project for running autograder
resource "aws_codebuild_project" "autograder" {
  name          = "autograder-project"
  description   = "Autograder for CS class"
  service_role  = aws_iam_role.codebuild_role.arn
  build_timeout = "60"

  artifacts {
    type = "NO_ARTIFACTS"
  }

  environment {
    compute_type                = "BUILD_GENERAL1_SMALL"
    image                       = "aws/codebuild/amazonlinux2-x86_64-standard:4.0"
    type                        = "LINUX_CONTAINER"
    image_pull_credentials_type = "CODEBUILD"
    privileged_mode             = false

    environment_variable {
      name  = "RESULTS_BUCKET"
      value = aws_s3_bucket.autograder_results.bucket
    }

    environment_variable {
      name  = "SUBMISSION_ID"
      value = "placeholder"
      type  = "PLAINTEXT"
    }
  }

  source {
    type            = "GITHUB"
    location        = var.github_repo_url
    git_clone_depth = 1
    buildspec       = <<-EOT
      version: 0.2
      phases:
        pre_build:
          commands:
            - echo "Starting autograder for submission $SUBMISSION_ID"
            - pip install -r requirements.txt || true
        build:
          commands:
            - echo "Running tests..."
            - python -m pytest tests/ --tb=short -v || true
            - python run_autograder.py || ./grade.sh || echo "No autograder script found"
        post_build:
          commands:
            - echo "Collecting results..."
            - |
              cat > results.json << 'RESULTSEOF'
              {
                "submission_id": "$SUBMISSION_ID",
                "timestamp": "$(date -u +%Y-%m-%dT%H:%M:%SZ)",
                "build_id": "$CODEBUILD_BUILD_ID",
                "status": "$CODEBUILD_BUILD_SUCCEEDING"
              }
              RESULTSEOF
            - aws s3 cp results.json s3://$RESULTS_BUCKET/submissions/$SUBMISSION_ID/results.json
            - |
              if [ -f test_output.txt ]; then
                aws s3 cp test_output.txt s3://$RESULTS_BUCKET/submissions/$SUBMISSION_ID/test_output.txt
              fi
            - |
              if [ -d test-reports ]; then
                aws s3 sync test-reports s3://$RESULTS_BUCKET/submissions/$SUBMISSION_ID/test-reports/
              fi
      artifacts:
        files:
          - results.json
          - test_output.txt
          - 'test-reports/**/*'
        discard-paths: no
    EOT
  }

  logs_config {
    cloudwatch_logs {
      group_name  = aws_cloudwatch_log_group.autograder.name
      stream_name = "autograder-build"
    }
  }

  tags = {
    Purpose = "CS Autograder"
  }
}

# GitHub webhook for CodeBuild (optional - enables automatic builds on push)
resource "aws_codebuild_webhook" "autograder" {
  project_name = aws_codebuild_project.autograder.name
  build_type   = "BUILD"

  filter_group {
    filter {
      type    = "EVENT"
      pattern = "PUSH, PULL_REQUEST_CREATED, PULL_REQUEST_UPDATED"
    }

    filter {
      type    = "HEAD_REF"
      pattern = "^refs/heads/main$|^refs/heads/master$"
    }
  }
}

# Secrets Manager for GitHub token
resource "aws_secretsmanager_secret" "github_token" {
  name        = "autograder/github-token"
  description = "GitHub token for accessing student repositories"
}

resource "aws_secretsmanager_secret_version" "github_token" {
  secret_id     = aws_secretsmanager_secret.github_token.id
  secret_string = var.github_token
}

# IAM policy to allow CodeBuild to read the secret
resource "aws_iam_role_policy" "codebuild_secrets_policy" {
  name = "autograder-secrets-policy"
  role = aws_iam_role.codebuild_role.id

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect = "Allow"
        Action = [
          "secretsmanager:GetSecretValue"
        ]
        Resource = aws_secretsmanager_secret.github_token.arn
      }
    ]
  })
}

# SNS Topic for autograder notifications
resource "aws_sns_topic" "autograder_notifications" {
  name = "autograder-notifications"
}

resource "aws_sns_topic_policy" "autograder_notifications" {
  arn = aws_sns_topic.autograder_notifications.arn

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Sid    = "AllowCodeBuildPublish"
        Effect = "Allow"
        Principal = {
          Service = "codebuild.amazonaws.com"
        }
        Action   = "SNS:Publish"
        Resource = aws_sns_topic.autograder_notifications.arn
      }
    ]
  })
}

# Lambda function to trigger autograder (for custom submission handling)
resource "aws_iam_role" "lambda_role" {
  name = "autograder-lambda-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "lambda.amazonaws.com"
        }
      }
    ]
  })
}

resource "aws_iam_role_policy_attachment" "lambda_basic" {
  role       = aws_iam_role.lambda_role.name
  policy_arn = "arn:aws:iam::aws:policy/service-role/AWSLambdaBasicExecutionRole"
}

resource "aws_iam_role_policy" "lambda_codebuild" {
  name = "autograder-lambda-codebuild-policy"
  role = aws_iam_role.lambda_role.id

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
