data "archive_file" "lambda_zip" {
  type        = "zip"
  output_path = "${path.module}/lambda_function.zip"

  source {
    content  = <<-EOF
      import json
      import boto3
      import os

      codebuild = boto3.client('codebuild')

      def handler(event, context):
          # Extract submission details from event
          # Event can come from API Gateway, S3, or direct invocation

          submission_id = event.get('submission_id', 'unknown')
          github_ref = event.get('github_ref', 'main')
          student_id = event.get('student_id', 'unknown')

          try:
              response = codebuild.start_build(
                  projectName=os.environ['CODEBUILD_PROJECT_NAME'],
                  environmentVariablesOverride=[
                      {
                          'name': 'SUBMISSION_ID',
                          'value': submission_id,
                          'type': 'PLAINTEXT'
                      },
                      {
                          'name': 'GITHUB_REF',
                          'value': github_ref,
                          'type': 'PLAINTEXT'
                      },
                      {
                          'name': 'STUDENT_ID',
                          'value': student_id,
                          'type': 'PLAINTEXT'
                      }
                  ]
              )

              return {
                  'statusCode': 200,
                  'body': json.dumps({
                      'message': 'Autograder started successfully',
                      'buildId': response['build']['id'],
                      'submissionId': submission_id
                  })
              }

          except Exception as e:
              return {
                  'statusCode': 500,
                  'body': json.dumps({
                      'message': f'Failed to start autograder: {str(e)}'
                  })
              }
      EOF
    filename = "index.py"
  }
}

