    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = []
  }

  tags = {
    Name = "autograder-vpc-endpoints-sg"
  }
}

# Security group for CodeBuild - no outbound internet access
resource "aws_security_group" "codebuild" {
  name_prefix = "autograder-codebuild-"
  vpc_id      = aws_vpc.autograder_vpc.id

  # No egress rules - completely isolated from internet

  tags = {
    Name = "autograder-codebuild-sg"
  }
}

data "aws_availability_zones" "available" {
  state = "available"
}

# S3 bucket for storing autograder results
resource "aws_s3_bucket" "autograder_results" {
  bucket_prefix = "autograder-results-"

  tags = {
    Name = "autograder-results"
  }
}

resource "aws_s3_bucket_versioning" "autograder_results" {
  bucket = aws_s3_bucket.autograder_results.id
  versioning_configuration {
    status = "Enabled"
  }
}

resource "aws_s3_bucket_server_side_encryption_configuration" "autograder_results" {
  bucket = aws_s3_bucket.autograder_results.id

  rule {
    apply_server_side_encryption_by_default {
      sse_algorithm = "AES256"
    }
  }
}

resource "aws_s3_bucket_public_access_block" "autograder_results" {
  bucket = aws_s3_bucket.autograder_results.id

  block_public_acls       = true
  block_public_policy     = true
  ignore_public_acls      = true
  restrict_public_buckets = true
}

# IAM role for CodeBuild
resource "aws_iam_role" "codebuild_role" {
  name = "autograder-codebuild-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "codebuild.amazonaws.com"
        }
      }
    ]
  })
}

resource "aws_iam_role_policy" "codebuild_policy" {
  name = "autograder-codebuild-policy"
  role = aws_iam_role.codebuild_role.id

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect = "Allow"
        Action = [
          "logs:CreateLogGroup",
          "logs:CreateLogStream",
          "logs:PutLogEvents"
        ]
        Resource = "*"
      },
      {
        Effect = "Allow"
        Action = [
          "s3:PutObject",
          "s3:GetObject",
          "s3:GetObjectVersion",
          "s3:GetBucketAcl",
          "s3:GetBucketLocation"
        ]
        Resource = [
          aws_s3_bucket.autograder_results.arn,
          "${aws_s3_bucket.autograder_results.arn}/*"
        ]
      },
      {
        Effect = "Allow"
        Action = [
          "ec2:CreateNetworkInterface",
          "ec2:DescribeDhcpOptions",
          "ec2:DescribeNetworkInterfaces",
          "ec2:DeleteNetworkInterface",
          "ec2:DescribeSubnets",
          "ec2:DescribeSecurityGroups",
          "ec2:DescribeVpcs"
        ]
        Resource = "*"
      }
    ]
  })
}

# CodeBuild project for autograder
resource "aws_codebuild_project" "autograder" {
  name          = "cs-autograder"
  description   = "Autograder for CS class student submissions"
  build_timeout = "60"
  service_role  = aws_iam_role.codebuild_role.arn

  artifacts {
    type     = "S3"
    location = aws_s3_bucket.autograder_results.bucket
    path     = "build-output/"
    name     = "autograder-results.zip"
  }

  environment {
    compute_type                = "BUILD_GENERAL1_SMALL"
    image                       = var.autograder_image
    type                        = "LINUX_CONTAINER"
    image_pull_credentials_type = "CODEBUILD"
    privileged_mode             = false

    # Environment variables for autograder script
    environment_variable {
      name  = "AUTOGRADER_MODE"
      value = "safe"
    }

    environment_variable {
      name  = "RESULTS_BUCKET"
      value = aws_s3_bucket.autograder_results.bucket
    }
  }

  source {
    type            = "GITHUB"
    location        = var.github_repo_url
    git_clone_depth = 1

    git_submodules_config {
      fetch_submodules = false
    }

    buildspec = <<-EOT
      version: 0.2
      phases:
        pre_build:
          commands:
            - echo "Starting autograder in isolated environment..."
            - echo "Network connectivity test (should fail for external sites):"
            - curl -v --max-time 5 https://google.com || echo "Network isolation confirmed - no external access"
        build:
          commands:
            - echo "Running student code in sandboxed environment..."
            - |
              # Run student code with strict resource limits
              timeout 300 ./run_autograder.sh || echo "Autograder completed or timed out"
            - echo "Collecting results..."
        post_build:
          commands:
            - echo "Autograder finished at $(date)"
            - ls -la results/ || echo "No results directory"
      artifacts:
        files:
          - results/**/*
        name: autograder-$(date +%Y%m%d-%H%M%S)
      EOT
  }

  vpc_config {
    vpc_id             = aws_vpc.autograder_vpc.id
    subnets            = [aws_subnet.autograder_private.id]
    security_group_ids = [aws_security_group.codebuild.id]
  }

  tags = {
    Name = "cs-autograder"
  }
}

# CloudWatch Log Group for CodeBuild logs
resource "aws_cloudwatch_log_group" "autograder" {
  name              = "/aws/codebuild/${aws_codebuild_project.autograder.name}"
  retention_in_days = 30

  tags = {
    Name = "autograder-logs"
  }
}

# Optional: EventBridge rule to trigger autograder on schedule or webhook
resource "aws_codebuild_webhook" "autograder" {
  project_name = aws_codebuild_project.autograder.name

  filter_group {
    filter {
      type    = "EVENT"
      pattern = "PUSH"
    }

    filter {
      type    = "HEAD_REF"
      pattern = "^refs/heads/main$"
    }
  }
}

# Outputs
output "autograder_results_bucket" {
  description = "S3 bucket for autograder results"
  value       = aws_s3_bucket.autograder_results.bucket
}

output "codebuild_project_name" {
  description = "CodeBuild project name"
  value       = aws_codebuild_project.autograder.name
}

output "vpc_id" {
  description = "VPC ID for the isolated autograder environment"
  value       = aws_vpc.autograder_vpc.id
}

output "private_subnet_id" {
  description = "Private subnet ID (no internet access)"
  value       = aws_subnet.autograder_private.id
}
