# CodeBuild Project
resource "aws_codebuild_project" "autograder" {
  name          = "${var.project_name}-project"
  description   = "Autograder for CS class - isolated environment"
  build_timeout = "60"
  service_role  = aws_iam_role.codebuild.arn

  artifacts {
    type = "S3"
    location = aws_s3_bucket.autograder.id
    path = "build-output/"
    packaging = "ZIP"
    name = "autograder-results.zip"
  }

  environment {
    compute_type                = "BUILD_GENERAL1_SMALL"
    image                       = "aws/codebuild/standard:5.0"
    type                        = "LINUX_CONTAINER"
    image_pull_credentials_type = "CODEBUILD"
    privileged_mode             = false

    # Environment variables for the build
    environment_variable {
      name  = "RESULTS_BUCKET"
      value = aws_s3_bucket.autograder.id
    }

    environment_variable {
      name  = "STUDENT_REPO_URL"
      value = var.github_repository_url
    }
  }

  source {
    type            = "GITHUB"
    location        = var.github_repository_url
    git_clone_depth = 1
    buildspec       = <<-EOT
      version: 0.2
      phases:
        pre_build:
          commands:
            - echo "Starting autograder in isolated environment..."
            - echo "Network connectivity test (should fail for external sites):"
            - curl -v --max-time 5 https://google.com || echo "External network blocked as expected"
        build:
          commands:
            - echo "Running student code in sandbox..."
            - mkdir -p /tmp/sandbox
            - cp -r $CODEBUILD_SRC_DIR/* /tmp/sandbox/
            - cd /tmp/sandbox
            # Run autograder script (customize as needed)
            - |
              if [ -f run_tests.sh ]; then
                chmod +x run_tests.sh
                timeout 300 ./run_tests.sh || echo "Tests completed or timed out"
              else
                echo "No run_tests.sh found, checking for other test files..."
                find . -name "*.py" -o -name "*.java" -o -name "*.c" | head -20
              fi
        post_build:
          commands:
            - echo "Preparing results..."
            - |
              cat > /tmp/results.json << 'RESULTSEOF'
              {
                "build_id": "$CODEBUILD_BUILD_ID",
                "start_time": "$CODEBUILD_START_TIME",
                "status": "completed",
                "sandboxed": true,
                "network_restricted": true
              }
              RESULTSEOF
            - cp /tmp/results.json $CODEBUILD_ARTIFACTS_PATH/results.json || true
            - echo "Results prepared for upload to S3"
      artifacts:
        files:
          - '**/*'
        base-directory: /tmp/sandbox
        discard-paths: no
      EOT
  }

  vpc_config {
    vpc_id             = aws_vpc.autograder.id
    subnets            = [aws_subnet.isolated.id]
    security_group_ids = [aws_security_group.codebuild.id]
  }

  logs_config {
    cloudwatch_logs {
      group_name  = aws_cloudwatch_log_group.codebuild.name
      stream_name = "autograder"
    }
  }

  # Disable concurrent builds for security
  concurrent_build_limit = 1

  tags = {
    Name = "${var.project_name}-project"
  }
}

# CloudWatch Log Group
resource "aws_cloudwatch_log_group" "codebuild" {
  name              = "/aws/codebuild/${var.project_name}"
  retention_in_days = 7

  tags = {
    Name = "${var.project_name}-logs"
  }
}

# Secrets Manager for GitHub token
resource "aws_secretsmanager_secret" "github_token" {
  name                    = "${var.project_name}/github-token"
  description             = "GitHub token for accessing student repositories"
  recovery_window_in_days = 7
}

resource "aws_secretsmanager_secret_version" "github_token" {
  secret_id     = aws_secretsmanager_secret.github_token.id
  secret_string = var.github_token
}

# CodeBuild Source Credential (for GitHub)
resource "aws_codebuild_source_credential" "github" {
  auth_type   = "PERSONAL_ACCESS_TOKEN"
  server_type = "GITHUB"
  token       = var.github_token
}

# S3 Bucket policy to restrict access
resource "aws_s3_bucket_policy" "autograder" {
  bucket = aws_s3_bucket.autograder.id

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Sid       = "DenyInsecureTransport"
        Effect    = "Deny"
        Principal = "*"
        Action    = "s3:*"
        Resource = [
          aws_s3_bucket.autograder.arn,
          "${aws_s3_bucket.autograder.arn}/*"
        ]
        Condition = {
          Bool = {
            "aws:SecureTransport" = "false"
          }
        }
      },
      {
        Sid    = "AllowCodeBuildAccess"
        Effect = "Allow"
        Principal = {
          AWS = aws_iam_role.codebuild.arn
        }
        Action = [
          "s3:GetObject",
          "s3:GetObjectVersion",
          "s3:PutObject",
          "s3:ListBucket"
        ]
        Resource = [
          aws_s3_bucket.autograder.arn,
          "${aws_s3_bucket.autograder.arn}/*"
        ]
      }
    ]
  })
}

# Network ACL for additional isolation
resource "aws_network_acl" "isolated" {
  vpc_id     = aws_vpc.autograder.id
  subnet_ids = [aws_subnet.isolated.id]

  # Deny all inbound traffic from internet
  egress {
    protocol   = "-1"
    rule_no    = 100
    action     = "deny"
    cidr_block = "0.0.0.0/0"
    from_port  = 0
    to_port    = 0
  }

  # Allow traffic to VPC endpoints (local VPC only)
  egress {
    protocol   = "tcp"
    rule_no    = 200
    action     = "allow"
    cidr_block = aws_vpc.autograder.cidr_block
    from_port  = 443
    to_port    = 443
  }

  # Deny all inbound from internet
  ingress {
    protocol   = "-1"
    rule_no    = 100
    action     = "deny"
    cidr_block = "0.0.0.0/0"
    from_port  = 0
    to_port    = 0
  }

  # Allow return traffic from VPC endpoints
  ingress {
    protocol   = "tcp"
    rule_no    = 200
    action     = "allow"
    cidr_block = aws_vpc.autograder.cidr_block
    from_port  = 1024
    to_port    = 65535
  }

  tags = {
    Name = "${var.project_name}-isolated-nacl"
  }
}

# Outputs
output "s3_bucket_name" {
  description = "Name of the S3 bucket for autograder results"
  value       = aws_s3_bucket.autograder.id
}

output "codebuild_project_name" {
  description = "Name of the CodeBuild project"
  value       = aws_codebuild_project.autograder.name
}

output "vpc_id" {
  description = "ID of the isolated VPC"
  value       = aws_vpc.autograder.id
}

output "isolated_subnet_id" {
  description = "ID of the isolated subnet (no internet access)"
  value       = aws_subnet.isolated.id
}

reference:
terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.75"
    }
  }

  required_version = "~> 1.9.8"
}

provider "aws" {
  region = "us-east-1"
  profile = "admin-1"

  assume_role {
    role_arn = "arn:aws:iam::590184057477:role/yicun-iac"
  }
}

resource "aws_s3_bucket" "artifact_bucket" {
  bucket_prefix = "artifact-bucket-"
}

resource "aws_codebuild_project" "autograder_build" {
  name         = "autograder_build"
  service_role = aws_iam_role.autograder_build_role.arn

  artifacts {
    type     = "S3"
    location = aws_s3_bucket.artifact_bucket.arn
    name     = "results.zip" # include this
  }

  environment { # arguments required, exact value not specified
    compute_type = "BUILD_GENERAL1_SMALL"
    image        = "aws/codebuild/standard:7.0-24.10.29"
    type         = "LINUX_CONTAINER"
  }

  source {
    type            = "GITHUB"
    git_clone_depth = 1 # good to have, not required
    location        = "github.com/source-location"
  }

  vpc_config {
    vpc_id             = aws_vpc.autograder_vpc.id
    subnets            = [aws_subnet.autograder_vpc_subnet.id]
    security_group_ids = [aws_security_group.autograder_vpc_securitygroup.id]
  }
}

resource "aws_vpc" "autograder_vpc" {
  cidr_block = "10.0.0.0/16" # extra value not specified
}

resource "aws_subnet" "autograder_vpc_subnet" {
  vpc_id     = aws_vpc.autograder_vpc.id
  cidr_block = "10.0.0.0/24" # include this
}

resource "aws_security_group" "autograder_vpc_securitygroup" {
  vpc_id = aws_vpc.autograder_vpc.id
}

resource "aws_iam_role" "autograder_build_role" {
  assume_role_policy = data.aws_iam_policy_document.autograder_build_policy_assume.json
}

data "aws_iam_policy_document" "autograder_build_policy_assume" {
  statement {
    actions = ["sts:AssumeRole"]

    principals {
      type        = "Service"
      identifiers = ["codebuild.amazonaws.com"]
    }
  }
}

data "aws_iam_policy_document" "autograder_build_policy" {
  statement {
    effect = "Allow"
    actions = [
      "ec2:DescribeSubnets",
      "ec2:DescribeSecurityGroups",
      "ec2:DescribeVpcs"
    ]
    resources = [
      "*"
    ]
  }

  statement {
    effect  = "Allow"
    actions = ["s3:*"]
    resources = [
      aws_s3_bucket.artifact_bucket.arn,
      "${aws_s3_bucket.artifact_bucket.arn}/*",
    ]
  }
}

resource "aws_iam_policy" "autograder_build_policy" {
  name        = "lambda_policy"
  description = "Grants permissions to Lambda to describe vpc, subnet, security group"

  policy = data.aws_iam_policy_document.autograder_build_policy.json
}

