terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

provider "aws" {
  region = var.aws_region
}

variable "aws_region" {
  description = "AWS region"
  type        = string
  default     = "us-east-1"
}

variable "project_name" {
  description = "Name of the autograder project"
  type        = string
  default     = "cs-autograder"
}

variable "github_repository_url" {
  description = "GitHub repository URL containing student code"
  type        = string
}

variable "github_token" {
  description = "GitHub personal access token"
  type        = string
  sensitive   = true
}

# VPC Configuration
resource "aws_vpc" "autograder" {
  cidr_block           = "10.0.0.0/16"
  enable_dns_hostnames = true
  enable_dns_support   = true

  tags = {
    Name = "${var.project_name}-vpc"
  }
}

# Private Subnet (no internet access)
resource "aws_subnet" "private" {
  vpc_id            = aws_vpc.autograder.id
  cidr_block        = "10.0.1.0/24"
  availability_zone = data.aws_availability_zones.available.names[0]

  tags = {
    Name = "${var.project_name}-private-subnet"
  }
}

# Isolated subnet for CodeBuild (no route table)
resource "aws_subnet" "isolated" {
  vpc_id            = aws_vpc.autograder.id
  cidr_block        = "10.0.2.0/24"
  availability_zone = data.aws_availability_zones.available.names[0]

  tags = {
    Name = "${var.project_name}-isolated-subnet"
  }
}

data "aws_availability_zones" "available" {
  state = "available"
}

# VPC Endpoints for AWS services (no internet required)
resource "aws_vpc_endpoint" "s3" {
  vpc_id       = aws_vpc.autograder.id
  service_name = "com.amazonaws.${var.aws_region}.s3"
  route_table_ids = [aws_route_table.isolated.id]

  tags = {
    Name = "${var.project_name}-s3-endpoint"
  }
}

resource "aws_vpc_endpoint" "cloudwatch_logs" {
  vpc_id              = aws_vpc.autograder.id
  service_name        = "com.amazonaws.${var.aws_region}.logs"
  vpc_endpoint_type   = "Interface"
  subnet_ids          = [aws_subnet.isolated.id]
  security_group_ids  = [aws_security_group.vpc_endpoints.id]
  private_dns_enabled = true

  tags = {
    Name = "${var.project_name}-cloudwatch-logs-endpoint"
  }
}

resource "aws_vpc_endpoint" "codebuild" {
  vpc_id              = aws_vpc.autograder.id
  service_name        = "com.amazonaws.${var.aws_region}.codebuild"
  vpc_endpoint_type   = "Interface"
  subnet_ids          = [aws_subnet.isolated.id]
  security_group_ids  = [aws_security_group.vpc_endpoints.id]
  private_dns_enabled = true

  tags = {
    Name = "${var.project_name}-codebuild-endpoint"
  }
}

# Route table for isolated subnet (only S3 via endpoint)
resource "aws_route_table" "isolated" {
  vpc_id = aws_vpc.autograder.id

  tags = {
    Name = "${var.project_name}-isolated-rt"
  }
}

resource "aws_route_table_association" "isolated" {
  subnet_id      = aws_subnet.isolated.id
  route_table_id = aws_route_table.isolated.id
}

# Security group for VPC endpoints
resource "aws_security_group" "vpc_endpoints" {
  name_prefix = "${var.project_name}-vpce-"
  vpc_id      = aws_vpc.autograder.id

  ingress {
    from_port   = 443
    to_port     = 443
    protocol    = "tcp"
    cidr_blocks = [aws_vpc.autograder.cidr_block]
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = []
  }

  tags = {
    Name = "${var.project_name}-vpce-sg"
  }
}

# Security group for CodeBuild (no outbound internet)
resource "aws_security_group" "codebuild" {
  name_prefix = "${var.project_name}-codebuild-"
  vpc_id      = aws_vpc.autograder.id

  egress {
    from_port       = 443
    to_port         = 443
    protocol        = "tcp"
    security_groups = [aws_security_group.vpc_endpoints.id]
    description     = "HTTPS to VPC endpoints only"
  }

  tags = {
    Name = "${var.project_name}-codebuild-sg"
  }
}

# S3 Bucket for build artifacts and results
resource "aws_s3_bucket" "autograder" {
  bucket_prefix = "${var.project_name}-"

  tags = {
    Name = "${var.project_name}-bucket"
  }
}

resource "aws_s3_bucket_versioning" "autograder" {
  bucket = aws_s3_bucket.autograder.id
  versioning_configuration {
    status = "Enabled"
  }
}

resource "aws_s3_bucket_server_side_encryption_configuration" "autograder" {
  bucket = aws_s3_bucket.autograder.id

  rule {
    apply_server_side_encryption_by_default {
      sse_algorithm = "AES256"
    }
  }
}

resource "aws_s3_bucket_public_access_block" "autograder" {
  bucket = aws_s3_bucket.autograder.id

  block_public_acls       = true
  block_public_policy     = true
  ignore_public_acls      = true
  restrict_public_buckets = true
}

# IAM Role for CodeBuild
resource "aws_iam_role" "codebuild" {
  name = "${var.project_name}-codebuild-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "codebuild.amazonaws.com"
        }
      }
    ]
  })
}

resource "aws_iam_role_policy" "codebuild" {
  name = "${var.project_name}-codebuild-policy"
  role = aws_iam_role.codebuild.id

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect = "Allow"
        Action = [
          "logs:CreateLogGroup",
          "logs:CreateLogStream",
          "logs:PutLogEvents"
        ]
        Resource = "*"
      },
      {
        Effect = "Allow"
        Action = [
          "s3:GetObject",
          "s3:GetObjectVersion",
          "s3:PutObject",
          "s3:ListBucket"
        ]
        Resource = [
          aws_s3_bucket.autograder.arn,
          "${aws_s3_bucket.autograder.arn}/*"
        ]
      },
      {
        Effect = "Allow"
        Action = [
          "codebuild:CreateReportGroup",
          "codebuild:CreateReport",
          "codebuild:UpdateReport",
          "codebuild:BatchPutTestCases",
          "codebuild:BatchPutCodeCoverages"
        ]
        Resource = "*"
      }
    ]
  })
}

# CodeBuild Project
resource "aws_codebuild_project" "autograder" {
  name          = "${var.project_name}-project"
  description   = "Autograder for CS class - isolated environment"
  build_timeout = "60"
  service_role  = aws_iam_role.codebuild.arn

  artifacts {
    type = "S3"
    location = aws_s3_bucket.autograder.id
    path = "build-output/"
    packaging = "ZIP"
    name = "autograder-results.zip"
  }

  environment {
    compute_type                = "BUILD_GENERAL1_SMALL"
    image                       = "aws/codebuild/standard:5.0"
    type                        = "LINUX_CONTAINER"
    image_pull_credentials_type = "CODEBUILD"
    privileged_mode             = false

    # Environment variables for the build
    environment_variable {
      name  = "RESULTS_BUCKET"
      value = aws_s3_bucket.autograder.id
    }

    environment_variable {
      name  = "STUDENT_REPO_URL"
      value = var.github_repository_url
    }
  }

  source {
    type            = "GITHUB"
    location        = var.github_repository_url
    git_clone_depth = 1
    buildspec       = <<-EOT
      version: 0.2
      phases:
        pre_build:
          commands:
            - echo "Starting autograder in isolated environment..."
            - echo "Network connectivity test (should fail for external sites):"
            - curl -v --max-time 5 https://google.com || echo "External network blocked as expected"
        build:
          commands:
            - echo "Running student code in sandbox..."
            - mkdir -p /tmp/sandbox
            - cp -r $CODEBUILD_SRC_DIR/* /tmp/sandbox/
            - cd /tmp/sandbox
            # Run autograder script (customize as needed)
            - |
              if [ -f run_tests.sh ]; then
                chmod +x run_tests.sh
                timeout 300 ./run_tests.sh || echo "Tests completed or timed out"
              else
                echo "No run_tests.sh found, checking for other test files..."
                find . -name "*.py" -o -name "*.java" -o -name "*.c" | head -20
              fi
        post_build:
          commands:
            - echo "Preparing results..."
            - |
              cat > /tmp/results.json << 'RESULTSEOF'
              {
                "build_id": "$CODEBUILD_BUILD_ID",
                "start_time": "$CODEBUILD_START_TIME",
                "status": "completed",
                "sandboxed": true,
                "network_restricted": true
              }
              RESULTSEOF
            - cp /tmp/results.json $CODEBUILD_ARTIFACTS_PATH/results.json || true
            - echo "Results prepared for upload to S3"
      artifacts:
        files:
          - '**/*'
        base-directory: /tmp/sandbox
        discard-paths: no
      EOT
  }

  vpc_config {
    vpc_id             = aws_vpc.autograder.id
    subnets            = [aws_subnet.isolated.id]
    security_group_ids = [aws_security_group.codebuild.id]
  }

  logs_config {
    cloudwatch_logs {
      group_name  = aws_cloudwatch_log_group.codebuild.name
      stream_name = "autograder"
    }
  }

  # Disable concurrent builds for security
  concurrent_build_limit = 1

  tags = {
    Name = "${var.project_name}-project"
  }
}

# CloudWatch Log Group
resource "aws_cloudwatch_log_group" "codebuild" {
  name              = "/aws/codebuild/${var.project_name}"
  retention_in_days = 7

  tags = {
    Name = "${var.project_name}-logs"
  }
}

# Secrets Manager for GitHub token
resource "aws_secretsmanager_secret" "github_token" {
  name                    = "${var.project_name}/github-token"
  description             = "GitHub token for accessing student repositories"
  recovery_window_in_days = 7
}

resource "aws_secretsmanager_secret_version" "github_token" {
  secret_id     = aws_secretsmanager_secret.github_token.id
  secret_string = var.github_token
}

# CodeBuild Source Credential (for GitHub)
resource "aws_codebuild_source_credential" "github" {
  auth_type   = "PERSONAL_ACCESS_TOKEN"
  server_type = "GITHUB"
  token       = var.github_token
}

# S3 Bucket policy to restrict access
resource "aws_s3_bucket_policy" "autograder" {
  bucket = aws_s3_bucket.autograder.id

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Sid       = "DenyInsecureTransport"
        Effect    = "Deny"
        Principal = "*"
        Action    = "s3:*"
        Resource = [
          aws_s3_bucket.autograder.arn,
          "${aws_s3_bucket.autograder.arn}/*"
        ]
        Condition = {
          Bool = {
            "aws:SecureTransport" = "false"
          }
        }
      },
      {
        Sid    = "AllowCodeBuildAccess"
        Effect = "Allow"
        Principal = {
          AWS = aws_iam_role.codebuild.arn
        }
        Action = [
          "s3:GetObject",
          "s3:GetObjectVersion",
          "s3:PutObject",
          "s3:ListBucket"
        ]
        Resource = [
          aws_s3_bucket.autograder.arn,
          "${aws_s3_bucket.autograder.arn}/*"
        ]
      }
    ]
  })
}

# Network ACL for additional isolation
resource "aws_network_acl" "isolated" {
  vpc_id     = aws_vpc.autograder.id
  subnet_ids = [aws_subnet.isolated.id]

  # Deny all inbound traffic from internet
  egress {
    protocol   = "-1"
    rule_no    = 100
    action     = "deny"
    cidr_block = "0.0.0.0/0"
    from_port  = 0
    to_port    = 0
  }

  # Allow traffic to VPC endpoints (local VPC only)
  egress {
    protocol   = "tcp"
    rule_no    = 200
    action     = "allow"
    cidr_block = aws_vpc.autograder.cidr_block
    from_port  = 443
    to_port    = 443
  }

  # Deny all inbound from internet
  ingress {
    protocol   = "-1"
    rule_no    = 100
    action     = "deny"
    cidr_block = "0.0.0.0/0"
    from_port  = 0
    to_port    = 0
  }

  # Allow return traffic from VPC endpoints
  ingress {
    protocol   = "tcp"
    rule_no    = 200
    action     = "allow"
    cidr_block = aws_vpc.autograder.cidr_block
    from_port  = 1024
    to_port    = 65535
  }

  tags = {
    Name = "${var.project_name}-isolated-nacl"
  }
}

# Outputs
output "s3_bucket_name" {
  description = "Name of the S3 bucket for autograder results"
  value       = aws_s3_bucket.autograder.id
}

output "codebuild_project_name" {
  description = "Name of the CodeBuild project"
  value       = aws_codebuild_project.autograder.name
}

output "vpc_id" {
  description = "ID of the isolated VPC"
  value       = aws_vpc.autograder.id
}

output "isolated_subnet_id" {
  description = "ID of the isolated subnet (no internet access)"
  value       = aws_subnet.isolated.id
}
