```hcl
terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

provider "aws" {
  region = var.aws_region
}

variable "aws_region" {
  description = "AWS region"
  type        = string
  default     = "us-east-1"
}

variable "github_repository_url" {
  description = "GitHub repository URL containing student code"
  type        = string
}

variable "github_token" {
  description = "GitHub personal access token"
  type        = string
  sensitive   = true
}

# VPC for isolated autograder environment
resource "aws_vpc" "autograder_vpc" {
  cidr_block           = "10.0.0.0/16"
  enable_dns_hostnames = true
  enable_dns_support   = true

  tags = {
    Name = "autograder-vpc"
  }
}

# Private subnet with no internet access
resource "aws_subnet" "autograder_subnet" {
  vpc_id                  = aws_vpc.autograder_vpc.id
  cidr_block              = "10.0.1.0/24"
  availability_zone       = "${var.aws_region}a"
  map_public_ip_on_launch = false

  tags = {
    Name = "autograder-private-subnet"
  }
}

# Security group with no inbound or outbound internet access
resource "aws_security_group" "autograder_sg" {
  name        = "autograder-security-group"
  description = "Security group for autograder - no internet access"
  vpc_id      = aws_vpc.autograder_vpc.id

  # No ingress rules - no inbound traffic allowed

  # No egress rules to internet - complete isolation

  tags = {
    Name = "autograder-sg"
  }
}

# VPC Endpoint for S3 to allow CodeBuild to access S3 without internet
resource "aws_vpc_endpoint" "s3_endpoint" {
  vpc_id            = aws_vpc.autograder_vpc.id
  service_name      = "com.amazonaws.${var.aws_region}.s3"
  vpc_endpoint_type = "Gateway"
  route_table_ids   = [aws_route_table.autograder_rt.id]

  tags = {
    Name = "autograder-s3-endpoint"
  }
}

# VPC Endpoint for CodeBuild logs (CloudWatch Logs)
resource "aws_vpc_endpoint" "cloudwatch_logs_endpoint" {
  vpc_id              = aws_vpc.autograder_vpc.id
  service_name        = "com.amazonaws.${var.aws_region}.logs"
  vpc_endpoint_type   = "Interface"
  subnet_ids          = [aws_subnet.autograder_subnet.id]
  security_group_ids  = [aws_security_group.vpc_endpoint_sg.id]
  private_dns_enabled = true

  tags = {
    Name = "autograder-cloudwatch-logs-endpoint"
  }
}

# VPC Endpoint for CodeBuild to communicate with AWS services
resource "aws_vpc_endpoint" "codebuild_endpoint" {
  vpc_id              = aws_vpc.autograder_vpc.id
  service_name        = "com.amazonaws.${var.aws_region}.codebuild"
  vpc_endpoint_type   = "Interface"
  subnet_ids          = [aws_subnet.autograder_subnet.id]
  security_group_ids  = [aws_security_group.vpc_endpoint_sg.id]
  private_dns_enabled = true

  tags = {
    Name = "autograder-codebuild-endpoint"
  }
}

# Security group for VPC endpoints
resource "aws_security_group" "vpc_endpoint_sg" {
  name        = "vpc-endpoint-sg"
  description = "Security group for VPC endpoints"
  vpc_id      = aws_vpc.autograder_vpc.id

  ingress {
    from_port   = 443
    to_port     = 443
    protocol    = "tcp"
    cidr_blocks = [aws_vpc.autograder_vpc.cidr_block]
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = [aws_vpc.autograder_vpc.cidr_block]
  }

  tags = {
    Name = "vpc-endpoint-sg"
  }
}

# Route table for private subnet
resource "aws_route_table" "autograder_rt" {
  vpc_id = aws_vpc.autograder_vpc.id

  tags = {
    Name = "autograder-route-table"
  }
}

# Associate route table with subnet
resource "aws_route_table_association" "autograder_rta" {
  subnet_id      = aws_subnet.autograder_subnet.id
  route_table_id = aws_route_table.autograder_rt.id
}

# S3 Bucket for storing autograder results
resource "aws_s3_bucket" "autograder_results" {
  bucket_prefix = "autograder-results-"

  tags = {
    Name = "autograder-results"
  }
}

# S3 Bucket versioning
resource "aws_s3_bucket_versioning" "autograder_results_versioning" {
  bucket = aws_s3_bucket.autograder_results.id
  versioning_configuration {
    status = "Enabled"
  }
}

# S3 Bucket encryption
resource "aws_s3_bucket_server_side_encryption_configuration" "autograder_results_encryption" {
  bucket = aws_s3_bucket.autograder_results.id

  rule {
    apply_server_side_encryption_by_default {
      sse_algorithm = "AES256"
    }
  }
}

# S3 Bucket public access block
resource "aws_s3_bucket_public_access_block" "autograder_results_public_block" {
  bucket = aws_s3_bucket.autograder_results.id

  block_public_acls       = true
  block_public_policy     = true
  ignore_public_acls      = true
  restrict_public_buckets = true
}

# IAM Role for CodeBuild
resource "aws_iam_role" "codebuild_role" {
  name = "autograder-codebuild-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "codebuild.amazonaws.com"
        }
      }
    ]
  })
}

# IAM Policy for CodeBuild
resource "aws_iam_role_policy" "codebuild_policy" {
  name = "autograder-codebuild-policy"
  role = aws_iam_role.codebuild_role.id

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect = "Allow"
        Action = [
          "logs:CreateLogGroup",
          "logs:CreateLogStream",
          "logs:PutLogEvents"
        ]
        Resource = "*"
      },
      {
        Effect = "Allow"
        Action = [
          "s3:PutObject",
          "s3:GetObject",
          "s3:GetObjectVersion",
          "s3:ListBucket"
        ]
        Resource = [
          aws_s3_bucket.autograder_results.arn,
          "${aws_s3_bucket.autograder_results.arn}/*"
        ]
      },
      {
        Effect = "Allow"
        Action = [
          "ec2:CreateNetworkInterface",
          "ec2:DescribeDhcpOptions",
          "ec2:DescribeNetworkInterfaces",
          "ec2:DeleteNetworkInterface",
          "ec2:DescribeSubnets",
          "ec2:DescribeSecurityGroups",
          "ec2:DescribeVpcs"
        ]
        Resource = "*"
      }
    ]
  })
}

# CloudWatch Log Group for CodeBuild
resource "aws_cloudwatch_log_group" "autograder_logs" {
  name              = "/aws/codebuild/autograder"
  retention_in_days = 7
}

# CodeBuild Project for autograder
resource "aws_codebuild_project" "autograder" {
  name          = "autograder-project"
  description   = "Autograder for CS class - runs student code in isolated environment"
  build_timeout = "30"
  service_role  = aws_iam_role.codebuild_role.arn

  artifacts {
    type = "NO_ARTIFACTS"
  }

  environment {
    compute_type                = "BUILD_GENERAL1_SMALL"
    image                       = "aws/codebuild/standard:5.0"
    type                        = "LINUX_CONTAINER"
    image_pull_credentials_type = "CODEBUILD"
    privileged_mode             = false

    environment_variable {
      name  = "RESULTS_BUCKET"
      value = aws_s3_bucket.autograder_results.bucket
    }

    environment_variable {
      name  = "STUDENT_REPO_URL"
      value = var.github_repository_url
    }
  }

  source {
    type            = "GITHUB"
    location        = var.github_repository_url
    git_clone_depth = 1
    buildspec       = <<-EOT
      version: 0.2

      phases:
        pre_build:
          commands:
            - echo "Starting autograder in isolated environment..."
            - echo "Internet access is disabled"
        build:
          commands:
            - echo "Running student code..."
            - # Add your autograder test commands here
            - # Example: python -m pytest tests/ --tb=short
            - echo "Tests completed"
        post_build:
          commands:
            - echo "Uploading results to S3..."
            - aws s3 cp results.json s3://$RESULTS_BUCKET/results/$(date +%Y%m%d-%H%M%S)-$CODEBUILD_BUILD_ID.json || echo "No results file found"
            - echo "Autograder complete"
      artifacts:
        files:
          - results.json
        discard-paths: no
    EOT
  }

  vpc_config {
    vpc_id             = aws_vpc.autograder_vpc.id
    subnets            = [aws_subnet.autograder_subnet.id]
    security_group_ids = [aws_security_group.autograder_sg.id]
  }

  logs_config {
    cloudwatch_logs {
      group_name  = aws_cloudwatch_log_group.autograder_logs.name
      stream_name = "autograder-build"
    }
  }

  tags = {
    Name = "autograder-project"
  }
}

# CodeBuild webhook for GitHub integration (optional - for automatic triggers)
resource "aws_codebuild_webhook" "autograder_webhook" {
  project_name = aws_codebuild_project.autograder.name
  build_type   = "BUILD"

  filter_group {
    filter {
      type    = "EVENT"
      pattern = "PUSH"
    }

    filter {
      type    = "HEAD_REF"
      pattern = "^refs/heads/main$"
    }
  }
}

# Secrets Manager for GitHub token
resource "aws_secretsmanager_secret" "github_token" {
  name                    = "autograder/github-token"
  description             = "GitHub token for autograder access"
  recovery_window_in_days = 7
}

resource "aws_secretsmanager_secret_version" "github_token" {
  secret_id     = aws_secretsmanager_secret.github_token.id
  secret_string = var.github_token
}

# GitHub credential for CodeBuild
resource "aws_codebuild_source_credential" "github_credential" {
  auth_type   = "PERSONAL_ACCESS_TOKEN"
  server_type = "GITHUB"
  token       = var.github_token
}

# Outputs
output "s3_bucket_name" {
  description = "Name of the S3 bucket for autograder results"
  value       = aws_s3_bucket.autograder_results.bucket
}

output "codebuild_project_name" {
  description = "Name of the CodeBuild project"
  value       = aws_codebuild_project.autograder.name
}

output "vpc_id" {
  description = "ID of the isolated VPC"
  value       = aws_vpc.autograder_vpc.id
}
```

