data "archive_file" "lambda_upload" {
  type        = "zip"
  output_path = "${path.module}/lambda_upload.zip"

  source {
    content  = <<-EOF
    const AWS = require('aws-sdk');
    const s3 = new AWS.S3();

    exports.handler = async (event) => {
      const bucketName = process.env.BUCKET_NAME;

      if (event.httpMethod === 'POST') {
        const body = JSON.parse(event.body);
        const imageData = Buffer.from(body.image, 'base64');
        const key = `cats/${Date.now()}-${body.filename || 'cat.jpg'}`;

        await s3.putObject({
          Bucket: bucketName,
          Key: key,
          Body: imageData,
          ContentType: body.contentType || 'image/jpeg'
        }).promise();

        return {
          statusCode: 200,
          headers: {
            'Access-Control-Allow-Origin': '*',
            'Access-Control-Allow-Headers': 'Content-Type',
            'Access-Control-Allow-Methods': 'OPTIONS,POST,GET'
          },
          body: JSON.stringify({ message: 'Cat picture uploaded!', key: key })
        };
      }

      return {
        statusCode: 400,
        headers: {
          'Access-Control-Allow-Origin': '*',
          'Access-Control-Allow-Headers': 'Content-Type',
          'Access-Control-Allow-Methods': 'OPTIONS,POST,GET'
        },
        body: JSON.stringify({ error: 'Invalid request' })
      };
    };
    EOF
    filename = "index.js"
  }
}

