data "archive_file" "lambda_list" {
  type        = "zip"
  output_path = "${path.module}/lambda_list.zip"

  source {
    content  = <<-EOF
    const AWS = require('aws-sdk');
    const s3 = new AWS.S3();

    exports.handler = async (event) => {
      const bucketName = process.env.BUCKET_NAME;

      try {
        const listResult = await s3.listObjectsV2({
          Bucket: bucketName,
          Prefix: 'cats/'
        }).promise();

        const pictures = (listResult.Contents || []).map(obj => ({
          key: obj.Key,
          lastModified: obj.LastModified,
          size: obj.Size,
          url: `https://${bucketName}.s3.amazonaws.com/${obj.Key}`
        }));

        return {
          statusCode: 200,
          headers: {
            'Access-Control-Allow-Origin': '*',
            'Access-Control-Allow-Headers': 'Content-Type',
            'Access-Control-Allow-Methods': 'OPTIONS,POST,GET'
          },
          body: JSON.stringify({ pictures: pictures, count: pictures.length })
        };
      } catch (error) {
        return {
          statusCode: 500,
          headers: {
            'Access-Control-Allow-Origin': '*',
            'Access-Control-Allow-Headers': 'Content-Type',
            'Access-Control-Allow-Methods': 'OPTIONS,POST,GET'
          },
          body: JSON.stringify({ error: error.message })
        };
      }
    };
    EOF
    filename = "index.js"
  }
}

