data "archive_file" "lambda_random" {
  type        = "zip"
  output_path = "${path.module}/lambda_random.zip"

  source {
    content  = <<-EOF
    const AWS = require('aws-sdk');
    const s3 = new AWS.S3();

    exports.handler = async (event) => {
      const bucketName = process.env.BUCKET_NAME;

      try {
        const listResult = await s3.listObjectsV2({
          Bucket: bucketName,
          Prefix: 'cats/'
        }).promise();

        if (!listResult.Contents || listResult.Contents.length === 0) {
          return {
            statusCode: 404,
            headers: {
              'Access-Control-Allow-Origin': '*',
              'Access-Control-Allow-Headers': 'Content-Type',
              'Access-Control-Allow-Methods': 'OPTIONS,POST,GET'
            },
            body: JSON.stringify({ error: 'No cat pictures found' })
          };
        }

        const randomIndex = Math.floor(Math.random() * listResult.Contents.length);
        const randomKey = listResult.Contents[randomIndex].Key;

        const url = s3.getSignedUrl('getObject', {
          Bucket: bucketName,
          Key: randomKey,
          Expires: 300
        });

        return {
          statusCode: 200,
          headers: {
            'Access-Control-Allow-Origin': '*',
            'Access-Control-Allow-Headers': 'Content-Type',
            'Access-Control-Allow-Methods': 'OPTIONS,POST,GET'
          },
          body: JSON.stringify({ 
            url: url,
            key: randomKey,
            publicUrl: `https://${bucketName}.s3.amazonaws.com/${randomKey}`
          })
        };
      } catch (error) {
        return {
          statusCode: 500,
          headers: {
            'Access-Control-Allow-Origin': '*',
            'Access-Control-Allow-Headers': 'Content-Type',
            'Access-Control-Allow-Methods': 'OPTIONS,POST,GET'
          },
          body: JSON.stringify({ error: error.message })
        };
      }
    };
    EOF
    filename = "index.js"
  }
}

