# Lambda function for uploading cat pictures
data "archive_file" "upload_lambda" {
  type        = "zip"
  output_path = "${path.module}/upload_lambda.zip"

  source {
    content  = <<-EOF
    import json
    import boto3
    import base64
    import uuid

    s3 = boto3.client('s3')
    BUCKET_NAME = '${aws_s3_bucket.cat_pictures.id}'

    def lambda_handler(event, context):
        try:
            body = json.loads(event.get('body', '{}'))
            image_data = body.get('image')
            filename = body.get('filename', f"{str(uuid.uuid4())}.jpg")

            if not image_data:
                return {
                    'statusCode': 400,
                    'headers': {'Access-Control-Allow-Origin': '*'},
                    'body': json.dumps({'error': 'No image data provided'})
                }

            # Decode base64 image
            image_bytes = base64.b64decode(image_data)

            # Upload to S3
            s3.put_object(
                Bucket=BUCKET_NAME,
                Key=f"uploads/{filename}",
                Body=image_bytes,
                ContentType='image/jpeg'
            )

            return {
                'statusCode': 200,
                'headers': {'Access-Control-Allow-Origin': '*'},
                'body': json.dumps({
                    'message': 'Cat picture uploaded successfully',
                    'filename': filename
                })
            }
        except Exception as e:
            return {
                'statusCode': 500,
                'headers': {'Access-Control-Allow-Origin': '*'},
                'body': json.dumps({'error': str(e)})
            }
    EOF
    filename = "index.py"
  }
}

resource "aws_lambda_function" "upload_cat" {
  function_name    = "upload-cat-picture"
  runtime          = "python3.11"
  handler          = "index.lambda_handler"
  role             = aws_iam_role.lambda_role.arn
  filename         = data.archive_file.upload_lambda.output_path
  source_code_hash = data.archive_file.upload_lambda.output_base64sha256
  timeout          = 10
}

# Lambda function for getting random cat pictures
data "archive_file" "get_lambda" {
  type        = "zip"
  output_path = "${path.module}/get_lambda.zip"

  source {
    content  = <<-EOF
    import json
    import boto3
    import random

    s3 = boto3.client('s3')
    BUCKET_NAME = '${aws_s3_bucket.cat_pictures.id}'

    def lambda_handler(event, context):
        try:
            # List all objects in uploads folder
            response = s3.list_objects_v2(
                Bucket=BUCKET_NAME,
                Prefix='uploads/'
            )

            objects = response.get('Contents', [])

            if len(objects) <= 1:  # Only the prefix itself
                return {
                    'statusCode': 404,
                    'headers': {'Access-Control-Allow-Origin': '*'},
                    'body': json.dumps({'error': 'No cat pictures available'})
                }

            # Filter out the prefix folder itself
            images = [obj for obj in objects if obj['Key'] != 'uploads/']

            if not images:
                return {
                    'statusCode': 404,
                    'headers': {'Access-Control-Allow-Origin': '*'},
                    'body': json.dumps({'error': 'No cat pictures available'})
                }

            # Select random image
            random_image = random.choice(images)
            image_key = random_image['Key']

            # Generate presigned URL
            url = s3.generate_presigned_url(
                'get_object',
                Params={
                    'Bucket': BUCKET_NAME,
                    'Key': image_key
                },
                ExpiresIn=3600
            )

            return {
                'statusCode': 200,
                'headers': {'Access-Control-Allow-Origin': '*'},
                'body': json.dumps({
                    'image_url': url,
                    'filename': image_key.split('/')[-1]
                })
            }
        except Exception as e:
            return {
                'statusCode': 500,
                'headers': {'Access-Control-Allow-Origin': '*'},
                'body': json.dumps({'error': str(e)})
            }
    EOF
    filename = "index.py"
  }
}

