data "archive_file" "lambda_get" {
  type        = "zip"
  output_path = "${path.module}/lambda_get.zip"

  source {
    content  = <<-EOF
import json
import boto3
import os

s3 = boto3.client('s3')
dynamodb = boto3.resource('dynamodb')
table = dynamodb.Table(os.environ['TABLE_NAME'])
bucket = os.environ['BUCKET_NAME']

def handler(event, context):
    cat_name = event.get('queryStringParameters', {}).get('name', 'unknown')

    # Get cat info from DynamoDB
    response = table.get_item(Key={'name': cat_name})
    cat_info = response.get('Item', {})

    # List pictures from S3
    try:
        s3_response = s3.list_objects_v2(
            Bucket=bucket,
            Prefix=f"{cat_name}/"
        )
        pictures = [obj['Key'] for obj in s3_response.get('Contents', [])]
    except:
        pictures = []

    return {
        'statusCode': 200,
        'headers': {
            'Content-Type': 'application/json'
        },
        'body': json.dumps({
            'cat': cat_info,
            'pictures': pictures
        })
    }
EOF
    filename = "index.py"
  }
}

