data "archive_file" "lambda_put" {
  type        = "zip"
  output_path = "${path.module}/lambda_put.zip"

  source {
    content  = <<-EOF
import json
import boto3
import os

dynamodb = boto3.resource('dynamodb')
table = dynamodb.Table(os.environ['TABLE_NAME'])

def handler(event, context):
    body = json.loads(event.get('body', '{}'))
    cat_name = body.get('name')

    if not cat_name:
        return {
            'statusCode': 400,
            'body': json.dumps({'error': 'Cat name is required'})
        }

    # Store cat info in DynamoDB
    item = {
        'name': cat_name,
        'breed': body.get('breed', 'unknown'),
        'age': body.get('age', 0)
    }

    table.put_item(Item=item)

    return {
        'statusCode': 201,
        'headers': {
            'Content-Type': 'application/json'
        },
        'body': json.dumps({
            'message': 'Cat created successfully',
            'cat': item
        })
    }
EOF
    filename = "index.py"
  }
}

