extracted_code:
terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

provider "aws" {
  region = "us-east-1"
}

# Data source for latest Amazon Linux 2 AMI
data "aws_ami" "amazon_linux_2" {
  most_recent = true
  owners      = ["amazon"]

  filter {
    name   = "name"
    values = ["amzn2-ami-hvm-*-x86_64-gp2"]
  }
}

# EC2 Key Pair
resource "tls_private_key" "ec2_key" {
  algorithm = "RSA"
  rsa_bits  = 4096
}

resource "aws_key_pair" "ec2_key_pair" {
  key_name   = "ec2-backup-key"
  public_key = tls_private_key.ec2_key.public_key_openssh
}

# Save private key locally (optional, for reference)
resource "local_file" "private_key" {
  content  = tls_private_key.ec2_key.private_key_pem
  filename = "${path.module}/ec2-backup-key.pem"
  file_permission = "0400"
}

# VPC and networking resources (required for EC2)
data "aws_vpc" "default" {
  default = true
}

data "aws_subnets" "default" {
  filter {
    name   = "vpc-id"
    values = [data.aws_vpc.default.id]
  }
}

# Security group for EC2
resource "aws_security_group" "ec2_sg" {
  name_prefix = "ec2-backup-sg"
  vpc_id      = data.aws_vpc.default.id

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }

  tags = {
    Name = "ec2-backup-sg"
  }
}

# IAM role for EC2 instance profile
resource "aws_iam_role" "ec2_role" {
  name = "ec2-backup-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "ec2.amazonaws.com"
        }
      }
    ]
  })
}

resource "aws_iam_role_policy_attachment" "ec2_ssm" {
  role       = aws_iam_role.ec2_role.name
  policy_arn = "arn:aws:iam::aws:policy/AmazonSSMManagedInstanceCore"
}

resource "aws_iam_instance_profile" "ec2_profile" {
  name = "ec2-backup-profile"
  role = aws_iam_role.ec2_role.name
}

# EC2 Instance
resource "aws_instance" "backup_instance" {
  ami                    = data.aws_ami.amazon_linux_2.id
  instance_type          = "t3.micro"
  key_name               = aws_key_pair.ec2_key_pair.key_name
  vpc_security_group_ids = [aws_security_group.ec2_sg.id]
  subnet_id              = data.aws_subnets.default.ids[0]
  iam_instance_profile   = aws_iam_instance_profile.ec2_profile.name

  root_block_device {
    volume_size           = 20
    volume_type           = "gp3"
    encrypted             = true
    delete_on_termination = true
    tags = {
      Name = "ec2-backup-root-volume"
    }
  }

  tags = {
    Name        = "backup-instance"
    BackupDaily = "true"
  }
}

# EBS volume for additional data (optional, to demonstrate backup)
resource "aws_ebs_volume" "data_volume" {
  availability_zone = aws_instance.backup_instance.availability_zone
  size              = 10
  type              = "gp3"
  encrypted         = true

  tags = {
    Name        = "ec2-data-volume"
    BackupDaily = "true"
  }
}

resource "aws_volume_attachment" "data_volume_attach" {
  device_name = "/dev/sdf"
  volume_id   = aws_ebs_volume.data_volume.id
  instance_id = aws_instance.backup_instance.id
}

# AWS Backup Vault
resource "aws_backup_vault" "daily_backup_vault" {
  name        = "daily-backup-vault"
  kms_key_arn = aws_kms_key.backup_key.arn

  tags = {
    Name = "daily-backup-vault"
  }
}

# KMS key for backup encryption
resource "aws_kms_key" "backup_key" {
  description             = "KMS key for backup encryption"
  deletion_window_in_days = 7
  enable_key_rotation     = true

  tags = {
    Name = "backup-encryption-key"
  }
}

resource "aws_kms_alias" "backup_key_alias" {
  name          = "alias/backup-key"
  target_key_id = aws_kms_key.backup_key.key_id
}

# IAM role for AWS Backup
resource "aws_iam_role" "backup_role" {
  name = "aws-backup-service-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "backup.amazonaws.com"
        }
      }
    ]
  })
}

resource "aws_iam_role_policy_attachment" "backup_policy" {
  role       = aws_iam_role.backup_role.name
  policy_arn = "arn:aws:iam::aws:policy/service-role/AWSBackupServiceRolePolicyForBackup"
}

resource "aws_iam_role_policy_attachment" "backup_restore_policy" {
  role       = aws_iam_role.backup_role.name
  policy_arn = "arn:aws:iam::aws:policy/service-role/AWSBackupServiceRolePolicyForRestores"
}

# AWS Backup Plan - Daily at midnight
resource "aws_backup_plan" "daily_midnight_backup" {
  name = "daily-midnight-backup-plan"

  rule {
    rule_name         = "daily-midnight-rule"
    target_vault_name = aws_backup_vault.daily_backup_vault.name
    schedule          = "cron(0 0 * * ? *)" # Every day at midnight UTC

    lifecycle {
      delete_after = 30 # Keep backups for 30 days
    }

    recovery_point_tags = {
      BackupType = "Daily"
      CreatedBy  = "AWS Backup"
    }
  }

  advanced_backup_setting {
    resource_type = "EC2"
    backup_options = {
      WindowsVSS = "disabled"
    }
  }

  tags = {
    Name = "daily-midnight-backup-plan"
  }
}

# AWS Backup Selection - Select EC2 instances by tag
resource "aws_backup_selection" "ec2_backup_selection" {
  iam_role_arn = aws_iam_role.backup_role.arn
  name         = "ec2-backup-selection"
  plan_id      = aws_backup_plan.daily_midnight_backup.id

  selection_tag {
    type  = "STRINGEQUALS"
    key   = "BackupDaily"
    value = "true"
  }

  resources = [
    aws_instance.backup_instance.arn,
    aws_ebs_volume.data_volume.arn
  ]
}

# Outputs
output "ec2_instance_id" {
  description = "ID of the created EC2 instance"
  value       = aws_instance.backup_instance.id
}

output "ec2_public_ip" {
  description = "Public IP of the EC2 instance"
  value       = aws_instance.backup_instance.public_ip
}

output "backup_vault_arn" {
  description = "ARN of the backup vault"
  value       = aws_backup_vault.daily_backup_vault.arn
}

output "backup_plan_id" {
  description = "ID of the backup plan"
  value       = aws_backup_plan.daily_midnight_backup.id
}

output "private_key_path" {
  description = "Path to the private key file"
  value       = local_file.private_key.filename
}

