provider "aws" {
  region = "us-east-1"
}

# IAM role for Lambda execution
resource "aws_iam_role" "lambda_role" {
  name = "eventbridge_lambda_role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "lambda.amazonaws.com"
        }
      }
    ]
  })
}

resource "aws_iam_role_policy_attachment" "lambda_basic_execution" {
  role       = aws_iam_role.lambda_role.name
  policy_arn = "arn:aws:iam::aws:policy/service-role/AWSLambdaBasicExecutionRole"
}

# Lambda function
resource "aws_lambda_function" "scheduled_function" {
  function_name = "daily-scheduled-function"
  role          = aws_iam_role.lambda_role.arn
  handler       = "index.handler"
  runtime       = "python3.11"
  timeout       = 60

  filename         = data.archive_file.lambda_zip.output_path
  source_code_hash = data.archive_file.lambda_zip.output_base64sha256
}

# Lambda deployment package
data "archive_file" "lambda_zip" {
  type        = "zip"
  output_path = "${path.module}/lambda.zip"

  source {
    content  = <<-EOF
import json

def handler(event, context):
    print("Lambda executed at 7 UTC daily")
    return {
        'statusCode': 200,
        'body': json.dumps('Hello from scheduled Lambda!')
    }
EOF
    filename = "index.py"
  }
}

# EventBridge rule for daily execution at 7 UTC
resource "aws_cloudwatch_event_rule" "daily_schedule" {
  name                = "daily-7-utc-schedule"
  description         = "Trigger Lambda every day at 7:00 UTC"
  schedule_expression = "cron(0 7 * * ? *)"
}

# EventBridge target (Lambda)
resource "aws_cloudwatch_event_target" "lambda_target" {
  rule      = aws_cloudwatch_event_rule.daily_schedule.name
  target_id = "LambdaTarget"
  arn       = aws_lambda_function.scheduled_function.arn
}

# Permission for EventBridge to invoke Lambda
resource "aws_lambda_permission" "allow_eventbridge" {
