  source {
    content  = <<EOF
import json
import boto3
import os

def lambda_handler(event, context):
    mediaconvert = boto3.client('mediaconvert', endpoint_url=os.environ['MEDIACONVERT_ENDPOINT'])

    for record in event['Records']:
        message = json.loads(record['Sns']['Message'])
        bucket = message['Records'][0]['s3']['bucket']['name']
        key = message['Records'][0]['s3']['object']['key']

        job_settings = {
            "Inputs": [{
                "FileInput": f"s3://{bucket}/{key}",
                "AudioSelectors": {
                    "Audio Selector 1": {
                        "DefaultSelection": "DEFAULT"
                    }
                }
            }],
            "OutputGroups": [
                {
                    "Name": "HLS",
                    "OutputGroupSettings": {
                        "Type": "HLS_GROUP_SETTINGS",
                        "HlsGroupSettings": {
                            "SegmentLength": 10,
                            "Destination": f"s3://{bucket}/output/hls/",
                            "MinSegmentLength": 2
                        }
                    },
                    "Outputs": [
                        {
                            "NameModifier": "_1080p",
                            "VideoDescription": {
                                "Width": 1920,
                                "Height": 1080,
                                "CodecSettings": {
                                    "Codec": "H_264",
                                    "H264Settings": {
                                        "RateControlMode": "VBR",
                                        "MaxBitrate": 5000000
                                    }
                                }
                            },
                            "AudioDescriptions": [{
                                "AudioSourceName": "Audio Selector 1",
                                "CodecSettings": {
                                    "Codec": "AAC",
                                    "AacSettings": {
                                        "Bitrate": 128000
                                    }
                                }
                            }],
                            "ContainerSettings": {
                                "Container": "M3U8"
                            }
                        },
                        {
                            "NameModifier": "_720p",
                            "VideoDescription": {
                                "Width": 1280,
                                "Height": 720,
                                "CodecSettings": {
                                    "Codec": "H_264",
                                    "H264Settings": {
                                        "RateControlMode": "VBR",
                                        "MaxBitrate": 2500000
                                    }
                                }
                            },
                            "AudioDescriptions": [{
                                "AudioSourceName": "Audio Selector 1",
                                "CodecSettings": {
                                    "Codec": "AAC",
                                    "AacSettings": {
                                        "Bitrate": 96000
                                    }
                                }
                            }],
                            "ContainerSettings": {
                                "Container": "M3U8"
                            }
                        },
                        {
                            "NameModifier": "_480p",
                            "VideoDescription": {
                                "Width": 854,
                                "Height": 480,
                                "CodecSettings": {
                                    "Codec": "H_264",
                                    "H264Settings": {
                                        "RateControlMode": "VBR",
                                        "MaxBitrate": 1000000
                                    }
                                }
                            },
                            "AudioDescriptions": [{
                                "AudioSourceName": "Audio Selector 1",
                                "CodecSettings": {
                                    "Codec": "AAC",
                                    "AacSettings": {
                                        "Bitrate": 64000
                                    }
                                }
                            }],
                            "ContainerSettings": {
                                "Container": "M3U8"
                            }
                        }
                    ]
                }
            ]
        }

        response = mediaconvert.create_job(
            Role=os.environ['MEDIACONVERT_ROLE'],
            Settings=job_settings
        )

    return {
        'statusCode': 200,
        'body': json.dumps('Job created successfully')
    }
EOF
    filename = "index.py"
  }
}

