data "archive_file" "lambda_edge_zip" {
  type        = "zip"
  output_path = "${path.module}/lambda_edge.zip"

  source {
    content  = <<EOF
exports.handler = async (event) => {
    const request = event.Records[0].cf.request;
    const headers = request.headers;

    // Add video-specific headers for adaptive bitrate streaming
    if (request.uri.match(/\.m3u8$/)) {
        headers['content-type'] = [{ key: 'Content-Type', value: 'application/vnd.apple.mpegurl' }];
    }
    if (request.uri.match(/\.mpd$/)) {
        headers['content-type'] = [{ key: 'Content-Type', value: 'application/dash+xml' }];
    }
    if (request.uri.match(/\.ts$/)) {
        headers['content-type'] = [{ key: 'Content-Type', value: 'video/MP2T' }];
    }
    if (request.uri.match(/\.m4s$/)) {
        headers['content-type'] = [{ key: 'Content-Type', value: 'video/iso.segment' }];
    }

    // Add CORS headers for video players
    headers['access-control-allow-origin'] = [{ key: 'Access-Control-Allow-Origin', value: '*' }];
    headers['access-control-allow-methods'] = [{ key: 'Access-Control-Allow-Methods', value: 'GET, HEAD, OPTIONS' }];

    // Add cache control for video segments
    if (request.uri.includes('/segments/')) {
        headers['cache-control'] = [{ key: 'Cache-Control', value: 'public, max-age=60' }];
    }

    return request;
};
EOF
    filename = "index.js"
  }
}

