    from_port   = 5432
    to_port     = 5432
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"]
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }

  tags = {
    Name = "Airbyte PostgreSQL Security Group"
  }
}

# RDS PostgreSQL 15 Instance
resource "aws_db_instance" "airbyte_postgres" {
  identifier = "airbyte-postgres-15"

  # Engine settings
  engine         = "postgres"
  engine_version = "15"
  instance_class = "db.t3.micro"

  # Storage settings (managed)
  allocated_storage     = 20
  max_allocated_storage = 100
  storage_type          = "gp3"
  storage_encrypted     = true

  # Credentials
  db_name  = "airbyte"
  username = var.db_username
  password = var.db_password

  # Network settings
  db_subnet_group_name   = aws_db_subnet_group.airbyte_postgres.name
  vpc_security_group_ids = [aws_security_group.airbyte_postgres.id]
  publicly_accessible    = true

  # Managed maintenance settings
  auto_minor_version_upgrade = true
  maintenance_window         = "Mon:03:00-Mon:04:00"

  # Backup settings (minimal for test environment)
  backup_retention_period = 1
  backup_window           = "02:00-03:00"

  # Monitoring (basic)
  monitoring_interval = 0

  # Deletion protection off for test environment
  deletion_protection = false

  # Skip final snapshot and apply immediately
  skip_final_snapshot    = true
  apply_immediately      = true

  # Performance Insights (disabled for cost)
  performance_insights_enabled = false

  tags = {
    Name        = "Airbyte PostgreSQL 15"
    Environment = "test"
    Purpose     = "Airbyte connector tests"
  }
}

output "rds_endpoint" {
  description = "RDS PostgreSQL endpoint"
  value       = aws_db_instance.airbyte_postgres.endpoint
}

output "rds_port" {
  description = "RDS PostgreSQL port"
  value       = aws_db_instance.airbyte_postgres.port
}

output "rds_database_name" {
  description = "RDS database name"
  value       = aws_db_instance.airbyte_postgres.db_name
}

