    description = "PostgreSQL access"
    from_port   = 5432
    to_port     = 5432
    protocol    = "tcp"
    cidr_blocks = var.allowed_cidr_blocks
  }

  egress {
    description = "Allow all outbound"
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }

  tags = {
    Name = "airbyte-postgres-sg"
  }
}

# RDS PostgreSQL 15 instance with managed settings
resource "aws_db_instance" "airbyte_postgres" {
  identifier = "airbyte-postgres-test"

  # Engine settings
  engine         = "postgres"
  engine_version = "15.7"
  instance_class = "db.t3.medium"

  # Storage settings
  allocated_storage     = 500
  max_allocated_storage = 1000
  storage_type          = "gp3"
  storage_encrypted     = true

  # Credentials
  db_name  = "airbyte"
  username = var.db_username
  password = var.db_password

  # Network settings
  db_subnet_group_name   = aws_db_subnet_group.airbyte_postgres.name
  vpc_security_group_ids = [aws_security_group.airbyte_postgres.id]
  publicly_accessible    = true

  # Managed maintenance settings
  auto_minor_version_upgrade = true
  maintenance_window         = "Mon:03:00-Mon:04:00"

  # Backup settings
  backup_retention_period = 7
  backup_window           = "02:00-03:00"

  # Monitoring and logging
  enabled_cloudwatch_logs_exports = ["postgresql", "upgrade"]
  monitoring_interval             = 60
  monitoring_role_arn             = aws_iam_role.rds_monitoring.arn

  # Performance Insights for troubleshooting test cases
  performance_insights_enabled          = true
  performance_insights_retention_period = 7

  # Deletion protection off for test environment flexibility
  deletion_protection = false
  skip_final_snapshot = true

  tags = {
    Name        = "airbyte-postgres-test"
    Environment = "test"
    Purpose     = "airbyte-connector-tests"
  }
}

# IAM Role for RDS Enhanced Monitoring
resource "aws_iam_role" "rds_monitoring" {
  name = "airbyte-rds-monitoring-role"

  assume_role_policy = jsonencode({
