provider "aws" {
  region = "us-east-1"
}

# Generate random password for RDS
resource "random_password" "rds_password" {
  length           = 16
  special          = true
  override_special = "!#$%&*()-_=+[]{}<>:?"
}

# Store password in Secrets Manager
resource "aws_secretsmanager_secret" "rds_password" {
  name        = "mysql-rds-password-${random_id.unique.hex}"
  description = "Password for MySQL RDS instance"
}

resource "aws_secretsmanager_secret_version" "rds_password" {
  secret_id     = aws_secretsmanager_secret.rds_password.id
  secret_string = random_password.rds_password.result
}

# Generate unique ID for resource naming
resource "random_id" "unique" {
  byte_length = 4
}

# Get available AZs
data "aws_availability_zones" "available" {
  state = "available"
}

# Create VPC
resource "aws_vpc" "main" {
  cidr_block           = "10.0.0.0/16"
  enable_dns_hostnames = true
  enable_dns_support   = true

  tags = {
    Name = "rds-vpc-${random_id.unique.hex}"
  }
}

# Create Internet Gateway
resource "aws_internet_gateway" "main" {
  vpc_id = aws_vpc.main.id

  tags = {
    Name = "rds-igw-${random_id.unique.hex}"
  }
}

# Create public subnet
resource "aws_subnet" "public" {
  vpc_id                  = aws_vpc.main.id
  cidr_block              = "10.0.1.0/24"
  availability_zone       = data.aws_availability_zones.available.names[0]
  map_public_ip_on_launch = true

  tags = {
    Name = "rds-public-subnet-${random_id.unique.hex}"
  }
}

# Create second public subnet for RDS (required for some configurations)
resource "aws_subnet" "public_2" {
  vpc_id                  = aws_vpc.main.id
  cidr_block              = "10.0.2.0/24"
  availability_zone       = data.aws_availability_zones.available.names[1]
  map_public_ip_on_launch = true

  tags = {
    Name = "rds-public-subnet-2-${random_id.unique.hex}"
  }
}

# Create route table
resource "aws_route_table" "public" {
  vpc_id = aws_vpc.main.id

  route {
    cidr_block = "0.0.0.0/0"
    gateway_id = aws_internet_gateway.main.id
  }

  tags = {
    Name = "rds-public-rt-${random_id.unique.hex}"
  }
}

# Associate route table with subnets
resource "aws_route_table_association" "public" {
  subnet_id      = aws_subnet.public.id
  route_table_id = aws_route_table.public.id
}

resource "aws_route_table_association" "public_2" {
  subnet_id      = aws_subnet.public_2.id
  route_table_id = aws_route_table.public.id
}

# Create DB subnet group
resource "aws_db_subnet_group" "main" {
  name       = "rds-subnet-group-${random_id.unique.hex}"
  subnet_ids = [aws_subnet.public.id, aws_subnet.public_2.id]

  tags = {
    Name = "RDS subnet group"
  }
}

# Create security group for public access
resource "aws_security_group" "rds_public" {
  name        = "rds-mysql-public-${random_id.unique.hex}"
  description = "Security group for MySQL RDS with public access"
  vpc_id      = aws_vpc.main.id

  # MySQL port
  ingress {
    description = "MySQL from anywhere"
    from_port   = 3306
    to_port     = 3306
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"]
  }

  egress {
    description = "Allow all outbound traffic"
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }

  tags = {
    Name = "rds-mysql-public"
  }
}

# Create RDS MySQL 5.7 instance
resource "aws_db_instance" "mysql" {
  identifier           = "mysql57-${random_id.unique.hex}"
  engine               = "mysql"
  engine_version       = "5.7"
  instance_class       = "db.t3.micro"
  allocated_storage    = 200
  storage_type         = "gp2"

  db_name  = "mydb"
  username = "admin"
  password = random_password.rds_password.result

  publicly_accessible    = true
  vpc_security_group_ids = [aws_security_group.rds_public.id]
  db_subnet_group_name   = aws_db_subnet_group.main.name

  # Backup and maintenance
  backup_retention_period = 7
  backup_window           = "03:00-04:00"
  maintenance_window      = "Mon:04:00-Mon:05:00"

  # Deletion protection (set to false for easier cleanup, set to true for production)
  deletion_protection = false
  skip_final_snapshot = true

  tags = {
    Name = "MySQL 5.7 Instance"
  }
}

# Outputs
output "rds_endpoint" {
  description = "RDS instance endpoint"
  value       = aws_db_instance.mysql.endpoint
}

output "rds_username" {
  description = "RDS master username"
  value       = aws_db_instance.mysql.username
}

output "rds_database_name" {
  description = "RDS database name"
  value       = aws_db_instance.mysql.db_name
}

output "rds_password_secret_arn" {
  description = "ARN of the secret containing the RDS password"
  value       = aws_secretsmanager_secret.rds_password.arn
  sensitive   = true
}

