terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

provider "aws" {
  region = "us-east-1"
}

# Create a Lightsail key pair (optional - for SSH access)
resource "aws_lightsail_key_pair" "example" {
  name = "example-key-pair"
}

# Create a Lightsail instance with user data
resource "aws_lightsail_instance" "example" {
  name              = "example-instance"
  availability_zone = "us-east-1a"
  blueprint_id      = "amazon_linux_2"
  bundle_id         = "nano_2_0"
  key_pair_name     = aws_lightsail_key_pair.example.name

  # User data script to run on instance launch
  user_data = <<-EOF
              #!/bin/bash
              yum update -y
              yum install -y httpd
              systemctl start httpd
              systemctl enable httpd
              echo "<h1>Hello from Terraform Lightsail!</h1>" > /var/www/html/index.html
              EOF

  tags = {
    Environment = "dev"
    ManagedBy   = "terraform"
  }
}

# Optional: Create a static IP and attach it to the instance
resource "aws_lightsail_static_ip" "example" {
  name = "example-static-ip"
}

resource "aws_lightsail_static_ip_attachment" "example" {
  static_ip_name = aws_lightsail_static_ip.example.name
  instance_name  = aws_lightsail_instance.example.name
}

# Optional: Create a firewall ( Lightsail instance firewall )
resource "aws_lightsail_instance_public_ports" "example" {
  instance_name = aws_lightsail_instance.example.name

  port_info {
    protocol  = "tcp"
    from_port = 22
    to_port   = 22
  }

  port_info {
    protocol  = "tcp"
    from_port = 80
    to_port   = 80
  }

  port_info {
    protocol  = "tcp"
    from_port = 443
    to_port   = 443
  }
}

# Outputs
output "instance_public_ip" {
  description = "The public IP address of the Lightsail instance"
  value       = aws_lightsail_static_ip.example.ip_address
}

output "instance_username" {
  description = "The username for connecting to the instance"
  value       = aws_lightsail_instance.example.username
}

output "ssh_command" {
  description = "SSH command to connect to the instance"
  value       = "ssh -i ${aws_lightsail_key_pair.example.name}.pem ${aws_lightsail_instance.example.username}@${aws_lightsail_static_ip.example.ip_address}"
}

