terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

provider "aws" {
  region = "us-east-1"
}

variable "instance_name" {
  default = "lightsail-multi-disk"
}

variable "availability_zone" {
  default = "us-east-1a"
}

resource "aws_lightsail_instance" "main" {
  name              = var.instance_name
  availability_zone = var.availability_zone
  blueprint_id      = "amazon_linux_2"
  bundle_id         = "nano_2_0"
  key_pair_name     = aws_lightsail_key_pair.main.name

  tags = {
    Name = var.instance_name
  }
}

resource "aws_lightsail_key_pair" "main" {
  name = "${var.instance_name}-key"
}

resource "aws_lightsail_disk" "data_disk_1" {
  name              = "${var.instance_name}-data-1"
  size_in_gb        = 32
  availability_zone = var.availability_zone
}

resource "aws_lightsail_disk" "data_disk_2" {
  name              = "${var.instance_name}-data-2"
  size_in_gb        = 64
  availability_zone = var.availability_zone
}

resource "aws_lightsail_disk" "backup_disk" {
  name              = "${var.instance_name}-backup"
  size_in_gb        = 128
  availability_zone = var.availability_zone
}

resource "aws_lightsail_disk_attachment" "data_disk_1_attach" {
  disk_name     = aws_lightsail_disk.data_disk_1.name
  instance_name = aws_lightsail_instance.main.name
  disk_path     = "/dev/xvdf"
}

resource "aws_lightsail_disk_attachment" "data_disk_2_attach" {
  disk_name     = aws_lightsail_disk.data_disk_2.name
  instance_name = aws_lightsail_instance.main.name
  disk_path     = "/dev/xvdg"
}

resource "aws_lightsail_disk_attachment" "backup_disk_attach" {
  disk_name     = aws_lightsail_disk.backup_disk.name
  instance_name = aws_lightsail_instance.main.name
  disk_path     = "/dev/xvdh"
}

output "instance_public_ip" {
  description = "Public IP of the Lightsail instance"
  value       = aws_lightsail_instance.main.public_ip_address
}

output "attached_disks" {
  description = "List of attached disk names"
  value = [
    aws_lightsail_disk.data_disk_1.name,
    aws_lightsail_disk.data_disk_2.name,
    aws_lightsail_disk.backup_disk.name,
  ]
}

