variable "aws_region" {
  description = "AWS region"
  type        = string
  default     = "us-east-1"
}

variable "instance_name" {
  description = "Name of the Lightsail instance"
  type        = string
  default     = "web-server"
}

variable "availability_zone" {
  description = "Availability zone for the instance"
  type        = string
  default     = "us-east-1a"
}

variable "bundle_id" {
  description = "Lightsail bundle ID (instance size)"
  type        = string
  default     = "nano_3_0"
}

variable "blueprint_id" {
  description = "Lightsail blueprint ID (OS/application)"
  type        = string
  default     = "amazon_linux_2023"
}

variable "distribution_name" {
  description = "Name of the Lightsail distribution"
  type        = string
  default     = "cdn-distribution"
}

provider "aws" {
  region = var.aws_region
}

# Create a Lightsail static IP for the instance
resource "aws_lightsail_static_ip" "web_static_ip" {
  name = "${var.instance_name}-static-ip"
}

# Create the Lightsail instance
resource "aws_lightsail_instance" "web" {
  name              = var.instance_name
  availability_zone = var.availability_zone
  blueprint_id      = var.blueprint_id
  bundle_id         = var.bundle_id

  user_data = <<-EOF
              #!/bin/bash
              yum update -y
              yum install -y httpd
              systemctl start httpd
              systemctl enable httpd
              echo "<h1>Hello from Lightsail Instance</h1>" > /var/www/html/index.html
              EOF

  tags = {
    Environment = "production"
    Name        = var.instance_name
  }
}

# Attach static IP to the instance
resource "aws_lightsail_static_ip_attachment" "web_ip_attach" {
  static_ip_name = aws_lightsail_static_ip.web_static_ip.name
  instance_name  = aws_lightsail_instance.web.name
}

# Create Lightsail Distribution (CDN) with instance as origin
resource "aws_lightsail_distribution" "cdn" {
  name         = var.distribution_name
  bundle_id    = "small_1_0"
  is_enabled   = true
  ip_address_type = "dualstack"

  origin {
    name        = aws_lightsail_instance.web.name
    region_name = var.aws_region
    protocol_policy = "http-only"

    response_timeout = 30
  }

  default_cache_behavior {
    behavior = "cache"
  }

  cache_behavior_settings {
    allowed_http_methods = "GET,HEAD,OPTIONS,PUT,PATCH,POST,DELETE"
    cached_http_methods  = "GET,HEAD"

    default_ttl = 86400
    max_ttl     = 31536000
    min_ttl     = 0

    forwarded_cookies {
      option = "none"
    }

    forwarded_headers {
      option = "none"
    }

    forwarded_query_strings {
      option = false
    }
  }

  tags = {
    Environment = "production"
    Name        = var.distribution_name
  }

  depends_on = [aws_lightsail_static_ip_attachment.web_ip_attach]
}

# Optional: Create a custom domain for the distribution
# resource "aws_lightsail_domain" "custom_domain" {
#   domain_name = "example.com"
# }

# Optional: Attach custom domain to distribution
# resource "aws_lightsail_domain_entry" "cdn_domain" {
#   domain_name = aws_lightsail_domain.custom_domain.domain_name
#   name        = "cdn"
#   type        = "CNAME"
#   target      = aws_lightsail_distribution.cdn.domain_name
# }

# Output the distribution details
output "instance_public_ip" {
  description = "Public IP of the Lightsail instance"
  value       = aws_lightsail_static_ip.web_static_ip.ip_address
}

output "distribution_domain_name" {
  description = "Domain name of the Lightsail distribution"
  value       = aws_lightsail_distribution.cdn.domain_name
}

output "distribution_url" {
  description = "URL to access the distribution"
  value       = "https://${aws_lightsail_distribution.cdn.domain_name}"
}

output "distribution_status" {
  description = "Status of the distribution"
  value       = aws_lightsail_distribution.cdn.status
}

