extracted_code:
# Terraform configuration for AWS long-term storage and backup
# Includes S3 with lifecycle policies, Glacier, and Backup services

terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

provider "aws" {
  region = var.aws_region
}

variable "aws_region" {
  description = "AWS region"
  type        = string
  default     = "us-east-1"
}

variable "environment" {
  description = "Environment name"
  type        = string
  default     = "production"
}

variable "project_name" {
  description = "Project name"
  type        = string
  default     = "long-term-storage"
}

# S3 Bucket for long-term data storage
resource "aws_s3_bucket" "long_term_storage" {
  bucket = "${var.project_name}-${var.environment}-${data.aws_caller_identity.current.account_id}"

  tags = {
    Name        = "Long Term Storage"
    Environment = var.environment
  }
}

data "aws_caller_identity" "current" {}

resource "aws_s3_bucket_versioning" "long_term_storage" {
  bucket = aws_s3_bucket.long_term_storage.id
  versioning_configuration {
    status = "Enabled"
  }
}

resource "aws_s3_bucket_server_side_encryption_configuration" "long_term_storage" {
  bucket = aws_s3_bucket.long_term_storage.id

  rule {
    apply_server_side_encryption_by_default {
      sse_algorithm = "aws:kms"
    }
    bucket_key_enabled = true
  }
}

resource "aws_s3_bucket_public_access_block" "long_term_storage" {
  bucket = aws_s3_bucket.long_term_storage.id

  block_public_acls       = true
  block_public_policy     = true
  ignore_public_acls      = true
  restrict_public_buckets = true
}

# Lifecycle policy for cost optimization
resource "aws_s3_bucket_lifecycle_configuration" "long_term_storage" {
  bucket = aws_s3_bucket.long_term_storage.id

  rule {
    id     = "transition-to-glacier"
    status = "Enabled"

    transition {
      days          = 90
      storage_class = "GLACIER"
    }

    transition {
      days          = 365
      storage_class = "DEEP_ARCHIVE"
    }

    noncurrent_version_transition {
      noncurrent_days = 30
      storage_class   = "GLACIER"
    }

    noncurrent_version_transition {
      noncurrent_days = 180
      storage_class   = "DEEP_ARCHIVE"
    }

    noncurrent_version_expiration {
      noncurrent_days = 2555 # 7 years
    }
  }

  rule {
    id     = "abort-incomplete-multipart-upload"
    status = "Enabled"

    abort_incomplete_multipart_upload {
      days_after_initiation = 7
    }
  }
}

# S3 Bucket for backup storage
resource "aws_s3_bucket" "backup_storage" {
  bucket = "${var.project_name}-backup-${var.environment}-${data.aws_caller_identity.current.account_id}"

  tags = {
    Name        = "Backup Storage"
    Environment = var.environment
  }
}

resource "aws_s3_bucket_versioning" "backup_storage" {
  bucket = aws_s3_bucket.backup_storage.id
  versioning_configuration {
    status = "Enabled"
  }
}

resource "aws_s3_bucket_server_side_encryption_configuration" "backup_storage" {
  bucket = aws_s3_bucket.backup_storage.id

  rule {
    apply_server_side_encryption_by_default {
      sse_algorithm = "aws:kms"
    }
    bucket_key_enabled = true
  }
}

resource "aws_s3_bucket_public_access_block" "backup_storage" {
  bucket = aws_s3_bucket.backup_storage.id

  block_public_acls       = true
  block_public_policy     = true
  ignore_public_acls      = true
  restrict_public_buckets = true
}

resource "aws_s3_bucket_lifecycle_configuration" "backup_storage" {
  bucket = aws_s3_bucket.backup_storage.id

  rule {
    id     = "backup-retention"
    status = "Enabled"

    transition {
      days          = 30
      storage_class = "STANDARD_IA"
    }

    transition {
      days          = 90
      storage_class = "GLACIER"
    }

    transition {
      days          = 365
      storage_class = "DEEP_ARCHIVE"
    }

    expiration {
      days = 2555 # 7 years retention
    }

    noncurrent_version_transition {
      noncurrent_days = 30
      storage_class   = "GLACIER"
    }

    noncurrent_version_expiration {
      noncurrent_days = 365
    }
  }
}

# Cross-region replication for disaster recovery
resource "aws_s3_bucket" "backup_replica" {
  provider = aws.replica
  bucket   = "${var.project_name}-backup-replica-${var.environment}-${data.aws_caller_identity.current.account_id}"

  tags = {
    Name        = "Backup Replica"
    Environment = var.environment
  }
}

provider "aws" {
  alias  = "replica"
  region = "us-west-2"
}

resource "aws_s3_bucket_versioning" "backup_replica" {
  provider = aws.replica
  bucket   = aws_s3_bucket.backup_replica.id
  versioning_configuration {
    status = "Enabled"
  }
}

resource "aws_s3_bucket_server_side_encryption_configuration" "backup_replica" {
  provider = aws.replica
  bucket   = aws_s3_bucket.backup_replica.id

  rule {
    apply_server_side_encryption_by_default {
      sse_algorithm = "aws:kms"
    }
    bucket_key_enabled = true
  }
}

resource "aws_s3_bucket_replication_configuration" "backup_replication" {
  role   = aws_iam_role.replication_role.arn
  bucket = aws_s3_bucket.backup_storage.id

  rule {
    id     = "replicate-backups"
    status = "Enabled"
    priority = 1

    filter {
      prefix = ""
    }

    delete_marker_replication {
      status = "Enabled"
    }

    destination {
      bucket        = aws_s3_bucket.backup_replica.arn
      storage_class = "GLACIER"

      replication_time {
        status  = "Enabled"
        minutes = 15
      }

      metrics {
        status  = "Enabled"
        minutes = 15
      }

      encryption_configuration {
        replica_kms_key_id = "arn:aws:kms:us-west-2:${data.aws_caller_identity.current.account_id}:alias/aws/s3"
      }
    }

    source_selection_criteria {
      replica_modifications {
        status = "Enabled"
      }
      sse_kms_encrypted_objects {
        status = "Enabled"
      }
    }
  }
}

# IAM role for replication
resource "aws_iam_role" "replication_role" {
  name = "s3-backup-replication-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "s3.amazonaws.com"
        }
      }
    ]
  })
}

resource "aws_iam_role_policy" "replication_policy" {
  name = "s3-backup-replication-policy"
  role = aws_iam_role.replication_role.id

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect = "Allow"
        Action = [
          "s3:GetReplicationConfiguration",
          "s3:ListBucket"
        ]
        Resource = [aws_s3_bucket.backup_storage.arn]
      },
      {
        Effect = "Allow"
        Action = [
          "s3:GetObjectVersionForReplication",
          "s3:GetObjectVersionAcl",
          "s3:GetObjectVersionTagging"
        ]
        Resource = ["${aws_s3_bucket.backup_storage.arn}/*"]
      },
      {
        Effect = "Allow"
        Action = [
          "s3:ReplicateObject",
          "s3:ReplicateDelete",
          "s3:ReplicateTags"
        ]
        Resource = ["${aws_s3_bucket.backup_replica.arn}/*"]
      },
      {
        Effect = "Allow"
        Action = [
          "kms:Decrypt"
        ]
        Resource = ["*"]
        Condition = {
          StringEquals = {
            "kms:ViaService" = "s3.${var.aws_region}.amazonaws.com"
            "kms:CallerAccount" = data.aws_caller_identity.current.account_id
          }
        }
      },
      {
        Effect = "Allow"
        Action = [
          "kms:Encrypt"
        ]
        Resource = ["*"]
        Condition = {
          StringEquals = {
            "kms:ViaService" = "s3.us-west-2.amazonaws.com"
            "kms:CallerAccount" = data.aws_caller_identity.current.account_id
          }
        }
      }
    ]
  })
}

# AWS Backup Vault
resource "aws_backup_vault" "main" {
  name        = "${var.project_name}-vault"
  kms_key_arn = aws_kms_key.backup_key.arn

  tags = {
    Name = "Main Backup Vault"
  }
}

resource "aws_kms_key" "backup_key" {
  description             = "KMS key for backup encryption"
  deletion_window_in_days = 30
  enable_key_rotation     = true

  tags = {
    Name = "Backup Encryption Key"
  }
}

resource "aws_kms_alias" "backup_key" {
  name          = "alias/${var.project_name}-backup-key"
  target_key_id = aws_kms_key.backup_key.key_id
}

# AWS Backup Plan
resource "aws_backup_plan" "main" {
  name = "${var.project_name}-backup-plan"

  rule {
    rule_name         = "daily-backup"
    target_vault_name = aws_backup_vault.main.name
    schedule          = "cron(0 5 ? * * *)"

    lifecycle {
      delete_after = 35
    }

    copy_action {
      destination_vault_arn = aws_backup_vault.secondary.arn

      lifecycle {
        delete_after = 120
      }
    }
  }

  rule {
    rule_name         = "monthly-backup"
    target_vault_name = aws_backup_vault.main.name
    schedule          = "cron(0 5 1 * ? *)"

    lifecycle {
      cold_storage_after = 30
      delete_after       = 2555
    }

    copy_action {
      destination_vault_arn = aws_backup_vault.secondary.arn

      lifecycle {
        cold_storage_after = 30
        delete_after       = 2555
      }
    }
  }

  rule {
    rule_name         = "yearly-backup"
    target_vault_name = aws_backup_vault.main.name
    schedule          = "cron(0 5 1 1 ? *)"

    lifecycle {
      cold_storage_after = 30
      delete_after       = 3653
    }

    copy_action {
      destination_vault_arn = aws_backup_vault.secondary.arn

      lifecycle {
        cold_storage_after = 30
        delete_after       = 3653
      }
    }
  }

  advanced_backup_setting {
    backup_options = {
      WindowsVSS = "enabled"
    }
    resource_type = "EC2"
  }
}

# Secondary backup vault in different region
resource "aws_backup_vault" "secondary" {
  provider    = aws.replica
  name        = "${var.project_name}-vault-secondary"
  kms_key_arn = aws_kms_key.backup_key_secondary.arn

  tags = {
    Name = "Secondary Backup Vault"
  }
}

resource "aws_kms_key" "backup_key_secondary" {
  provider                = aws.replica
  description             = "KMS key for secondary backup encryption"
  deletion_window_in_days = 30
  enable_key_rotation     = true

  tags = {
    Name = "Secondary Backup Encryption Key"
  }
}

# AWS Backup Selection
resource "aws_backup_selection" "main" {
  iam_role_arn = aws_iam_role.backup_role.arn
  name         = "${var.project_name}-selection"
  plan_id      = aws_backup_plan.main.id

  selection_tag {
    type  = "STRINGEQUALS"
    key   = "Backup"
    value = "true"
  }
}

# IAM Role for AWS Backup
resource "aws_iam_role" "backup_role" {
  name = "aws-backup-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "backup.amazonaws.com"
        }
      }
    ]
  })

  managed_policy_arns = [
    "arn:aws:iam::aws:policy/service-role/AWSBackupServiceRolePolicyForBackup",
    "arn:aws:iam::aws:policy/service-role/AWSBackupServiceRolePolicyForRestores"
  ]
}

# Glacier Vault for archive storage
resource "aws_glacier_vault" "archive" {
  name = "${var.project_name}-archive"

  tags = {
    Name = "Archive Vault"
  }
}

resource "aws_glacier_vault_lock" "archive" {
  vault_name = aws_glacier_vault.archive.name
  policy     = data.aws_iam_policy_document.glacier_lock.json

  complete_lock = false
}

data "aws_iam_policy_document" "glacier_lock" {
  statement {
    actions   = ["glacier:DeleteArchive"]
    effect    = "Deny"
    resources = [aws_glacier_vault.archive.arn]

    condition {
      test     = "NumericLessThanEquals"
      variable = "glacier:ArchiveAgeInDays"
      values   = ["365"]
    }

    principals {
      type        = "AWS"
      identifiers = ["*"]
    }
  }
}

# S3 Bucket policy for long-term storage
resource "aws_s3_bucket_policy" "long_term_storage" {
  bucket = aws_s3_bucket.long_term_storage.id
  policy = data.aws_iam_policy_document.long_term_storage.json
}

data "aws_iam_policy_document" "long_term_storage" {
  statement {
    sid    = "EnforceSSL"
    effect = "Deny"
    principals {
      type        = "*"
      identifiers = ["*"]
    }
    actions   = ["s3:*"]
    resources = [
      aws_s3_bucket.long_term_storage.arn,
      "${aws_s3_bucket.long_term_storage.arn}/*"
    ]
    condition {
      test     = "Bool"
      variable = "aws:SecureTransport"
      values   = ["false"]
    }
  }

  statement {
    sid    = "DenyUnencryptedUploads"
    effect = "Deny"
    principals {
      type        = "*"
      identifiers = ["*"]
    }
    actions   = ["s3:PutObject"]
    resources = ["${aws_s3_bucket.long_term_storage.arn}/*"]
    condition {
      test     = "StringNotEquals"
      variable = "s3:x-amz-server-side-encryption"
      values   = ["aws:kms"]
    }
  }
}

# Outputs
output "long_term_storage_bucket" {
  description = "Name of the long-term storage S3 bucket"
  value       = aws_s3_bucket.long_term_storage.id
}

output "backup_storage_bucket" {
  description = "Name of the backup storage S3 bucket"
  value       = aws_s3_bucket.backup_storage.id
}

output "backup_vault_arn" {
  description = "ARN of the main backup vault"
  value       = aws_backup_vault.main.arn
}

output "glacier_vault_arn" {
  description = "ARN of the Glacier archive vault"
  value       = aws_glacier_vault.archive.arn
}

