}

# IAM Role for Data Lifecycle Manager
resource "aws_iam_role" "dlm_lifecycle_role" {
  name = "dlm-lifecycle-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "dlm.amazonaws.com"
        }
      }
    ]
  })
}

# IAM Policy for Data Lifecycle Manager
resource "aws_iam_role_policy" "dlm_lifecycle" {
  name = "dlm-lifecycle-policy"
  role = aws_iam_role.dlm_lifecycle_role.id

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect = "Allow"
        Action = [
          "ec2:CreateSnapshot",
          "ec2:CreateSnapshots",
          "ec2:DeleteSnapshot",
          "ec2:DescribeInstances",
          "ec2:DescribeVolumes",
          "ec2:DescribeSnapshots"
        ]
        Resource = "*"
      },
      {
        Effect = "Allow"
        Action = [
          "ec2:CreateTags"
        ]
        Resource = "arn:aws:ec2:*::snapshot/*"
      }
    ]
  })
}

# Data Lifecycle Manager Policy for EBS snapshots with cross-region copy to Glacier
resource "aws_dlm_lifecycle_policy" "example" {
  description        = "DLM policy for EBS snapshots with Glacier archiving"
  execution_role_arn = aws_iam_role.dlm_lifecycle_role.arn
  state              = "ENABLED"

  policy_details {
    resource_types = ["VOLUME"]

    schedule {
      name = "Daily snapshots with Glacier archiving"

      create_rule {
        interval      = 24
        interval_unit = "HOURS"
        times         = ["03:00"]
      }

      retain_rule {
        count = 7
      }

      tags_to_add = {
        SnapshotCreator = "DLM"
      }

      copy_tags = true

      # Cross-region copy to Glacier vault (via S3 and S3 Glacier integration)
      cross_region_copy_rule {
        target_region = "us-west-2"
        encrypted     = true

        retain_rule {
          interval      = 1
          interval_unit = "MONTHS"
        }
      }
    }

    target_tags = {
      Backup = "true"
    }
  }
}

# Alternative: DLM Policy for EBS direct to Archive tier (using EBS direct APIs)
resource "aws_dlm_lifecycle_policy" "ebs_archive" {
  description        = "DLM policy for EBS snapshots with archive tier"
  execution_role_arn = aws_iam_role.dlm_lifecycle_role.arn
  state              = "ENABLED"

  policy_details {
    resource_types = ["VOLUME"]

    schedule {
      name = "Daily snapshots with archive tier"

      create_rule {
        interval      = 24
        interval_unit = "HOURS"
        times         = ["04:00"]
      }

      retain_rule {
        count = 5
      }

      # Archive rule to move snapshots to archive tier
      archive_rule {
        retain_rule {
          archive_retention {
            retention_archive_tier {
              count = 90
              interval = 1
              interval_unit = "DAYS"
            }
          }
        }
      }

      tags_to_add = {
        SnapshotCreator = "DLM-Archive"
      }

      copy_tags = true
    }

    target_tags = {
      ArchiveBackup = "true"
    }
  }
}

# S3 Bucket for intermediate storage before Glacier (common pattern)
resource "aws_s3_bucket" "dlm_backup" {
  bucket = "dlm-backup-bucket-${data.aws_caller_identity.current.account_id}-${data.aws_region.current.name}"
}

resource "aws_s3_bucket_lifecycle_configuration" "dlm_backup" {
  bucket = aws_s3_bucket.dlm_backup.id

  rule {
    id     = "transition-to-glacier"
    status = "Enabled"

    transition {
      days          = 0
      storage_class = "GLACIER"
    }

    expiration {
      days = 365
    }
  }
}

# S3 Bucket Policy to allow DLM access
resource "aws_s3_bucket_policy" "dlm_backup" {
  bucket = aws_s3_bucket.dlm_backup.id
  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Sid    = "AllowDLM"
        Effect = "Allow"
        Principal = {
          Service = "dlm.amazonaws.com"
        }
        Action = [
          "s3:PutObject",
          "s3:GetObject",
          "s3:DeleteObject"
        ]
        Resource = "${aws_s3_bucket.dlm_backup.arn}/*"
      }
    ]
  })
}

