provider "aws" {
  region = "us-east-1"
}

# SNS Topic for Glacier Vault Notifications
resource "aws_sns_topic" "glacier_vault_notifications" {
  name = "glacier-vault-notifications"

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Sid    = "GlacierPublish"
        Effect = "Allow"
        Principal = {
          Service = "glacier.amazonaws.com"
        }
        Action   = "SNS:Publish"
        Resource = "arn:aws:sns:*:*:glacier-vault-notifications"
        Condition = {
          StringEquals = {
            "AWS:SourceOwner" = data.aws_caller_identity.current.account_id
          }
        }
      }
    ]
  })
}

# SQS Queue for archiving notifications (optional - for testing)
resource "aws_sqs_queue" "glacier_notifications" {
  name = "glacier-vault-notifications-queue"
}

# SQS Queue Policy to allow SNS to send messages
resource "aws_sqs_queue_policy" "glacier_notifications" {
  queue_url = aws_sqs_queue.glacier_notifications.id

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect = "Allow"
        Principal = {
          Service = "sns.amazonaws.com"
        }
        Action   = "sqs:SendMessage"
        Resource = aws_sqs_queue.glacier_notifications.arn
        Condition = {
          ArnEquals = {
            "aws:SourceArn" = aws_sns_topic.glacier_vault_notifications.arn
          }
        }
      }
    ]
  })
}

# SNS Topic Subscription to SQS
resource "aws_sns_topic_subscription" "glacier_to_sqs" {
  topic_arn = aws_sns_topic.glacier_vault_notifications.arn
  protocol  = "sqs"
  endpoint  = aws_sqs_queue.glacier_notifications.arn
}

# S3 Glacier Vault
resource "aws_glacier_vault" "main" {
  name = "my-archive-vault"

  notification {
    sns_topic = aws_sns_topic.glacier_vault_notifications.arn
    events    = ["ArchiveRetrievalCompleted", "InventoryRetrievalCompleted"]
  }

  tags = {
    Name        = "My Archive Vault"
    Environment = "Production"
  }
}

# Glacier Vault Access Policy (optional - for cross-account access)
resource "aws_glacier_vault_lock" "main" {
  vault_name = aws_glacier_vault.main.name

  complete_lock = false

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Sid    = "DenyDeletion"
        Effect = "Deny"
        Principal = {
          AWS = "*"
        }
        Action   = "glacier:DeleteArchive"
        Resource = aws_glacier_vault.main.arn
        Condition = {
          NumericLessThan = {
            "glacier:ArchiveAgeInDays" = "365"
          }
        }
      }
    ]
  })
}

# Data source for current account ID
data "aws_caller_identity" "current" {}

# Outputs
output "vault_arn" {
  description = "The ARN of the Glacier vault"
  value       = aws_glacier_vault.main.arn
}

output "vault_location" {
  description = "The URI of the Glacier vault"
  value       = aws_glacier_vault.main.location
}

output "sns_topic_arn" {
  description = "The ARN of the SNS topic for Glacier notifications"
  value       = aws_sns_topic.glacier_vault_notifications.arn
}

output "sqs_queue_url" {
  description = "The URL of the SQS queue for Glacier notifications"
  value       = aws_sqs_queue.glacier_notifications.url
}

