```hcl
# Provider configuration
terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

provider "aws" {
  region = var.aws_region
}

# Variables
variable "aws_region" {
  description = "AWS region"
  type        = string
  default     = "us-east-1"
}

variable "vpc_id" {
  description = "VPC ID for the NLB"
  type        = string
}

variable "subnet_ids" {
  description = "List of subnet IDs for the NLB"
  type        = list(string)
}

variable "nlb_name" {
  description = "Name of the Network Load Balancer"
  type        = string
  default     = "my-nlb"
}

variable "enable_cross_zone_load_balancing" {
  description = "Enable cross-zone load balancing"
  type        = bool
  default     = true
}

variable "enable_deletion_protection" {
  description = "Enable deletion protection"
  type        = bool
  default     = false
}

variable "target_port" {
  description = "Port on which targets receive traffic"
  type        = number
  default     = 80
}

variable "listener_port" {
  description = "Port on which the NLB listens"
  type        = number
  default     = 80
}

variable "health_check_port" {
  description = "Port to use for health checks"
  type        = string
  default     = "traffic-port"
}

variable "health_check_protocol" {
  description = "Protocol to use for health checks"
  type        = string
  default     = "TCP"
}

# Data source to get VPC details
data "aws_vpc" "selected" {
  id = var.vpc_id
}

# Network Load Balancer
resource "aws_lb" "nlb" {
  name               = var.nlb_name
  internal           = false
  load_balancer_type = "network"
  subnets            = var.subnet_ids

  enable_cross_zone_load_balancing = var.enable_cross_zone_load_balancing
  enable_deletion_protection       = var.enable_deletion_protection

  tags = {
    Name        = var.nlb_name
    Environment = "production"
    ManagedBy   = "terraform"
  }
}

# Target Group
resource "aws_lb_target_group" "nlb_tg" {
  name     = "${var.nlb_name}-tg"
  port     = var.target_port
  protocol = "TCP"
  vpc_id   = var.vpc_id

  health_check {
    enabled             = true
    healthy_threshold   = 3
    interval            = 30
    port                = var.health_check_port
    protocol            = var.health_check_protocol
    unhealthy_threshold = 3
  }

  tags = {
    Name        = "${var.nlb_name}-tg"
    Environment = "production"
    ManagedBy   = "terraform"
  }

  lifecycle {
    create_before_destroy = true
  }
}

# NLB Listener
resource "aws_lb_listener" "nlb_listener" {
  load_balancer_arn = aws_lb.nlb.arn
  port              = var.listener_port
  protocol          = "TCP"

  default_action {
    type             = "forward"
    target_group_arn = aws_lb_target_group.nlb_tg.arn
  }
}

# Optional: TLS Listener (port 443)
resource "aws_lb_listener" "nlb_tls_listener" {
  count = var.listener_port == 443 ? 1 : 0

  load_balancer_arn = aws_lb.nlb.arn
  port              = 443
  protocol          = "TLS"
  certificate_arn   = var.certificate_arn
  ssl_policy        = "ELBSecurityPolicy-TLS13-1-2-2021-06"

  default_action {
    type             = "forward"
    target_group_arn = aws_lb_target_group.nlb_tg.arn
  }
}

variable "certificate_arn" {
  description = "ACM certificate ARN for TLS listener"
  type        = string
  default     = ""
}

# Security Group for NLB (Network Load Balancers don't require security groups, 
# but we create one for associated resources if needed)
resource "aws_security_group" "nlb_sg" {
  name        = "${var.nlb_name}-sg"
  description = "Security group for NLB associated resources"
  vpc_id      = var.vpc_id

  ingress {
    from_port   = var.listener_port
    to_port     = var.listener_port
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"]
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }

  tags = {
    Name        = "${var.nlb_name}-sg"
    Environment = "production"
    ManagedBy   = "terraform"
  }
}

# Outputs
output "nlb_arn" {
  description = "ARN of the Network Load Balancer"
  value       = aws_lb.nlb.arn
}

output "nlb_dns_name" {
  description = "DNS name of the Network Load Balancer"
  value       = aws_lb.nlb.dns_name
}

output "nlb_zone_id" {
  description = "Zone ID of the Network Load Balancer"
  value       = aws_lb.nlb.zone_id
}

output "target_group_arn" {
  description = "ARN of the target group"
  value       = aws_lb_target_group.nlb_tg.arn
}

output "target_group_name" {
  description = "Name of the target group"
  value       = aws_lb_target_group.nlb_tg.name
}
```

