# Data source to get available AZs
data "aws_availability_zones" "available" {
  state = "available"
}

# VPC and Networking
resource "aws_vpc" "main" {
  cidr_block           = "10.0.0.0/16"
  enable_dns_hostnames = true
  enable_dns_support   = true

  tags = {
    Name = "main-vpc"
  }
}

resource "aws_internet_gateway" "main" {
  vpc_id = aws_vpc.main.id

  tags = {
    Name = "main-igw"
  }
}

resource "aws_subnet" "public" {
  count                   = 2
  vpc_id                  = aws_vpc.main.id
  cidr_block              = "10.0.${count.index + 1}.0/24"
  availability_zone       = data.aws_availability_zones.available.names[count.index]
  map_public_ip_on_launch = true

  tags = {
    Name = "public-subnet-${count.index + 1}"
  }
}

resource "aws_route_table" "public" {
  vpc_id = aws_vpc.main.id

  route {
    cidr_block = "0.0.0.0/0"
    gateway_id = aws_internet_gateway.main.id
  }

  tags = {
    Name = "public-rt"
  }
}

resource "aws_route_table_association" "public" {
  count          = 2
  subnet_id      = aws_subnet.public[count.index].id
  route_table_id = aws_route_table.public.id
}

# Elastic IPs for Network Load Balancer
resource "aws_eip" "nlb" {
  count  = 2
  domain = "vpc"

  tags = {
    Name = "nlb-eip-${count.index + 1}"
  }

  depends_on = [aws_internet_gateway.main]
}

# Network Load Balancer with Elastic IPs
resource "aws_lb" "nlb" {
  name               = "nlb-with-eips"
  internal           = false
  load_balancer_type = "network"

  dynamic "subnet_mapping" {
    for_each = aws_subnet.public
    content {
      subnet_id     = subnet_mapping.value.id
      allocation_id = aws_eip.nlb[subnet_mapping.key].id
    }
  }

  tags = {
    Name = "nlb-with-eips"
  }
}

# Target Group for NLB
resource "aws_lb_target_group" "nlb_tg" {
  name     = "nlb-target-group"
  port     = 80
  protocol = "TCP"
  vpc_id   = aws_vpc.main.id

  health_check {
    protocol = "TCP"
    port     = "traffic-port"
  }
}

# NLB Listener
resource "aws_lb_listener" "nlb_listener" {
  load_balancer_arn = aws_lb.nlb.arn
  port              = 80
  protocol          = "TCP"

  default_action {
    type             = "forward"
    target_group_arn = aws_lb_target_group.nlb_tg.arn
  }
}

# Application Load Balancer with Elastic IPs (using Global Accelerator or NLB in front)
# Alternative: Classic Load Balancer with Elastic IPs

# Classic Load Balancer with Elastic IPs
resource "aws_elb" "classic" {
  name               = "classic-elb-with-eips"
  availability_zones = slice(data.aws_availability_zones.available.names, 0, 2)

  listener {
    instance_port     = 80
    instance_protocol = "HTTP"
    lb_port           = 80
    lb_protocol       = "HTTP"
  }

  health_check {
    target              = "HTTP:80/"
    interval            = 30
    healthy_threshold   = 2
    unhealthy_threshold = 2
    timeout             = 5
  }

  tags = {
    Name = "classic-elb-with-eips"
  }
}

# Associate Elastic IPs with Classic ELB (using ELB's network interface)
# Note: AWS Classic ELB doesn't directly support Elastic IP attachment
# For true Elastic IP support, use Network Load Balancer as shown above

# Outputs
output "nlb_dns_name" {
  value = aws_lb.nlb.dns_name
}

output "nlb_eips" {
  value = aws_eip.nlb[*].public_ip
}

output "classic_elb_dns_name" {
  value = aws_elb.classic.dns_name
}

