terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

variable "db_snapshot_identifier" {
  description = "The identifier for the DB snapshot to restore from"
  type        = string
}

variable "db_instance_identifier" {
  description = "The identifier for the new DB instance"
  type        = string
}

variable "db_instance_class" {
  description = "The instance type of the RDS instance"
  type        = string
  default     = "db.t3.micro"
}

variable "db_subnet_group_name" {
  description = "The name of the DB subnet group to associate with this DB instance"
  type        = string
}

variable "vpc_security_group_ids" {
  description = "List of VPC security groups to associate"
  type        = list(string)
}

variable "availability_zone" {
  description = "The availability zone for the DB instance"
  type        = string
  default     = null
}

variable "publicly_accessible" {
  description = "Whether the DB instance is publicly accessible"
  type        = bool
  default     = false
}

variable "tags" {
  description = "A map of tags to assign to the resource"
  type        = map(string)
  default     = {}
}

resource "aws_db_instance" "from_snapshot" {
  identifier           = var.db_instance_identifier
  snapshot_identifier  = var.db_snapshot_identifier
  instance_class       = var.db_instance_class
  db_subnet_group_name = var.db_subnet_group_name
  vpc_security_group_ids = var.vpc_security_group_ids
  availability_zone    = var.availability_zone
  publicly_accessible  = var.publicly_accessible

  # These are required when restoring from snapshot
  # but will be inherited from the snapshot if not specified
  # engine and engine_version are optional when restoring from snapshot

  skip_final_snapshot = true

  tags = var.tags
}

output "db_instance_id" {
  description = "The ID of the RDS instance"
  value       = aws_db_instance.from_snapshot.id
}

output "db_instance_arn" {
  description = "The ARN of the RDS instance"
  value       = aws_db_instance.from_snapshot.arn
}

output "db_instance_endpoint" {
  description = "The connection endpoint"
  value       = aws_db_instance.from_snapshot.endpoint
}

output "db_instance_address" {
  description = "The hostname of the RDS instance"
  value       = aws_db_instance.from_snapshot.address
}
