terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

provider "aws" {
  region = "us-east-1"
}

# VPC and networking resources for RDS
resource "aws_vpc" "main" {
  cidr_block           = "10.0.0.0/16"
  enable_dns_hostnames = true
  enable_dns_support   = true

  tags = {
    Name = "rds-vpc"
  }
}

resource "aws_subnet" "subnet_a" {
  vpc_id            = aws_vpc.main.id
  cidr_block        = "10.0.1.0/24"
  availability_zone = "us-east-1a"

  tags = {
    Name = "rds-subnet-a"
  }
}

resource "aws_subnet" "subnet_b" {
  vpc_id            = aws_vpc.main.id
  cidr_block        = "10.0.2.0/24"
  availability_zone = "us-east-1b"

  tags = {
    Name = "rds-subnet-b"
  }
}

resource "aws_db_subnet_group" "main" {
  name       = "rds-subnet-group"
  subnet_ids = [aws_subnet.subnet_a.id, aws_subnet.subnet_b.id]

  tags = {
    Name = "RDS subnet group"
  }
}

resource "aws_security_group" "rds" {
  name_prefix = "rds-"
  vpc_id      = aws_vpc.main.id

  ingress {
    from_port   = 3306
    to_port     = 3306
    protocol    = "tcp"
    cidr_blocks = [aws_vpc.main.cidr_block]
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }

  tags = {
    Name = "RDS security group"
  }
}

# S3 bucket for database backup (source for restore)
resource "aws_s3_bucket" "db_backup" {
  bucket_prefix = "rds-backup-"
}

resource "aws_s3_bucket_versioning" "db_backup" {
  bucket = aws_s3_bucket.db_backup.id
  versioning_configuration {
    status = "Enabled"
  }
}

# IAM role for RDS to access S3
resource "aws_iam_role" "rds_s3_access" {
  name = "rds-s3-access-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "rds.amazonaws.com"
        }
      }
    ]
  })
}

resource "aws_iam_role_policy" "rds_s3_access" {
  name = "rds-s3-access-policy"
  role = aws_iam_role.rds_s3_access.id

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect = "Allow"
        Action = [
          "s3:GetObject",
          "s3:ListBucket"
        ]
        Resource = [
          aws_s3_bucket.db_backup.arn,
          "${aws_s3_bucket.db_backup.arn}/*"
        ]
      }
    ]
  })
}

# RDS instance restored from S3 (MySQL/MariaDB example)
# For SQL Server, use aws_db_instance with restore_to_point_in_time or s3_import
resource "aws_db_instance" "restored_from_s3" {
  identifier = "restored-db-from-s3"

  engine         = "mysql"
  engine_version = "8.0"
  instance_class = "db.t3.micro"

  allocated_storage     = 20
  max_allocated_storage = 100
  storage_type          = "gp3"

  db_name  = "mydatabase"
  username = "admin"
  password = "changeme123!" # Use AWS Secrets Manager in production

  db_subnet_group_name   = aws_db_subnet_group.main.name
  vpc_security_group_ids = [aws_security_group.rds.id]

  # S3 import configuration for initial data load
  # Note: This creates a new DB with data from S3, not a point-in-time restore
  s3_import {
    source_engine         = "mysql"
    source_engine_version = "8.0"
    bucket_name           = aws_s3_bucket.db_backup.bucket
    bucket_prefix         = "backup/" # Optional: prefix for backup files in S3
    ingestion_role        = aws_iam_role.rds_s3_access.arn
  }

  backup_retention_period = 7
  skip_final_snapshot     = true

  tags = {
    Name = "Restored from S3"
  }
}

# Alternative: Aurora cluster restored from S3
resource "aws_rds_cluster" "aurora_from_s3" {
  count = 0 # Set to 1 to enable, 0 to disable

  cluster_identifier = "aurora-from-s3"
  engine             = "aurora-mysql"
  engine_version     = "8.0.mysql_aurora.3.04.0"

  database_name   = "mydatabase"
  master_username = "admin"
  master_password = "changeme123!"

  db_subnet_group_name   = aws_db_subnet_group.main.name
  vpc_security_group_ids = [aws_security_group.rds.id]

  # S3 restore for Aurora
  s3_import {
    source_engine         = "mysql"
    source_engine_version = "8.0"
    bucket_name           = aws_s3_bucket.db_backup.bucket
    bucket_prefix         = "aurora-backup/"
    ingestion_role        = aws_iam_role.rds_s3_access.arn
  }

  skip_final_snapshot = true
}

resource "aws_rds_cluster_instance" "aurora_instance" {
  count = 0 # Set to 1 to enable, 0 to disable

  identifier         = "aurora-instance-1"
  cluster_identifier = aws_rds_cluster.aurora_from_s3[0].id
  instance_class     = "db.r6g.large"
  engine             = aws_rds_cluster.aurora_from_s3[0].engine
}

